"use client";

import React, { useState, useEffect } from "react";
import { motion, useScroll, useSpring, AnimatePresence, HTMLMotionProps } from "framer-motion";
import { cn } from "@/lib/utils";
import { ArrowUp } from "lucide-react";

export interface BackToTopProps extends HTMLMotionProps<"button"> {
  scrollContainerRef?: React.RefObject<HTMLElement | null>;
  threshold?: number;
  showProgress?: boolean;
  position?: "bottom-right" | "bottom-left" | "bottom-center";
  icon?: React.ReactNode;
}

export function BackToTop({
  scrollContainerRef,
  threshold = 200,
  showProgress = true,
  position = "bottom-right",
  icon = <ArrowUp className="w-5 h-5" />,
  className,
  ...props
}: BackToTopProps) {
  const [isVisible, setIsVisible] = useState(false);

  // Setup scroll tracking
  // If no container ref is provided, useScroll defaults to window
  const { scrollYProgress, scrollY } = useScroll(
    scrollContainerRef ? { container: scrollContainerRef } : {}
  );

  // Smooth out the progress ring animation
  const scaleY = useSpring(scrollYProgress, {
    stiffness: 100,
    damping: 30,
    restDelta: 0.001
  });

  // Check visibility threshold
  useEffect(() => {
    return scrollY.on("change", (latest) => {
      if (latest > threshold) {
        setIsVisible(true);
      } else {
        setIsVisible(false);
      }
    });
  }, [scrollY, threshold]);

  const handleScrollToTop = () => {
    if (scrollContainerRef?.current) {
      scrollContainerRef.current.scrollTo({
        top: 0,
        behavior: "smooth"
      });
    } else {
      window.scrollTo({
        top: 0,
        behavior: "smooth"
      });
    }
  };

  const positionClasses = {
    "bottom-right": "bottom-8 right-8",
    "bottom-left": "bottom-8 left-8",
    "bottom-center": "bottom-8 left-1/2 -translate-x-1/2",
  };

  return (
    <AnimatePresence>
      {isVisible && (
        <motion.button
          initial={{ opacity: 0, scale: 0.5, y: 20 }}
          animate={{ opacity: 1, scale: 1, y: 0 }}
          exit={{ opacity: 0, scale: 0.5, y: 20 }}
          transition={{ type: "spring", stiffness: 260, damping: 20 }}
          onClick={handleScrollToTop}
          className={cn(
            "fixed z-50 flex items-center justify-center p-3 rounded-full bg-zinc-900 text-white shadow-xl hover:bg-zinc-800 transition-colors border border-white/10 group focus:outline-none",
            positionClasses[position],
            className
          )}
          {...props}
        >
          {showProgress && (
            <svg 
              className="absolute inset-0 w-full h-full -rotate-90 pointer-events-none p-1" 
              viewBox="0 0 100 100"
            >
              <circle
                cx="50"
                cy="50"
                r="46"
                className="stroke-zinc-800 fill-none"
                strokeWidth="4"
              />
              <motion.circle
                cx="50"
                cy="50"
                r="46"
                className="stroke-indigo-500 fill-none"
                strokeWidth="4"
                strokeLinecap="round"
                style={{
                  pathLength: scaleY
                }}
              />
            </svg>
          )}

          <div className="relative z-10 transition-transform duration-300 group-hover:-translate-y-1">
            {icon}
          </div>
        </motion.button>
      )}
    </AnimatePresence>
  );
}

"use client";

import React, { useRef, useState, useEffect } from "react";
import { motion, useAnimation, useAnimationFrame } from "framer-motion";
import { Play, Square } from "lucide-react";
import { cn } from "@/lib/utils";

export interface BeatSyncedTypographyProps {
  text: string;
  audioUrl?: string; // Optional URL. If not provided, it will simulate a beat.
  className?: string;
  glitchColor?: string;
}

export function BeatSyncedTypography({ 
  text, 
  audioUrl, 
  className,
  glitchColor = "#ef4444" // Red-500
}: BeatSyncedTypographyProps) {
  const [isPlaying, setIsPlaying] = useState(false);
  const audioRef = useRef<HTMLAudioElement | null>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const dataArrayRef = useRef<Uint8Array | null>(null);

  const containerControls = useAnimation();
  const textControls = useAnimation();
  const glitchControls = useAnimation();

  useEffect(() => {
    // If audioUrl is provided, initialize Audio element (but don't play yet)
    if (audioUrl) {
      const audio = new Audio(audioUrl);
      audio.crossOrigin = "anonymous";
      audio.loop = true;
      audioRef.current = audio;
    }

    return () => {
      if (audioRef.current) {
        audioRef.current.pause();
        audioRef.current.src = "";
      }
      if (audioContextRef.current) {
        audioContextRef.current.close();
      }
    };
  }, [audioUrl]);

  const togglePlayback = () => {
    if (isPlaying) {
      if (audioRef.current) audioRef.current.pause();
      setIsPlaying(false);
      // Reset animations
      containerControls.start({ scale: 1, rotate: 0 });
      textControls.start({ opacity: 1, x: 0, filter: "blur(0px)" });
      glitchControls.start({ opacity: 0 });
    } else {
      if (audioRef.current) {
        // Setup Audio Context if not already done
        if (!audioContextRef.current) {
          const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)();
          audioContextRef.current = audioContext;

          const source = audioContext.createMediaElementSource(audioRef.current);
          const analyser = audioContext.createAnalyser();
          analyser.fftSize = 256;

          source.connect(analyser);
          analyser.connect(audioContext.destination); // Route to speakers

          analyserRef.current = analyser;
          dataArrayRef.current = new Uint8Array(analyser.frequencyBinCount);
        }

        // AudioContext requires a user gesture to resume in some browsers
        if (audioContextRef.current.state === 'suspended') {
          audioContextRef.current.resume();
        }

        audioRef.current.play();
      }
      setIsPlaying(true);
    }
  };

  useAnimationFrame(() => {
    if (!isPlaying) return;

    let bassLevel = 0;

    if (analyserRef.current && dataArrayRef.current) {
      // Real Audio Data
      analyserRef.current.getByteFrequencyData(dataArrayRef.current);
      // Sample lowest frequencies for "bass" beat
      let sum = 0;
      for (let i = 0; i < 5; i++) {
        sum += dataArrayRef.current[i];
      }
      bassLevel = (sum / 5) / 255.0; // 0 to 1
    } else {
      // Simulation mode if no audioUrl provided
      // A simple sine wave simulation mapped roughly to a 120BPM beat
      const time = Date.now() / 1000;
      bassLevel = Math.pow(Math.sin(time * Math.PI * 2), 4); // sharp peaks
    }

    // Threshold for a "beat" hit
    const BEAT_THRESHOLD = 0.7;

    if (bassLevel > BEAT_THRESHOLD) {
      // High bass: trigger scaling and glitch effects
      const intensity = (bassLevel - BEAT_THRESHOLD) / (1 - BEAT_THRESHOLD); // 0 to 1 based on how far past threshold

      containerControls.set({ 
        scale: 1 + intensity * 0.1, // Max scale 1.1
        rotate: (Math.random() - 0.5) * intensity * 2 // slight rotation shake
      });

      textControls.set({
        filter: `blur(${intensity * 4}px)`, // Max blur 4px
        x: (Math.random() - 0.5) * intensity * 10
      });

      // Glitch layer
      glitchControls.set({
        opacity: intensity,
        x: (Math.random() - 0.5) * intensity * 20,
        y: (Math.random() - 0.5) * intensity * 10,
        clipPath: `inset(${Math.random() * 40}% 0 ${Math.random() * 40}% 0)`
      });

    } else {
      // Decay back to normal
      containerControls.start({ scale: 1, rotate: 0, transition: { duration: 0.1 } });
      textControls.start({ filter: "blur(0px)", x: 0, transition: { duration: 0.1 } });
      glitchControls.start({ opacity: 0, transition: { duration: 0.1 } });
    }
  });

  // Split text for individual character styling if needed, but for raw performance on a fast loop, a single block is better.
  return (
    <div className={cn("relative flex flex-col items-center justify-center w-full min-h-[400px] bg-black overflow-hidden rounded-3xl", className)}>

      {/* Visualizer Area */}
      <div className="flex-1 flex items-center justify-center relative w-full h-full">
        <motion.div 
          animate={containerControls}
          className="relative select-none"
        >
          {/* Main Text */}
          <motion.h1 
            animate={textControls}
            className="text-6xl md:text-9xl font-black uppercase tracking-tighter text-white mix-blend-difference"
          >
            {text}
          </motion.h1>

          {/* Glitch Overlay (Red) */}
          <motion.h1 
            animate={glitchControls}
            className="text-6xl md:text-9xl font-black uppercase tracking-tighter absolute top-0 left-0 pointer-events-none"
            style={{ color: glitchColor, mixBlendMode: "screen" }}
          >
            {text}
          </motion.h1>

          {/* Glitch Overlay (Cyan) - Opposite direction */}
          <motion.h1 
            animate={glitchControls}
            className="text-6xl md:text-9xl font-black uppercase tracking-tighter absolute top-0 left-0 pointer-events-none text-cyan-400"
            style={{ mixBlendMode: "screen", x: "-10px", scale: 1.02 }}
          >
            {text}
          </motion.h1>

        </motion.div>
      </div>

      {/* Controls */}
      <div className="absolute bottom-6 flex flex-col items-center gap-3">
        {!audioUrl && (
          <span className="text-xs font-mono text-zinc-500 bg-zinc-900/80 px-3 py-1 rounded-full border border-white/10">
            SIMULATION MODE
          </span>
        )}
        <button
          onClick={togglePlayback}
          className={cn(
            "flex items-center gap-2 px-6 py-3 rounded-full font-bold uppercase tracking-widest text-sm transition-all duration-300 shadow-xl",
            isPlaying
              ? "bg-red-500 text-white hover:bg-red-600 shadow-red-500/20"
              : "bg-white text-black hover:bg-zinc-200"
          )}
        >
          {isPlaying ? (
            <>
              <Square className="w-4 h-4 fill-current" /> Stop
            </>
          ) : (
            <>
              <Play className="w-4 h-4 fill-current" /> Play
            </>
          )}
        </button>
      </div>
    </div>
  );
}

"use client";

import React, { useState, useRef, useEffect } from "react";
import { motion, useMotionValue, useTransform } from "framer-motion";
import { cn } from "@/lib/utils";
import { GripVertical } from "lucide-react";

export interface BeforeAfterSliderProps extends React.HTMLAttributes<HTMLDivElement> {
  beforeImage: string;
  afterImage: string;
  beforeLabel?: string;
  afterLabel?: string;
  defaultValue?: number;
  handleColor?: string;
  imageClassName?: string;
}

export function BeforeAfterSlider({
  beforeImage,
  afterImage,
  beforeLabel,
  afterLabel,
  defaultValue = 50,
  handleColor = "#ffffff",
  className,
  imageClassName,
  ...props
}: BeforeAfterSliderProps) {
  const [isHovered, setIsHovered] = useState(false);
  const containerRef = useRef<HTMLDivElement>(null);

  // Motion values for smooth drag and interpolation
  const progress = useMotionValue(defaultValue);
  const clipPath = useTransform(progress, (v) => `inset(0 ${100 - v}% 0 0)`);
  const leftPosition = useTransform(progress, (v) => `${v}%`);

  const handlePointerMove = (e: React.PointerEvent | PointerEvent) => {
    if (!containerRef.current) return;
    const { left, width } = containerRef.current.getBoundingClientRect();
    const x = e.clientX - left;
    const newProgress = Math.min(Math.max((x / width) * 100, 0), 100);
    progress.set(newProgress);
  };

  useEffect(() => {
    const handleMove = (e: PointerEvent) => {
      if (isHovered) {
        handlePointerMove(e);
      }
    };

    if (isHovered) {
      window.addEventListener("pointermove", handleMove);
    }

    return () => {
      window.removeEventListener("pointermove", handleMove);
    };
  }, [isHovered, progress]);

  return (
    <div
      ref={containerRef}
      className={cn(
        "relative w-full overflow-hidden rounded-xl cursor-ew-resize select-none touch-none",
        className
      )}
      onPointerEnter={() => setIsHovered(true)}
      onPointerLeave={() => setIsHovered(false)}
      onPointerDown={(e) => {
        setIsHovered(true);
        handlePointerMove(e);
      }}
      onPointerUp={() => setIsHovered(false)}
      {...props}
    >
      {/* Background Image (After) */}
      <img
        src={afterImage}
        alt={afterLabel || "After"}
        className={cn("w-full h-full object-cover block pointer-events-none", imageClassName)}
        draggable={false}
      />
      {afterLabel && (
        <span className="absolute bottom-4 right-4 bg-black/50 backdrop-blur-md text-white text-xs font-semibold px-2 py-1 rounded shadow-lg pointer-events-none z-10">
          {afterLabel}
        </span>
      )}

      {/* Foreground Image (Before) with Clip Path */}
      <motion.div
        className="absolute inset-0 z-20 overflow-hidden pointer-events-none"
        style={{ clipPath }}
      >
        <img
          src={beforeImage}
          alt={beforeLabel || "Before"}
          className={cn("absolute inset-0 w-full h-full object-cover block", imageClassName)}
          draggable={false}
        />
        {beforeLabel && (
          <span className="absolute bottom-4 left-4 bg-black/50 backdrop-blur-md text-white text-xs font-semibold px-2 py-1 rounded shadow-lg pointer-events-none">
            {beforeLabel}
          </span>
        )}
      </motion.div>

      {/* Draggable Handle */}
      <motion.div
        className="absolute top-0 bottom-0 w-1 flex items-center justify-center z-30 pointer-events-none"
        style={{ left: leftPosition, backgroundColor: handleColor }}
      >
        <div 
          className="w-8 h-8 rounded-full shadow-xl flex items-center justify-center -translate-x-1/2"
          style={{ backgroundColor: handleColor }}
        >
          <GripVertical className="w-4 h-4 text-black" />
        </div>
      </motion.div>
    </div>
  );
}

"use client";

import React, { useRef, useState, useEffect } from "react";
import { cn } from "@/lib/utils";

export function BentoGridGlow({ 
  children, 
  className 
}: { 
  children: React.ReactNode, 
  className?: string 
}) {
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (!containerRef.current) return;
      const rect = containerRef.current.getBoundingClientRect();
      const x = e.clientX - rect.left;
      const y = e.clientY - rect.top;

      // Update custom properties on the container for child elements to inherit
      containerRef.current.style.setProperty("--mouse-x", `${x}px`);
      containerRef.current.style.setProperty("--mouse-y", `${y}px`);
    };

    const element = containerRef.current;
    if (element) {
      element.addEventListener("mousemove", handleMouseMove);
    }
    return () => {
      if (element) element.removeEventListener("mousemove", handleMouseMove);
    };
  }, []);

  return (
    <div
      ref={containerRef}
      className={cn("grid grid-cols-1 md:grid-cols-3 gap-4 md:gap-6 group relative w-full", className)}
    >
      {React.Children.map(children, (child) => {
        if (!React.isValidElement(child)) return child;
        return (
          <div className="relative rounded-2xl bg-white/5 p-[1px] overflow-hidden">
            {/* The illuminating border glow */}
            <div 
              className="absolute inset-0 opacity-0 group-hover:opacity-100 transition-opacity duration-500"
              style={{
                background: "radial-gradient(800px circle at var(--mouse-x) var(--mouse-y), rgba(6,182,212,0.5), transparent 40%)"
              }}
            />
            {/* The content container that masks the center, leaving only the border illuminated */}
            <div className="relative z-10 bg-[#0a0a0a] rounded-[15px] h-full overflow-hidden">
              {/* Secondary subtle background glow that shines through the content */}
              <div 
                className="absolute inset-0 opacity-0 group-hover:opacity-100 transition-opacity duration-500 z-0 pointer-events-none"
                style={{
                  background: "radial-gradient(600px circle at var(--mouse-x) var(--mouse-y), rgba(6,182,212,0.1), transparent 40%)"
                }}
              />
              <div className="relative z-10 h-full p-8">
                {child}
              </div>
            </div>
          </div>
        );
      })}
    </div>
  );
}

"use client";

import React from "react";
import { motion } from "framer-motion";
import { cn } from "@/lib/utils";

export type BentoVariant = "standard" | "glow" | "scale";

interface BentoGridProps {
  children: React.ReactNode;
  className?: string;
  speed?: number;
  scale?: number;
  color?: string;
  variant?: BentoVariant;
}

export function BentoGrid({
  children,
  className,
  speed = 1,
  scale = 1,
  color,
  variant = "standard",
}: BentoGridProps) {
  // Pass playground props down to children
  const childrenWithProps = React.Children.map(children, (child) => {
    if (React.isValidElement(child)) {
      return React.cloneElement(child, { speed, scale, color, variant } as any);
    }
    return child;
  });

  return (
    <div className="@container w-full">
      <motion.div
        initial="hidden"
        whileInView="visible"
        viewport={{ once: true, margin: "-50px" }}
        variants={{
          visible: {
            transition: { staggerChildren: 0.1 / speed },
          },
        }}
        className={cn("grid grid-cols-1 @md:grid-cols-3 gap-4 max-w-7xl mx-auto w-full", className)}
      >
        {childrenWithProps}
      </motion.div>
    </div>
  );
}

interface BentoCardProps {
  className?: string;
  title?: string | React.ReactNode;
  description?: string | React.ReactNode;
  icon?: React.ReactNode;
  header?: React.ReactNode;
  children?: React.ReactNode;
  speed?: number;
  scale?: number;
  color?: string;
  variant?: BentoVariant;
}

export function BentoCard({
  className,
  title,
  description,
  icon,
  header,
  children,
  speed = 1,
  scale = 1,
  color,
  variant = "standard",
}: BentoCardProps) {
  const [hovered, setHovered] = React.useState(false);

  const hoverVariants = {
    standard: { y: -5 * scale },
    glow: { y: 0, boxShadow: color ? `0 0 25px ${color}30` : "0 0 25px rgba(255,255,255,0.1)" },
    scale: { y: 0, scale: 1.02 * scale },
  };

  return (
    <motion.div
      variants={{
