'use client';

import React, { useRef } from 'react';
import { motion, useInView, Variants } from 'framer-motion';
import { cn } from '@/lib/utils';

export type BlurVariant = 'elevate' | 'fade' | 'scale' | 'drop';

interface BlurTextProps {
  /** Text to animate */
  text: string;
  className?: string;
  /** Delay before animation starts (seconds). Default: 0 */
  delay?: number;
  /** Whether to animate word-by-word or character-by-character. Default: 'word' */
  animateBy?: 'word' | 'character';
  /** Animation preset. Default: 'elevate' */
  variant?: BlurVariant;
}

const getVariants = (variant: BlurVariant): Variants => {
  switch (variant) {
    case 'drop':
      return {
        hidden: { filter: 'blur(10px)', opacity: 0, y: -20 },
        visible: { filter: 'blur(0px)', opacity: 1, y: 0 },
      };
    case 'scale':
      return {
        hidden: { filter: 'blur(10px)', opacity: 0, scale: 1.2 },
        visible: { filter: 'blur(0px)', opacity: 1, scale: 1 },
      };
    case 'fade':
      return {
        hidden: { filter: 'blur(10px)', opacity: 0 },
        visible: { filter: 'blur(0px)', opacity: 1 },
      };
    case 'elevate':
    default:
      return {
        hidden: { filter: 'blur(10px)', opacity: 0, y: 20 },
        visible: { filter: 'blur(0px)', opacity: 1, y: 0 },
      };
  }
};

export function BlurText({
  text,
  className,
  delay = 0,
  animateBy = 'word',
  variant = 'elevate',
}: BlurTextProps) {
  const ref = useRef(null);
  const isInView = useInView(ref, { once: true, margin: '-10% 0px' });

  const elements = animateBy === 'word' ? text.split(' ') : text.split('');
  const variants = getVariants(variant);

  return (
    <div ref={ref} className={cn("flex flex-wrap", className)}>
      {elements.map((element, index) => (
        <motion.span
          key={index}
          initial="hidden"
          animate={isInView ? "visible" : "hidden"}
          variants={variants}
          transition={{
            duration: 0.8,
            ease: [0.4, 0.0, 0.2, 1],
            delay: delay + index * (animateBy === 'word' ? 0.05 : 0.02),
          }}
          className={cn(
            "inline-block",
            animateBy === 'word' && "mr-[0.25em]"
          )}
        >
          {element === ' ' ? '\u00A0' : element}
        </motion.span>
      ))}
    </div>
  );
}

"use client";

import React, { useEffect, useRef } from 'react';
import { cn } from '@/lib/utils';

interface BoidsCanvasProps {
  className?: string;
  count?: number;
  color?: string;
}

export function BoidsCanvas({ className, count = 100, color = "#6366f1" }: BoidsCanvasProps) {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let width = canvas.width = canvas.offsetWidth;
    let height = canvas.height = canvas.offsetHeight;

    class Boid {
      x: number;
      y: number;
      vx: number;
      vy: number;
      speed: number = 2;

      constructor() {
        this.x = Math.random() * width;
        this.y = Math.random() * height;
        this.vx = Math.random() * 2 - 1;
        this.vy = Math.random() * 2 - 1;
      }

      update(boids: Boid[], mouse: {x: number, y: number, radius: number}) {
        let separation = { x: 0, y: 0 };
        let alignment = { x: 0, y: 0 };
        let cohesion = { x: 0, y: 0 };
        let total = 0;

        // Boids Algorithm
        for (let other of boids) {
          let d = Math.hypot(this.x - other.x, this.y - other.y);
          if (other !== this && d < 50) {
            separation.x += this.x - other.x;
            separation.y += this.y - other.y;
            alignment.x += other.vx;
            alignment.y += other.vy;
            cohesion.x += other.x;
            cohesion.y += other.y;
            total++;
          }
        }

        if (total > 0) {
          separation.x /= total;
          separation.y /= total;
          alignment.x /= total;
          alignment.y /= total;
          cohesion.x = cohesion.x / total - this.x;
          cohesion.y = cohesion.y / total - this.y;

          this.vx += (separation.x * 0.05) + (alignment.x * 0.05) + (cohesion.x * 0.01);
          this.vy += (separation.y * 0.05) + (alignment.y * 0.05) + (cohesion.y * 0.01);
        }

        // Mouse Avoidance
        let dx = this.x - mouse.x;
        let dy = this.y - mouse.y;
        let dist = Math.hypot(dx, dy);
        if (dist < mouse.radius) {
          this.vx += (dx / dist) * 0.5;
          this.vy += (dy / dist) * 0.5;
        }

        // Normalize speed
        let mag = Math.hypot(this.vx, this.vy);
        if (mag > this.speed) {
          this.vx = (this.vx / mag) * this.speed;
          this.vy = (this.vy / mag) * this.speed;
        }

        this.x += this.vx;
        this.y += this.vy;

        // Wrap edges
        if (this.x < 0) this.x = width;
        if (this.x > width) this.x = 0;
        if (this.y < 0) this.y = height;
        if (this.y > height) this.y = 0;
      }

      draw(ctx: CanvasRenderingContext2D) {
        const angle = Math.atan2(this.vy, this.vx);
        ctx.save();
        ctx.translate(this.x, this.y);
        ctx.rotate(angle);

        ctx.beginPath();
        ctx.moveTo(4, 0);
        ctx.lineTo(-4, 3);
        ctx.lineTo(-2, 0);
        ctx.lineTo(-4, -3);
        ctx.closePath();

        ctx.fillStyle = color;
        ctx.fill();
        ctx.restore();
      }
    }

    const boids = Array.from({ length: count }, () => new Boid());
    const mouse = { x: -1000, y: -1000, radius: 100 };

    const handleMouseMove = (e: MouseEvent) => {
      const rect = canvas.getBoundingClientRect();
      mouse.x = e.clientX - rect.left;
      mouse.y = e.clientY - rect.top;
    };

    const handleMouseLeave = () => {
      mouse.x = -1000;
      mouse.y = -1000;
    };

    canvas.addEventListener('mousemove', handleMouseMove);
    canvas.addEventListener('mouseleave', handleMouseLeave);

    const handleResize = () => {
      width = canvas.width = canvas.offsetWidth;
      height = canvas.height = canvas.offsetHeight;
    };
    window.addEventListener('resize', handleResize);

    let animationId: number;
    const animate = () => {
      ctx.clearRect(0, 0, width, height);
      for (let boid of boids) {
        boid.update(boids, mouse);
        boid.draw(ctx);
      }
      animationId = requestAnimationFrame(animate);
    };
    animate();

    return () => {
      cancelAnimationFrame(animationId);
      window.removeEventListener('resize', handleResize);
      canvas.removeEventListener('mousemove', handleMouseMove);
      canvas.removeEventListener('mouseleave', handleMouseLeave);
    };
  }, [count, color]);

  return (
    <canvas 
      ref={canvasRef} 
      className={cn("w-full h-full block bg-black", className)} 
    />
  );
}

"use client";

import React, { useEffect, useRef } from "react";
import { motion, useMotionValue, useTransform, animate, useSpring } from "framer-motion";
import { cn } from "@/lib/utils";

export interface BreathingTextProps {
  /** The text to display */
  label: string;
  /** The interaction mode */
  mode?: "auto" | "cursor";
  /** Minimum font weight */
  minWeight?: number;
  /** Maximum font weight */
  maxWeight?: number;
  /** Optional class name */
  className?: string;
}

export function BreathingText({
  label,
  mode = "auto",
  minWeight = 100,
  maxWeight = 900,
  className,
}: BreathingTextProps) {
  const containerRef = useRef<HTMLDivElement>(null);

  // Motion value for the weight axis
  const weight = useMotionValue(minWeight);
  // Motion value for the slant axis (optional if font supports it)
  const slant = useMotionValue(0);

  // Smooth springs for cursor tracking
  const springWeight = useSpring(weight, { stiffness: 150, damping: 20 });
  const springSlant = useSpring(slant, { stiffness: 150, damping: 20 });

  // Map the motion values to the raw CSS font-variation-settings string
  const activeWeight = mode === "auto" ? weight : springWeight;
  const fontVariationSettings = useTransform(
    activeWeight,
    (w) => `"wght" ${w}`
  );

  useEffect(() => {
    if (mode === "auto") {
      // Create a breathing loop
      const controls = animate(weight, [minWeight, maxWeight, minWeight], {
        duration: 4,
        ease: "easeInOut",
        repeat: Infinity,
      });
      return () => controls.stop();
    }
  }, [mode, minWeight, maxWeight, weight]);

  useEffect(() => {
    if (mode === "cursor") {
      const handleMouseMove = (e: MouseEvent) => {
        if (!containerRef.current) return;
        const rect = containerRef.current.getBoundingClientRect();

        // Calculate mouse position relative to the center of the text container
        const centerX = rect.left + rect.width / 2;
        const centerY = rect.top + rect.height / 2;

        const distanceX = e.clientX - centerX;
        const distanceY = e.clientY - centerY;

        // Normalize distance (0 to 1) based on a max radius of say, 500px
        const maxRadius = 500;
        const distance = Math.min(Math.sqrt(distanceX ** 2 + distanceY ** 2), maxRadius);
        const normalized = 1 - distance / maxRadius; // 1 when exact center, 0 when far away

        // Map normalized distance to weight (closer = heavier)
        const targetWeight = minWeight + (maxWeight - minWeight) * normalized;
        weight.set(targetWeight);
      };

      const handleMouseLeave = () => {
        weight.set(minWeight);
      };

      window.addEventListener("mousemove", handleMouseMove);
      document.addEventListener("mouseleave", handleMouseLeave);
      return () => {
        window.removeEventListener("mousemove", handleMouseMove);
        document.removeEventListener("mouseleave", handleMouseLeave);
      };
    }
  }, [mode, minWeight, maxWeight, weight]);

  return (
    <div ref={containerRef} className={cn("relative flex justify-center", className)}>
      <motion.h1
        className="text-center transition-colors"
        style={{
          fontVariationSettings,
          // Fallback transition for colors if any
        }}
      >
        {label}
      </motion.h1>
    </div>
  );
}

"use client";

import React, { Children } from "react";
import { cn } from "@/lib/utils";
import { motion, HTMLMotionProps, Variants } from "framer-motion";

export interface BrokenGridProps extends HTMLMotionProps<"div"> {
  children: React.ReactNode;
  columns?: number;
  gap?: number;
  animate?: boolean;
}

export function BrokenGrid({
  children,
  columns = 12,
  gap = 4,
  animate = true,
  className,
  ...props
}: BrokenGridProps) {
  const childrenArray = Children.toArray(children);

  const containerVariants: Variants = {
    hidden: { opacity: 0 },
    show: {
      opacity: 1,
      transition: { staggerChildren: 0.15 },
    },
  };

  const itemVariants: Variants = {
    hidden: { opacity: 0, y: 30, filter: "blur(5px)" },
    show: { 
      opacity: 1, 
      y: 0, 
      filter: "blur(0px)",
      transition: { type: "spring", stiffness: 200, damping: 20 } 
    },
  };

  return (
    <motion.div
      variants={animate ? containerVariants : undefined}
      initial={animate ? "hidden" : undefined}
      whileInView={animate ? "show" : undefined}
      viewport={{ once: true, margin: "-100px" }}
      className={cn(
        "grid",
        `grid-cols-${columns}`,
        `gap-${gap}`,
        className
      )}
      style={{
        gridTemplateColumns: `repeat(${columns}, minmax(0, 1fr))`,
      }}
      {...props}
    >
      {childrenArray.map((child, i) => {
        if (React.isValidElement(child)) {
          return animate ? React.cloneElement(child, { variants: itemVariants } as any) : child;
        }
        return child;
      })}
    </motion.div>
  );
}

export interface BrokenGridItemProps extends HTMLMotionProps<"div"> {
  children?: React.ReactNode;
  colSpan?: number | { sm?: number; md?: number; lg?: number };
  rowSpan?: number;
  colStart?: number | { sm?: number; md?: number; lg?: number };
  rowStart?: number;
  offsetX?: string;
  offsetY?: string;
  zIndex?: number;
}

export function BrokenGridItem({
  children,
  colSpan = 4,
  rowSpan = 1,
  colStart,
  rowStart,
  offsetX = "0px",
  offsetY = "0px",
  zIndex = 1,
  className,
  ...props
}: BrokenGridItemProps) {

  // Helper to generate col-span classes based on responsive object or number
  const getColSpanStyle = () => {
    if (typeof colSpan === 'number') return { gridColumnEnd: `span ${colSpan}` };
    return {
      gridColumnEnd: `span ${colSpan.lg || colSpan.md || colSpan.sm || 4}`
    }; // simplified for inline styles; in real world might need media queries if not using classes
  };

  const getColStartStyle = () => {
    if (!colStart) return {};
    if (typeof colStart === 'number') return { gridColumnStart: colStart };
    return {
      gridColumnStart: colStart.lg || colStart.md || colStart.sm || 1
    };
  };

  return (
    <motion.div
      className={cn("relative w-full h-full", className)}
      style={{
        ...getColSpanStyle(),
        ...getColStartStyle(),
        ...(rowSpan > 1 ? { gridRowEnd: `span ${rowSpan}` } : {}),
        ...(rowStart ? { gridRowStart: rowStart } : {}),
        transform: `translate(${offsetX}, ${offsetY})`,
        zIndex,
      }}
      {...props}
    >
      {children}
    </motion.div>
  );
}

"use client";

import React, { useState } from "react";
import { motion, AnimatePresence, PanInfo } from "framer-motion";
import { cn } from "@/lib/utils";

export type CardStackVariant = "bottom" | "top" | "left" | "fan";

export interface Card {
  id: string | number;
  content: React.ReactNode;
}

interface CardStackProps {
  items: Card[];
  /** Distance between cards. Default: 10 */
  offset?: number;
  /** How much each successive card scales down. Default: 0.05 */
  scaleFactor?: number;
  className?: string;
  /** Layout and interaction style. Default: "bottom" */
  variant?: CardStackVariant;
}

export function CardStack({
  items,
  offset = 12,
  scaleFactor = 0.06,
  className,
  variant = "bottom",
}: CardStackProps) {
  const [cards, setCards] = useState<Card[]>(items);
  const [draggedCard, setDraggedCard] = useState<string | number | null>(null);

  const moveToEnd = (id: string | number) => {
    setCards((prev) => {
      const idx = prev.findIndex((c) => c.id === id);
      if (idx === -1) return prev;
      const newCards = [...prev];
      const [card] = newCards.splice(idx, 1);
      newCards.push(card);
      return newCards;
    });
  };

  const handleDragEnd = (event: any, info: PanInfo, id: string | number) => {
    const threshold = 100;
    if (Math.abs(info.offset.x) > threshold || Math.abs(info.offset.y) > threshold) {
      moveToEnd(id);
    }
    setDraggedCard(null);
  };

  const getCardStyles = (index: number, isDragged: boolean) => {
    if (isDragged) {
      return {
        top: 0,
        left: 0,
        scale: 1,
        rotate: 0,
      };
    }

    const scale = 1 - index * scaleFactor;

    switch (variant) {
      case "top":
        return { top: -index * offset, left: 0, scale, rotate: 0 };
      case "left":
        return { top: 0, left: -index * offset, scale, rotate: 0 };
      case "fan":
        return { 
          top: index * (offset / 2), 
          left: 0, 
          scale, 
          rotate: index % 2 === 0 ? index * 4 : -index * 4 
        };
      case "bottom":
      default:
        return { top: index * offset, left: 0, scale, rotate: 0 };
    }
  };

  return (
    <div className={cn("relative flex items-center justify-center h-full w-full", className)}>
      <AnimatePresence>
        {cards.map((card, index) => {
          const isTop = index === 0;
          const isDragged = draggedCard === card.id;

          // Only show top 3 cards for performance and visual clarity
          if (index > 3) return null;

          const activeStyle = getCardStyles(index, isDragged);

          return (
            <motion.div
              key={card.id}
              layout
              role={isTop ? "button" : "presentation"}
              tabIndex={isTop ? 0 : -1}
              aria-label={isTop ? "Swipeable card. Press Enter or Space to send to back." : undefined}
              onKeyDown={(e) => {
                if (isTop && (e.key === "Enter" || e.key === " ")) {
                  e.preventDefault();
                  moveToEnd(card.id);
                }
              }}
              className={cn(
                "absolute origin-center flex items-center justify-center",
                isTop ? "cursor-grab active:cursor-grabbing z-50" : "cursor-default",
              )}
              style={{
                zIndex: cards.length - index,
              }}
              drag={isTop}
              dragConstraints={{ left: 0, right: 0, top: 0, bottom: 0 }}
              dragElastic={0.5}
              onDragStart={() => setDraggedCard(card.id)}
              onDragEnd={(e, info) => handleDragEnd(e, info, card.id)}
              initial={{
                ...activeStyle,
                opacity: 0,
              }}
              animate={{
                ...activeStyle,
                opacity: 1,
              }}
              exit={{
                opacity: 0,
                scale: 0.5,
              }}
              transition={{
                type: "spring",
                stiffness: 300,
                damping: 20,
              }}
            >
              {card.content}
            </motion.div>
          );
        })}
      </AnimatePresence>
    </div>
  );
}

