"use client";

import React, { useState, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";

export interface CinematicPreloaderProps {
  isLoading: boolean;
  onComplete?: () => void;
  brandName?: string;
}

export function CinematicPreloader({ 
  isLoading, 
  onComplete,
  brandName = "ANTIGRAVITY" 
}: CinematicPreloaderProps) {
  const [progress, setProgress] = useState(0);
  const [isCounterDone, setIsCounterDone] = useState(false);

  // Handle the fake loading progress
  useEffect(() => {
    if (!isLoading) {
      setProgress(0);
      setIsCounterDone(false);
      return;
    }

    const duration = 2000; // 2 seconds to load
    const intervalTime = 20; // run every 20ms
    const step = 100 / (duration / intervalTime);

    const timer = setInterval(() => {
      setProgress((prev) => {
        if (prev >= 100) {
          clearInterval(timer);
          setTimeout(() => setIsCounterDone(true), 400); // Small pause at 100%
          return 100;
        }
        return prev + step;
      });
    }, intervalTime);

    return () => clearInterval(timer);
  }, [isLoading]);

  // When counter finishes and splitting animation starts, we wait then fire onComplete
  useEffect(() => {
    if (isCounterDone && onComplete) {
      const timeout = setTimeout(() => {
        onComplete();
      }, 1500); // Wait for the split animation to finish before unmounting
      return () => clearTimeout(timeout);
    }
  }, [isCounterDone, onComplete]);

  return (
    <AnimatePresence>
      {isLoading && (
        <div className="fixed inset-0 z-[9999] flex items-center justify-center pointer-events-none">

          {/* Top Half of the Split Screen */}
          <motion.div 
            className="absolute top-0 left-0 w-full h-1/2 bg-zinc-950 border-b border-white/5 origin-top pointer-events-auto"
            initial={{ y: 0 }}
            animate={{ y: isCounterDone ? "-100%" : 0 }}
            exit={{ y: "-100%" }}
            transition={{ duration: 1, ease: [0.76, 0, 0.24, 1], delay: 0.2 }}
          />

          {/* Bottom Half of the Split Screen */}
          <motion.div 
            className="absolute bottom-0 left-0 w-full h-1/2 bg-zinc-950 border-t border-white/5 origin-bottom pointer-events-auto"
            initial={{ y: 0 }}
            animate={{ y: isCounterDone ? "100%" : 0 }}
            exit={{ y: "100%" }}
            transition={{ duration: 1, ease: [0.76, 0, 0.24, 1], delay: 0.2 }}
          />

          {/* The Content (Counter and Brand) */}
          <motion.div 
            className="relative z-10 flex flex-col items-center justify-center pointer-events-none"
            animate={{ opacity: isCounterDone ? 0 : 1, scale: isCounterDone ? 0.9 : 1 }}
            transition={{ duration: 0.4, ease: "easeInOut" }}
          >
            <h1 className="text-6xl md:text-8xl font-black text-white tracking-tighter mb-4">
              {Math.floor(progress)}%
            </h1>
            <div className="h-[2px] w-[200px] bg-white/20 rounded-full overflow-hidden mb-8">
              <motion.div 
                className="h-full bg-white"
                style={{ width: `${progress}%` }}
              />
            </div>
            <span className="text-zinc-500 font-mono tracking-widest text-sm uppercase">
              {brandName}
            </span>
          </motion.div>

        </div>
      )}
    </AnimatePresence>
  );
}

"use client";

import React, { useRef } from "react";
import {
  motion,
  useScroll,
  useVelocity,
  useSpring,
  useTransform,
  useAnimationFrame,
  useMotionValue,
} from "framer-motion";
import { cn } from "@/lib/utils";

interface CircularTextProps {
  text: string;
  radius?: number;
  baseVelocity?: number;
  className?: string;
}

export function CircularText({
  text,
  radius = 150,
  baseVelocity = 0.5,
  className
}: CircularTextProps) {
  // Ensure the text is long enough to form a nice circle, pad with spaces if needed
  const characters = text.split("");
  const totalChars = characters.length;
  const degreePerChar = 360 / totalChars;

  const { scrollY } = useScroll();
  const scrollVelocity = useVelocity(scrollY);
  const smoothVelocity = useSpring(scrollVelocity, {
    damping: 50,
    stiffness: 400
  });

  // Transform scroll velocity into a rotation speed multiplier
  const velocityFactor = useTransform(smoothVelocity, [0, 1000], [0, 5], {
    clamp: false
  });

  const baseRotation = useMotionValue(0);

  const directionFactor = useRef<number>(1);

  useAnimationFrame((t, delta) => {
    let moveBy = directionFactor.current * baseVelocity * (delta / 16); // normalized to 60fps

    // Reverse direction based on scroll
    if (velocityFactor.get() < 0) {
      directionFactor.current = -1;
    } else if (velocityFactor.get() > 0) {
      directionFactor.current = 1;
    }

    // Add scroll velocity to base rotation
    moveBy += directionFactor.current * moveBy * velocityFactor.get();

    // Keep rotation between 0 and 360 to prevent numbers getting too large over time
    const newRotation = (baseRotation.get() + moveBy) % 360;
    baseRotation.set(newRotation);
  });

  return (
    <div className={cn("relative flex items-center justify-center overflow-hidden", className)} style={{ minHeight: radius * 2.5 }}>
      {/* 3D Perspective Container */}
      <div className="relative perspective-[1000px] flex items-center justify-center w-full h-full">
        {/* The Rotating Ring */}
        <motion.div
          className="relative flex items-center justify-center preserve-3d"
          style={{
            rotateZ: baseRotation,
            // Add a slight 3D tilt that intensifies with scroll velocity
            rotateX: useTransform(smoothVelocity, [-1000, 0, 1000], [60, 45, 60]),
            rotateY: useTransform(smoothVelocity, [-1000, 0, 1000], [-20, 0, 20]),
          }}
        >
          {characters.map((char, index) => {
            const rotate = index * degreePerChar;
            return (
              <motion.span
                key={index}
                className="absolute text-4xl md:text-5xl font-black uppercase text-white tracking-widest origin-bottom"
                style={{
                  transform: `rotate(${rotate}deg) translateY(-${radius}px)`,
                  // Optional: add text shadow for better 3D depth perception
                  textShadow: "0 10px 20px rgba(0,0,0,0.5)"
                }}
              >
                {char}
              </motion.span>
            );
          })}
        </motion.div>
      </div>
    </div>
  );
}

