import React, { useEffect, useState, useRef, useCallback } from "react";
import { Command } from "cmdk";
import { DialogTitle, DialogDescription } from "@radix-ui/react-dialog";
import { cn } from "@/lib/utils";
import { TerminalSquare } from "lucide-react";

export interface CyberTerminalProps {
  /** Array of commands to display */
  commands: {
    heading: string;
    items: {
      id: string;
      title: string;
      icon?: React.ReactNode;
      onSelect: () => void;
    }[];
  }[];
  /** Whether the terminal is open */
  open: boolean;
  /** Function to change open state */
  onOpenChange: (open: boolean) => void;
  /** Whether typing sounds are enabled */
  soundEnabled?: boolean;
  /** Optional class name */
  className?: string;
}

export function CyberTerminal({
  commands,
  open,
  onOpenChange,
  soundEnabled = true,
  className,
}: CyberTerminalProps) {
  const [inputValue, setInputValue] = useState("");
  const audioContextRef = useRef<AudioContext | null>(null);

  // Initialize Web Audio API on first interaction (required by browsers)
  const initAudio = useCallback(() => {
    if (!audioContextRef.current && soundEnabled) {
      const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
      if (AudioContext) {
        audioContextRef.current = new AudioContext();
      }
    }
  }, [soundEnabled]);

  // Play synthetic mechanical keystroke
  const playKeystroke = useCallback(() => {
    if (!soundEnabled || !audioContextRef.current) return;
    const ctx = audioContextRef.current;

    // Resume context if suspended
    if (ctx.state === "suspended") ctx.resume();

    // Create a very short, high-pitched mechanical "click"
    const osc = ctx.createOscillator();
    const gainNode = ctx.createGain();

    osc.type = "square";
    // Randomize frequency slightly for organic feel
    osc.frequency.setValueAtTime(150 + Math.random() * 50, ctx.currentTime);

    // Very sharp envelope
    gainNode.gain.setValueAtTime(0, ctx.currentTime);
    gainNode.gain.linearRampToValueAtTime(0.05, ctx.currentTime + 0.002);
    gainNode.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.02);

    osc.connect(gainNode);
    gainNode.connect(ctx.destination);

    osc.start();
    osc.stop(ctx.currentTime + 0.02);
  }, [soundEnabled]);

  // Handle keyboard shortcut (CMD+K)
  useEffect(() => {
    const down = (e: KeyboardEvent) => {
      if (e.key === "k" && (e.metaKey || e.ctrlKey)) {
        e.preventDefault();
        onOpenChange(!open);
      }
    };
    document.addEventListener("keydown", down);
    return () => document.removeEventListener("keydown", down);
  }, [open, onOpenChange]);

  // Matrix scramble effect for selected items
  const handleSelect = (onSelectAction: () => void) => {
    // Play slightly different sound for enter
    if (audioContextRef.current && soundEnabled) {
      const ctx = audioContextRef.current;
      const osc = ctx.createOscillator();
      const gainNode = ctx.createGain();
      osc.type = "triangle";
      osc.frequency.setValueAtTime(300, ctx.currentTime);
      osc.frequency.exponentialRampToValueAtTime(100, ctx.currentTime + 0.1);
      gainNode.gain.setValueAtTime(0.1, ctx.currentTime);
      gainNode.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.1);
      osc.connect(gainNode);
      gainNode.connect(ctx.destination);
      osc.start();
      osc.stop(ctx.currentTime + 0.1);
    }

    setTimeout(() => {
      onSelectAction();
      onOpenChange(false);
      setInputValue("");
    }, 150);
  };

  return (
    <>
      {/* 
        Tailwind CSS for CRT effects. We inject these here to avoid bloating global CSS.
        Usually better in a stylesheet, but fine for a drop-in component.
      */}
      <style dangerouslySetInnerHTML={{__html: `
        .crt-overlay {
          background: linear-gradient(
            to bottom,
            rgba(255,255,255,0),
            rgba(255,255,255,0) 50%,
            rgba(0,0,0,0.2) 50%,
            rgba(0,0,0,0.2)
          );
          background-size: 100% 4px;
          pointer-events: none;
        }
        @keyframes crt-flicker {
          0% { opacity: 0.95; }
          5% { opacity: 0.85; }
          10% { opacity: 0.95; }
          100% { opacity: 0.98; }
        }
        .animate-crt {
          animation: crt-flicker 0.15s infinite;
        }
        .phosphor-glow {
          text-shadow: 0 0 5px rgba(52, 211, 153, 0.8), 0 0 10px rgba(52, 211, 153, 0.4);
        }

        /* cmdk specific styles to override default headless behavior */
        [cmdk-root] {
          width: 100%;
          background: transparent;
        }
        [cmdk-input] {
          font-family: monospace;
          border: none;
          width: 100%;
          font-size: 1.125rem;
          padding: 1rem 1.5rem;
          outline: none;
          background: transparent;
          color: #34d399; /* emerald-400 */
        }
        [cmdk-input]::placeholder {
          color: #065f46; /* emerald-800 */
        }
        [cmdk-list] {
          min-height: 300px;
          max-height: 400px;
          overflow: auto;
          overscroll-behavior: contain;
          padding: 0.5rem 1rem 1rem 1rem;
        }
        [cmdk-group-heading] {
          padding: 0.5rem 0.5rem;
          color: #059669; /* emerald-600 */
          font-size: 0.75rem;
          text-transform: uppercase;
          letter-spacing: 0.1em;
          font-weight: bold;
          font-family: monospace;
        }
        [cmdk-item] {
          content-visibility: auto;
          cursor: pointer;
          height: 40px;
          border-radius: 4px;
          font-size: 0.875rem;
          display: flex;
          align-items: center;
          gap: 0.75rem;
          padding: 0 0.75rem;
          color: #10b981; /* emerald-500 */
          font-family: monospace;
          user-select: none;
          transition: all 0.1s ease;
        }
        [cmdk-item][data-selected="true"] {
          background: #064e3b; /* emerald-900 */
          color: #6ee7b7; /* emerald-300 */
          box-shadow: inset 2px 0 0 #34d399;
        }
        [cmdk-empty] {
          font-size: 0.875rem;
          padding: 2rem;
          text-align: center;
          color: #059669;
          font-family: monospace;
        }
      `}} />

      <Command.Dialog 
        open={open} 
        onOpenChange={onOpenChange}
        className={cn(
          "fixed top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2 w-full max-w-2xl bg-[#022c22] border-2 border-emerald-500/30 rounded-xl overflow-hidden shadow-[0_0_50px_rgba(4,120,87,0.5)] z-50 animate-crt",
          className
        )}
      >
        <DialogTitle className="sr-only">Cyber Terminal</DialogTitle>
        <DialogDescription className="sr-only">Cyberpunk styled command palette</DialogDescription>

        {/* CRT Overlay Effects */}
        <div className="absolute inset-0 crt-overlay z-10 pointer-events-none" />
        <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,transparent_50%,rgba(0,0,0,0.4)_100%)] z-10 pointer-events-none" />

        {/* Header decoration */}
        <div className="bg-emerald-950/80 border-b border-emerald-800/50 px-4 py-2 flex items-center justify-between font-mono text-[10px] text-emerald-600 select-none">
          <div className="flex items-center gap-2">
            <TerminalSquare className="w-3 h-3" />
            <span>CYBER_OS v9.4.1</span>
          </div>
          <div className="flex gap-2">
            <span className="animate-pulse">_REC</span>
            <span>MEM: 640K</span>
          </div>
        </div>

        <div className="relative z-20" onClickCapture={initAudio}>
          <div className="flex items-center px-2 border-b border-emerald-900/50">
            <span className="text-emerald-500 font-mono ml-4 mr-2 phosphor-glow">{">"}</span>
            <Command.Input 
              value={inputValue}
              onValueChange={(val) => {
                setInputValue(val);
                playKeystroke();
              }}
              placeholder="ENTER COMMAND..."
              className="phosphor-glow"
              autoFocus
            />
          </div>

          <Command.List>
            <Command.Empty>ERR: COMMAND NOT FOUND.</Command.Empty>

            {commands.map((group) => (
              <Command.Group key={group.heading} heading={group.heading}>
                {group.items.map((item) => (
                  <Command.Item 
                    key={item.id} 
                    onSelect={() => handleSelect(item.onSelect)}
                    className="group"
                  >
                    <span className="opacity-50 group-data-[selected=true]:opacity-100 transition-opacity">
                      {item.icon}
                    </span>
                    <span className="phosphor-glow uppercase tracking-wider">{item.title}</span>
                  </Command.Item>
                ))}
              </Command.Group>
            ))}
          </Command.List>
        </div>
      </Command.Dialog>
    </>
  );
}

"use client";

import React, { useMemo } from "react";
import { motion } from "framer-motion";
import { cn } from "@/lib/utils";

export interface CylinderMarqueeProps {
  items: React.ReactNode[];
  itemWidth?: number; // width in pixels
  itemHeight?: number; // height in pixels
  radius?: number; // If not provided, it's calculated automatically
  speed?: number; // seconds per full rotation
  direction?: "left" | "right";
  className?: string;
  itemClassName?: string;
}

export function CylinderMarquee({
  items,
  itemWidth = 300,
  itemHeight = 200,
  radius,
  speed = 20,
  direction = "left",
  className,
  itemClassName,
}: CylinderMarqueeProps) {
  const itemCount = items.length;
  const rotationAngle = 360 / itemCount;

  // Calculate the Z-translation required to form a perfect circle
  // r = (w / 2) / tan(π / n)
  const calculatedRadius = useMemo(() => {
    if (radius) return radius;
    // Add a little padding to the width for spacing
    const paddedWidth = itemWidth + 20; 
    return Math.round(paddedWidth / 2 / Math.tan(Math.PI / itemCount));
  }, [itemWidth, itemCount, radius]);

  return (
    <div 
      className={cn("relative flex items-center justify-center", className)}
      style={{ perspective: "1000px" }}
    >
      {/* Tilted container to view the cylinder from slightly above */}
      <div style={{ transform: "rotateX(-15deg)", transformStyle: "preserve-3d" }}>
        <motion.div
          className="relative flex items-center justify-center"
          style={{
            width: itemWidth,
            height: itemHeight,
            transformStyle: "preserve-3d",
          }}
          animate={{
            rotateY: direction === "left" ? [0, -360] : [0, 360],
          }}
          transition={{
            duration: speed,
            repeat: Infinity,
            ease: "linear",
          }}
        >
        {items.map((item, index) => {
          const rotateY = index * rotationAngle;

          return (
            <div
              key={index}
              className={cn(
                "absolute top-0 left-0 flex items-center justify-center",
                itemClassName
              )}
              style={{
                width: itemWidth,
                height: itemHeight,
                transform: `rotateY(${rotateY}deg) translateZ(${calculatedRadius}px)`,
                // We add a tiny bit of opacity fading if we want, but native 3D handles it beautifully
              }}
            >
              {item}
            </div>
          );
        })}
        </motion.div>
      </div>
    </div>
  );
}

"use client";

import React, { useState, useRef, createContext, useContext } from "react";
import { motion, useDragControls, AnimatePresence } from "framer-motion";
import { Maximize2, Minus, X } from "lucide-react";
import { cn } from "@/lib/utils";

// Context to manage highest z-index across all windows
const DesktopContext = createContext<{
  highestZ: number;
  bringToFront: () => number;
  containerRef: React.RefObject<HTMLDivElement> | null;
}>({ highestZ: 10, bringToFront: () => 10, containerRef: null });

interface DesktopEnvironmentProps {
  children: React.ReactNode;
  className?: string;
  backgroundUrl?: string;
}

export function DesktopEnvironment({ children, className, backgroundUrl }: DesktopEnvironmentProps) {
  const [highestZ, setHighestZ] = useState(10);
  const containerRef = useRef<HTMLDivElement>(null);

  const bringToFront = () => {
    setHighestZ(prev => prev + 1);
    return highestZ + 1;
  };

  return (
    <DesktopContext.Provider value={{ highestZ, bringToFront, containerRef }}>
      <div 
        ref={containerRef}
        className={cn("relative w-full h-full overflow-hidden bg-slate-900", className)}
        style={{
          backgroundImage: backgroundUrl ? `url(${backgroundUrl})` : undefined,
          backgroundSize: "cover",
          backgroundPosition: "center"
        }}
      >
        {children}
      </div>
    </DesktopContext.Provider>
  );
}

interface DraggableWindowProps {
  id: string;
  title: string;
  children: React.ReactNode;
  defaultPosition?: { x: number; y: number };
  defaultSize?: { width: number | string; height: number | string };
  className?: string;
  onClose?: () => void;
}

export function DraggableWindow({
  id,
  title,
  children,
  defaultPosition = { x: 50, y: 50 },
  defaultSize = { width: 600, height: 400 },
  className,
  onClose
}: DraggableWindowProps) {
  const { bringToFront, containerRef } = useContext(DesktopContext);
  const [zIndex, setZIndex] = useState(10);
  const [isMinimized, setIsMinimized] = useState(false);
  const [isFullscreen, setIsFullscreen] = useState(false);

  const dragControls = useDragControls();

  const handlePointerDown = (e: React.PointerEvent) => {
    setZIndex(bringToFront());
  };

  if (isMinimized) return null;

  return (
    <motion.div
      drag={!isFullscreen}
      dragControls={dragControls}
      dragListener={false} // Disable dragging on the whole body
      dragConstraints={containerRef || undefined}
      dragMomentum={false}
      dragElastic={0}
      initial={{ x: defaultPosition.x, y: defaultPosition.y, scale: 0.95, opacity: 0 }}
      animate={{ 
        x: isFullscreen ? 0 : undefined,
        y: isFullscreen ? 0 : undefined,
        scale: 1, 
        opacity: 1,
        width: isFullscreen ? "100%" : defaultSize.width,
        height: isFullscreen ? "100%" : defaultSize.height,
      }}
      exit={{ scale: 0.95, opacity: 0 }}
      transition={{ type: "spring", stiffness: 400, damping: 30 }}
      onPointerDown={handlePointerDown}
      style={{ zIndex }}
      className={cn(
        "absolute flex flex-col bg-slate-950/80 backdrop-blur-2xl border border-white/20 rounded-xl overflow-hidden shadow-2xl",
        isFullscreen && "rounded-none border-none",
        className
      )}
    >
      {/* Title Bar - Drag Handle */}
      <div 
        className="flex items-center justify-between px-4 py-2 bg-white/[0.02] border-b border-white/10 select-none touch-none"
        onPointerDown={(e) => {
          handlePointerDown(e);
          dragControls.start(e);
        }}
        onDoubleClick={() => setIsFullscreen(!isFullscreen)}
      >
        <div className="flex gap-2 items-center w-16">
          <button 
            onClick={(e) => { e.stopPropagation(); onClose?.(); }}
            className="w-3 h-3 rounded-full bg-red-500/80 hover:bg-red-500 flex items-center justify-center group"
          >
            <X className="w-2 h-2 text-black/50 opacity-0 group-hover:opacity-100" />
          </button>
          <button 
            onClick={(e) => { e.stopPropagation(); setIsMinimized(true); }}
            className="w-3 h-3 rounded-full bg-yellow-500/80 hover:bg-yellow-500 flex items-center justify-center group"
          >
            <Minus className="w-2 h-2 text-black/50 opacity-0 group-hover:opacity-100" />
          </button>
          <button 
            onClick={(e) => { e.stopPropagation(); setIsFullscreen(!isFullscreen); }}
            className="w-3 h-3 rounded-full bg-green-500/80 hover:bg-green-500 flex items-center justify-center group"
          >
            <Maximize2 className="w-2 h-2 text-black/50 opacity-0 group-hover:opacity-100" />
          </button>
        </div>

        <div className="text-xs font-medium text-zinc-400">
          {title}
        </div>

        <div className="w-16" /> {/* Spacer for centering title */}
      </div>

      {/* Content Body */}
      <div className="flex-1 overflow-auto custom-scrollbar relative bg-black/20">
        {children}
      </div>
    </motion.div>
  );
}

"use client";

import React, { useState } from "react";
import { motion } from "framer-motion";
import { cn } from "@/lib/utils";

export interface DestructibleUIProps {
  children: React.ReactNode;
  isDestroyed: boolean;
  className?: string;
  force?: number;
}

const SHARDS = [
  // Shard 1 (Top Left)
  {
    clipPath: "polygon(0% 0%, 60% 0%, 40% 60%, 0% 40%)",
    targetX: -100,
    targetY: 200,
    targetRotate: -45,
  },
  // Shard 2 (Top Right)
  {
    clipPath: "polygon(60% 0%, 100% 0%, 100% 60%, 40% 60%)",
    targetX: 120,
    targetY: 150,
    targetRotate: 60,
  },
  // Shard 3 (Bottom Left)
  {
    clipPath: "polygon(0% 40%, 40% 60%, 30% 100%, 0% 100%)",
    targetX: -80,
    targetY: 300,
    targetRotate: -90,
  },
  // Shard 4 (Bottom Center)
  {
    clipPath: "polygon(40% 60%, 100% 60%, 70% 100%, 30% 100%)",
    targetX: 40,
    targetY: 400,
    targetRotate: 20,
  },
  // Shard 5 (Bottom Right)
  {
    clipPath: "polygon(100% 60%, 100% 100%, 70% 100%)",
    targetX: 150,
    targetY: 250,
    targetRotate: 110,
  },
];

export function DestructibleUI({
  children,
  isDestroyed,
  className,
  force = 1,
}: DestructibleUIProps) {
  return (
    <div className={cn("relative inline-block", className)}>
      {/* 
        We keep the original children in the DOM but make them invisible when destroyed.
        This ensures the parent wrapper maintains the exact same layout dimensions!
      */}
      <div className={cn("transition-opacity duration-0", isDestroyed ? "opacity-0 pointer-events-none" : "opacity-100")}>
        {children}
      </div>

      {isDestroyed &&
        SHARDS.map((shard, i) => (
          <motion.div
            key={i}
            className="absolute inset-0 z-50 pointer-events-none"
            style={{ clipPath: shard.clipPath }}
            initial={{ opacity: 1, x: 0, y: 0, rotate: 0, scale: 1 }}
            animate={{
              opacity: [1, 1, 0], // Stay visible while falling, fade out at end
              x: shard.targetX * force,
              y: shard.targetY * force,
              rotate: shard.targetRotate * force,
              scale: 0.8,
            }}
            transition={{ 
              duration: 1.2 + Math.random() * 0.5, // Slight random stagger in fall speed
              ease: [0.32, 0.72, 0, 1], // Custom gravity-like ease
              times: [0, 0.7, 1]
            }}
          >
            {/* The shard contains an exact visual clone of the children */}
            {children}
          </motion.div>
        ))}
    </div>
  );
}

