"use client";

import React, { useRef } from "react";
import { motion, useMotionValue, useSpring, useMotionTemplate } from "framer-motion";
import { cn } from "@/lib/utils";

export interface FlashlightRevealProps {
  text: string;
  className?: string;
  cursorSize?: number;
}

export function FlashlightReveal({ text, className, cursorSize = 300 }: FlashlightRevealProps) {
  const containerRef = useRef<HTMLDivElement>(null);
  const mouseX = useMotionValue(-1000);
  const mouseY = useMotionValue(-1000);

  // Smooth out the flashlight movement
  const springX = useSpring(mouseX, { stiffness: 100, damping: 20 });
  const springY = useSpring(mouseY, { stiffness: 100, damping: 20 });

  const handleMouseMove = (e: React.MouseEvent | React.TouchEvent) => {
    if (!containerRef.current) return;
    const rect = containerRef.current.getBoundingClientRect();

    let clientX, clientY;
    if ("touches" in e) {
      clientX = e.touches[0].clientX;
      clientY = e.touches[0].clientY;
    } else {
      clientX = (e as React.MouseEvent).clientX;
      clientY = (e as React.MouseEvent).clientY;
    }

    mouseX.set(clientX - rect.left);
    mouseY.set(clientY - rect.top);
  };

  const handleMouseLeave = () => {
    // Move the flashlight far away when not hovering
    mouseX.set(-1000);
    mouseY.set(-1000);
  };

  return (
    <div 
      ref={containerRef}
      className={cn("relative w-full h-[600px] bg-zinc-950 overflow-hidden", className)}
      onMouseMove={handleMouseMove}
      onMouseLeave={handleMouseLeave}
      onTouchMove={handleMouseMove}
      onTouchEnd={handleMouseLeave}
      onTouchCancel={handleMouseLeave}
    >
      {/* 
        LAYER 1 (Bottom): The Colorful Reveal 
        This is what we see when the flashlight shines on it.
      */}
      <div className="absolute inset-0 w-full h-full flex items-center justify-center bg-zinc-900">
        {/* Colorful Gradient Background */}
        <div className="absolute inset-0 bg-gradient-to-br from-indigo-500 via-purple-500 to-pink-500 opacity-20" />
        {/* Colorful Text */}
        <h1 className="text-6xl md:text-9xl font-black uppercase tracking-tighter text-transparent bg-clip-text bg-gradient-to-br from-indigo-400 via-purple-400 to-pink-400 z-10 text-center px-4">
          {text}
        </h1>
        {/* Subtle grid for extra depth */}
        <div 
          className="absolute inset-0 z-0 pointer-events-none opacity-30 mix-blend-overlay"
          style={{
            backgroundImage: `linear-gradient(to right, #ffffff 1px, transparent 1px), linear-gradient(to bottom, #ffffff 1px, transparent 1px)`,
            backgroundSize: `40px 40px`
          }}
        />
      </div>

      {/* 
        LAYER 2 (Top): The Pitch Black Overlay 
        This layer covers everything. We punch a hole in it using CSS masking.
      */}
      <motion.div 
        className="absolute inset-0 w-full h-full flex items-center justify-center bg-zinc-950 z-20 pointer-events-none"
        style={{
          // Mask out a radial gradient hole where the mouse is
          WebkitMaskImage: useMotionTemplate`radial-gradient(circle ${cursorSize / 2}px at ${springX}px ${springY}px, transparent 0%, black 100%)`,
          maskImage: useMotionTemplate`radial-gradient(circle ${cursorSize / 2}px at ${springX}px ${springY}px, transparent 0%, black 100%)`
        }}
      >
        {/* Standard subtle text that you see before shining the light */}
        <h1 className="text-6xl md:text-9xl font-black uppercase tracking-tighter text-zinc-800 z-10 text-center px-4">
          {text}
        </h1>
      </motion.div>
    </div>
  );
}

"use client";

import React, { useEffect, useState, useRef } from "react";
import { cn } from "@/lib/utils";
import { motion } from "framer-motion";

// Standard character set for the flip board
const ALPHABET = " ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789.,!?@#$%&*()+-=";

interface FlipBoardProps {
  /** The text to display on the board */
  text: string;
  /** Number of rows in the board */
  rows?: number;
  /** Number of columns in the board (defaults to text length if rows=1) */
  cols?: number;
  /** Container class */
  className?: string;
  /** Character flap class */
  charClassName?: string;
  /** Theme of the board */
  theme?: "dark" | "light";
}

export function FlipBoard({
  text,
  rows = 1,
  cols,
  className,
  charClassName,
  theme = "dark",
}: FlipBoardProps) {
  const colCount = cols || Math.max(text.length, 1);
  const totalCells = rows * colCount;

  // Pad the text to fill the board
  const paddedText = (
    text.toUpperCase() + " ".repeat(Math.max(0, totalCells - text.length))
  ).slice(0, totalCells);

  const gridRows = [];
  for (let i = 0; i < rows; i++) {
    gridRows.push(paddedText.slice(i * colCount, (i + 1) * colCount));
  }

  return (
    <div
      className={cn(
        "flex flex-col gap-1 p-4 rounded-xl",
        theme === "dark"
          ? "bg-black border border-neutral-800 shadow-2xl"
          : "bg-neutral-300 border border-neutral-400 shadow-xl",
        className
      )}
    >
      {gridRows.map((rowText, rowIndex) => (
        <div key={rowIndex} className="flex gap-1 justify-center">
          {rowText.split("").map((char, colIndex) => (
            <FlipChar
              key={`${rowIndex}-${colIndex}`}
              targetChar={char}
              className={charClassName}
              theme={theme}
              // Add a slight stagger from top-left to bottom-right
              delay={(rowIndex * colCount + colIndex) * 0.03}
            />
          ))}
        </div>
      ))}
    </div>
  );
}

interface FlipCharProps {
  targetChar: string;
  delay?: number;
  className?: string;
  theme?: "dark" | "light";
}

function FlipChar({
  targetChar,
  delay = 0,
  className,
  theme = "dark",
}: FlipCharProps) {
  const [displayChar, setDisplayChar] = useState(ALPHABET[0]);
  const [nextChar, setNextChar] = useState(ALPHABET[0]);
  const [isFlipping, setIsFlipping] = useState(false);

  const currentRef = useRef(ALPHABET[0]);

  useEffect(() => {
    // Treat unknown characters as space
    const charToFind = targetChar.toUpperCase();
    const targetC = ALPHABET.includes(charToFind) ? charToFind : " ";

    if (currentRef.current === targetC) return;

    let interval: NodeJS.Timeout;
    let flipTimeout: NodeJS.Timeout;

    const startCycle = () => {
      interval = setInterval(() => {
        if (currentRef.current === targetC) {
          clearInterval(interval);
          return;
        }

        let currentIndex = ALPHABET.indexOf(currentRef.current);
        if (currentIndex === -1) currentIndex = 0;

        const nextIndex = (currentIndex + 1) % ALPHABET.length;
        const nextC = ALPHABET[nextIndex];

        setNextChar(nextC);
        setIsFlipping(true);

        flipTimeout = setTimeout(() => {
          currentRef.current = nextC;
          setDisplayChar(nextC);
          setIsFlipping(false);
        }, 50); // Half of the interval for the flip down
      }, 100); // Speed of character cycling (very fast)
    };

    const startDelay = setTimeout(startCycle, delay * 1000);

    return () => {
      clearTimeout(startDelay);
      clearInterval(interval);
      clearTimeout(flipTimeout);
    };
  }, [targetChar, delay]);

  const isDark = theme === "dark";
  const bgClass = isDark
    ? "bg-zinc-900 border-zinc-950 text-zinc-100"
    : "bg-white border-zinc-200 text-zinc-900";
  const innerBgClass = isDark ? "bg-zinc-900" : "bg-white";
  const dividerClass = isDark ? "bg-black/80" : "bg-zinc-300/80";

  return (
    <div
      className={cn(
        "relative inline-block perspective-[400px]",
        className
      )}
    >
      <div
        className={cn(
          "relative w-7 h-10 sm:w-10 sm:h-14 rounded-[3px] sm:rounded-md shadow-sm border font-mono text-xl sm:text-3xl font-bold flex flex-col justify-center items-center overflow-hidden",
          bgClass
        )}
      >
        {/* The center line crease */}
        <div
          className={cn(
            "absolute top-1/2 left-0 w-full h-[1px] sm:h-[2px] -mt-[0.5px] sm:-mt-[1px] z-20 shadow-sm",
            dividerClass
          )}
        />

        {/* Top Half (Next Char Background) */}
        <div
          className={cn(
            "absolute top-0 left-0 w-full h-1/2 overflow-hidden flex items-end justify-center pb-[1px]",
            innerBgClass
          )}
        >
          <span className="translate-y-[50%]">{nextChar}</span>
        </div>

        {/* Bottom Half (Current Char Background) */}
        <div
          className={cn(
            "absolute bottom-0 left-0 w-full h-1/2 overflow-hidden flex items-start justify-center pt-[1px]",
            innerBgClass
          )}
        >
          <span className="-translate-y-[50%]">{displayChar}</span>
        </div>

        {/* Flap Top (Current Char folding down) */}
        <motion.div
          initial={{ rotateX: 0 }}
          animate={isFlipping ? { rotateX: -90 } : { rotateX: 0 }}
          transition={{ duration: 0.05, ease: "linear" }}
          className={cn(
            "absolute top-0 left-0 w-full h-1/2 overflow-hidden flex items-end justify-center pb-[1px] origin-bottom z-10 shadow-[inset_0_-1px_2px_rgba(0,0,0,0.3)]",
            innerBgClass
          )}
          style={{ backfaceVisibility: "hidden" }}
        >
          <span className="translate-y-[50%]">{displayChar}</span>
        </motion.div>

        {/* Flap Bottom (Next Char unfolding from back) */}
        <motion.div
          initial={{ rotateX: 90 }}
          animate={isFlipping ? { rotateX: 0 } : { rotateX: 90 }}
          transition={{ duration: 0.05, ease: "linear", delay: 0.05 }}
          className={cn(
            "absolute bottom-0 left-0 w-full h-1/2 overflow-hidden flex items-start justify-center pt-[1px] origin-top z-10 shadow-[inset_0_1px_2px_rgba(0,0,0,0.3)]",
            innerBgClass
          )}
          style={{ backfaceVisibility: "hidden" }}
        >
          <span className="-translate-y-[50%]">{nextChar}</span>
        </motion.div>
      </div>
    </div>
  );
}

'use client';

import React, { useRef, useState, useMemo } from 'react';
import { Canvas, useFrame } from '@react-three/fiber';
import {
  Icosahedron,
  Octahedron,
  Dodecahedron,
  Torus,
  TorusKnot,
  Float,
  Environment,
  ContactShadows,
  MeshDistortMaterial,
  MeshTransmissionMaterial,
} from '@react-three/drei';
import * as THREE from 'three';
import { cn } from '@/lib/utils';

export type Floating3DVariant = 'crystal' | 'nebula' | 'prism' | 'plasma' | 'ring';

interface CardProps extends React.HTMLAttributes<HTMLDivElement> {
  children: React.ReactNode;
  color?: string;
  speed?: number;
  scale?: number;
  variant?: Floating3DVariant;
}

// ─── Crystal Variant: Wireframe icosahedron with glass inner ──────────────────
function CrystalScene({ color = '#818cf8', speed = 1, scale = 1 }: { color?: string; speed?: number; scale?: number }) {
  const outerRef = useRef<THREE.Mesh>(null);
  const innerRef = useRef<THREE.Mesh>(null);

  useFrame((state) => {
    if (!outerRef.current) return;
    const targetX = (state.pointer.x * Math.PI) / 4;
    const targetY = (state.pointer.y * Math.PI) / 4;
    outerRef.current.rotation.y += (targetX - outerRef.current.rotation.y) * 0.08;
    outerRef.current.rotation.x += (-targetY - outerRef.current.rotation.x) * 0.08;

    if (innerRef.current) {
      innerRef.current.rotation.y = outerRef.current.rotation.y * 0.6;
      innerRef.current.rotation.x = outerRef.current.rotation.x * 0.6;
      innerRef.current.rotation.z += 0.003 * speed;
    }
  });

  return (
    <Float speed={1.5 * speed} rotationIntensity={0.8} floatIntensity={1.5}>
      <Icosahedron ref={outerRef} args={[1.5 * scale, 1]} position={[0, 0, 0]}>
        <meshPhysicalMaterial
          color={color}
          roughness={0.05}
          metalness={0.9}
          clearcoat={1}
          clearcoatRoughness={0.05}
          wireframe
        />
      </Icosahedron>
      <Icosahedron ref={innerRef} args={[1.1 * scale, 0]} position={[0, 0, 0]}>
        <meshPhysicalMaterial
          color={color}
          roughness={0.15}
          metalness={0.4}
          transparent
          opacity={0.6}
          envMapIntensity={2}
        />
      </Icosahedron>
    </Float>
  );
}

// ─── Nebula Variant: Distorted sphere with animated surface ───────────────────
function NebulaScene({ color = '#a855f7', speed = 1, scale = 1 }: { color?: string; speed?: number; scale?: number }) {
  const meshRef = useRef<THREE.Mesh>(null);
  const distortRef = useRef(3);

  useFrame((state) => {
    if (!meshRef.current) return;
    const targetX = (state.pointer.x * Math.PI) / 5;
    const targetY = (state.pointer.y * Math.PI) / 5;
    meshRef.current.rotation.y += (targetX - meshRef.current.rotation.y) * 0.06;
    meshRef.current.rotation.x += (-targetY - meshRef.current.rotation.x) * 0.06;

    // Animate distortion
    distortRef.current = 0.3 + Math.sin(state.clock.elapsedTime * speed * 0.8) * 0.15;
  });

  return (
    <Float speed={1.2 * speed} rotationIntensity={0.5} floatIntensity={2}>
      <mesh ref={meshRef} scale={1.4 * scale}>
        <icosahedronGeometry args={[1, 8]} />
        <MeshDistortMaterial
          color={color}
          roughness={0.2}
          metalness={0.8}
          distort={0.35}
          speed={2 * speed}
          envMapIntensity={1.5}
        />
      </mesh>
    </Float>
  );
}

// ─── Prism Variant: Rotating octahedron with refractive glass ─────────────────
function PrismScene({ color = '#22d3ee', speed = 1, scale = 1 }: { color?: string; speed?: number; scale?: number }) {
  const meshRef = useRef<THREE.Mesh>(null);
  const ringRef = useRef<THREE.Mesh>(null);

  useFrame((state) => {
    if (!meshRef.current) return;
    const targetX = (state.pointer.x * Math.PI) / 4;
    const targetY = (state.pointer.y * Math.PI) / 4;
    meshRef.current.rotation.y += (targetX - meshRef.current.rotation.y) * 0.08;
    meshRef.current.rotation.x += (-targetY - meshRef.current.rotation.x) * 0.08;
    meshRef.current.rotation.z += 0.002 * speed;

    if (ringRef.current) {
      ringRef.current.rotation.x += 0.004 * speed;
      ringRef.current.rotation.y += 0.006 * speed;
    }
  });

  return (
    <Float speed={2 * speed} rotationIntensity={0.6} floatIntensity={1.8}>
      <group>
        <Octahedron ref={meshRef} args={[1.3 * scale]} position={[0, 0, 0]}>
          <meshPhysicalMaterial
            color={color}
            roughness={0.0}
            metalness={0.1}
            transparent
            opacity={0.85}
            transmission={0.6}
            thickness={1.5}
            ior={2.4}
            envMapIntensity={3}
          />
        </Octahedron>
        <Torus ref={ringRef} args={[1.8 * scale, 0.015, 16, 100]} position={[0, 0, 0]}>
          <meshPhysicalMaterial
            color={color}
            roughness={0.1}
            metalness={0.95}
            emissive={color}
            emissiveIntensity={0.5}
          />
        </Torus>
      </group>
    </Float>
  );
}

// ─── Plasma Variant: Organic blob with emissive glow ──────────────────────────
function PlasmaScene({ color = '#f43f5e', speed = 1, scale = 1 }: { color?: string; speed?: number; scale?: number }) {
  const meshRef = useRef<THREE.Mesh>(null);

  useFrame((state) => {
    if (!meshRef.current) return;
    const targetX = (state.pointer.x * Math.PI) / 5;
    const targetY = (state.pointer.y * Math.PI) / 5;
    meshRef.current.rotation.y += (targetX - meshRef.current.rotation.y) * 0.05;
    meshRef.current.rotation.x += (-targetY - meshRef.current.rotation.x) * 0.05;
  });

  return (
    <Float speed={1 * speed} rotationIntensity={0.4} floatIntensity={2.5}>
      <mesh ref={meshRef} scale={1.3 * scale}>
        <icosahedronGeometry args={[1, 6]} />
        <MeshDistortMaterial
          color={color}
          roughness={0.1}
          metalness={0.3}
          distort={0.5}
          speed={1.5 * speed}
          emissive={color}
          emissiveIntensity={0.3}
          envMapIntensity={2}
        />
      </mesh>
    </Float>
  );
}

// ─── Ring Variant: Torus knot with metallic finish ────────────────────────────
function RingScene({ color = '#f59e0b', speed = 1, scale = 1 }: { color?: string; speed?: number; scale?: number }) {
  const meshRef = useRef<THREE.Mesh>(null);

  useFrame((state) => {
    if (!meshRef.current) return;
    const targetX = (state.pointer.x * Math.PI) / 4;
    const targetY = (state.pointer.y * Math.PI) / 4;
    meshRef.current.rotation.y += (targetX - meshRef.current.rotation.y) * 0.07;
    meshRef.current.rotation.x += (-targetY - meshRef.current.rotation.x) * 0.07;
    meshRef.current.rotation.z += 0.003 * speed;
  });

  return (
    <Float speed={1.5 * speed} rotationIntensity={0.7} floatIntensity={1.5}>
      <TorusKnot ref={meshRef} args={[0.9 * scale, 0.3 * scale, 128, 32]} position={[0, 0, 0]}>
        <meshPhysicalMaterial
          color={color}
          roughness={0.05}
          metalness={0.95}
          clearcoat={1}
          clearcoatRoughness={0.05}
          envMapIntensity={2.5}
        />
      </TorusKnot>
    </Float>
  );
}

// ─── Scene Wrapper ────────────────────────────────────────────────────────────
function Scene({ variant = 'crystal', color, speed = 1, scale = 1 }: {
  variant?: Floating3DVariant;
  color?: string;
  speed?: number;
  scale?: number;
}) {
  const SceneMap: Record<Floating3DVariant, React.FC<{ color?: string; speed?: number; scale?: number }>> = {
    crystal: CrystalScene,
    nebula: NebulaScene,
    prism: PrismScene,
    plasma: PlasmaScene,
    ring: RingScene,
  };

  const ActiveScene = SceneMap[variant] || CrystalScene;

  return (
    <>
      <ambientLight intensity={0.4} />
      <directionalLight position={[8, 8, 5]} intensity={1.2} />
      <directionalLight position={[-5, -3, -5]} intensity={0.3} color="#4338ca" />
      <pointLight position={[0, 0, 4]} intensity={0.5} color={color || '#818cf8'} />
      <Environment preset="city" />

      <ActiveScene color={color} speed={speed} scale={scale} />

      <ContactShadows
        position={[0, -2.5, 0]}
        opacity={0.35}
        scale={10}
        blur={2.5}
        far={4}
        color="#000000"
      />
    </>
  );
}

// ─── Main Floating3DCard Component ────────────────────────────────────────────
export function Floating3DCard({
  children,
  className,
  color,
  speed = 1,
  scale = 1,
  variant = 'crystal',
  ...props
}: CardProps) {
  const [isHovered, setIsHovered] = useState(false);
  const accentColor = color || {
    crystal: '#818cf8',
    nebula: '#a855f7',
    prism: '#22d3ee',
    plasma: '#f43f5e',
    ring: '#f59e0b',
  }[variant];

  return (
    <div
      className={cn(
        "relative w-full max-w-sm rounded-3xl border bg-background/50 backdrop-blur-xl overflow-hidden transition-all duration-500 hover:shadow-2xl",
        isHovered ? "border-white/20" : "border-border/50",
        className,
      )}
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
      style={{
        boxShadow: isHovered ? `0 0 40px ${accentColor}15, 0 20px 60px rgba(0,0,0,0.3)` : undefined,
      }}
      {...props}
    >
      {/* 3D Canvas Area */}
      <div
        className="h-72 w-full relative"
        style={{
          background: `linear-gradient(180deg, ${accentColor}10 0%, transparent 80%)`,
        }}
      >
        <Canvas
          camera={{ position: [0, 0, 5], fov: 45 }}
          dpr={[1, 2]}
          gl={{ antialias: true, alpha: true }}
        >
          <Scene variant={variant} color={color} speed={speed} scale={scale} />
        </Canvas>

        {/* Hover glow overlay */}
        <div
          className="absolute inset-0 transition-opacity duration-500 pointer-events-none"
          style={{
            opacity: isHovered ? 1 : 0,
            background: `radial-gradient(circle at 50% 50%, ${accentColor}20 0%, transparent 70%)`,
          }}
        />

        {/* Top edge light line */}
        <div
          className="absolute top-0 left-0 right-0 h-px transition-opacity duration-500"
          style={{
            opacity: isHovered ? 1 : 0,
            background: `linear-gradient(90deg, transparent, ${accentColor}60, transparent)`,
          }}
        />
      </div>

      {/* Content Area */}
      <div className="p-6 sm:p-8">{children}</div>
    </div>
  );
}

"use client";

import React, { useState, useRef, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Plus } from "lucide-react";
import { cn } from "@/lib/utils";

export interface FABAction {
  id: string | number;
  icon: React.ReactNode;
  label: string;
  onClick?: () => void;
}

export interface FloatingActionButtonProps extends React.HTMLAttributes<HTMLDivElement> {
  actions: FABAction[];
  position?: "bottom-right" | "bottom-left";
  icon?: React.ReactNode;
}

export function FloatingActionButton({
  actions,
  position = "bottom-right",
  icon = <Plus className="w-6 h-6" />,
  className,
  ...props
}: FloatingActionButtonProps) {
  const [isOpen, setIsOpen] = useState(false);
  const containerRef = useRef<HTMLDivElement>(null);

  // Close when clicking outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (containerRef.current && !containerRef.current.contains(event.target as Node)) {
        setIsOpen(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  const positionClasses = position === "bottom-right" 
    ? "bottom-6 right-6 md:bottom-8 md:right-8 items-end" 
    : "bottom-6 left-6 md:bottom-8 md:left-8 items-start";

  return (
    <div 
      ref={containerRef}
      className={cn("fixed z-50 flex flex-col gap-4", positionClasses, className)}
      {...props}
    >
      <AnimatePresence>
        {isOpen && (
          <motion.div 
            initial={{ opacity: 0, height: 0 }}
            animate={{ opacity: 1, height: "auto" }}
            exit={{ opacity: 0, height: 0 }}
            className="flex flex-col gap-3 pb-2"
            role="menu"
            aria-orientation="vertical"
          >
            {actions.map((action, i) => (
              <motion.button
                key={action.id}
                initial={{ opacity: 0, y: 10, scale: 0.8 }}
                animate={{ opacity: 1, y: 0, scale: 1 }}
                exit={{ opacity: 0, y: 10, scale: 0.8 }}
                transition={{ delay: (actions.length - i - 1) * 0.05 }}
                onClick={() => {
                  action.onClick?.();
                  setIsOpen(false);
                }}
                role="menuitem"
                aria-label={action.label}
                className={cn(
                  "group flex items-center gap-3 focus:outline-none focus:ring-2 focus:ring-indigo-500 rounded-full",
                  position === "bottom-right" ? "flex-row-reverse" : "flex-row"
                )}
              >
                <div className="w-12 h-12 rounded-full bg-zinc-800 text-white flex items-center justify-center hover:bg-zinc-700 hover:scale-110 transition-all shadow-lg border border-white/10">
                  {action.icon}
                </div>
                <span className="px-3 py-1.5 bg-zinc-900 text-white text-xs font-medium rounded-lg opacity-0 group-hover:opacity-100 transition-opacity border border-white/10 whitespace-nowrap shadow-lg">
                  {action.label}
                </span>
              </motion.button>
            ))}
          </motion.div>
        )}
      </AnimatePresence>

      <button
        onClick={() => setIsOpen(!isOpen)}
        aria-haspopup="menu"
        aria-expanded={isOpen}
        aria-label={isOpen ? "Close menu" : "Open menu"}
        className="w-14 h-14 rounded-full bg-indigo-500 text-white flex items-center justify-center hover:bg-indigo-600 hover:scale-105 active:scale-95 transition-all shadow-xl shadow-indigo-500/20 z-10 focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:ring-offset-2 focus:ring-offset-background"
      >
        <motion.div
          animate={{ rotate: isOpen ? 45 : 0 }}
          transition={{ type: "spring", stiffness: 260, damping: 20 }}
        >
          {icon}
        </motion.div>
      </button>
    </div>
  );
}

