"use client";

import React, { useState, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { cn } from "@/lib/utils";

export type FloatingNavbarVariant = "pill" | "underline" | "block";

interface NavItem {
  label: string;
  href: string;
}

interface FloatingNavbarProps {
  items?: NavItem[];
  className?: string;
  color?: string;
  speed?: number;
  scale?: number;
  variant?: FloatingNavbarVariant;
}

const defaultItems = [
  { label: "Home", href: "#" },
  { label: "Showcase", href: "#" },
  { label: "Specs", href: "#" },
];

export function FloatingNavbar({
  items,
  className,
  color,
  speed = 1,
  scale = 1,
  variant = "pill",
}: FloatingNavbarProps) {
  const [hoveredIndex, setHoveredIndex] = useState<number | null>(null);
  const [isVisible, setIsVisible] = useState(true);
  const [lastScrollY, setLastScrollY] = useState(0);

  const navItems = items && items.length > 0 ? items : defaultItems;

  useEffect(() => {
    const handleScroll = () => {
      const currentScrollY = window.scrollY;
      if (currentScrollY > lastScrollY && currentScrollY > 100) {
        setIsVisible(false); // Hide on scroll down
      } else {
        setIsVisible(true); // Show on scroll up
      }
      setLastScrollY(currentScrollY);
    };

    window.addEventListener("scroll", handleScroll, { passive: true });
    return () => window.removeEventListener("scroll", handleScroll);
  }, [lastScrollY]);

  const hasPosition =
    className?.includes("absolute") ||
    className?.includes("relative") ||
    className?.includes("fixed");

  const activeStiffness = 350 * speed;
  const activeDamping = 25 / speed;

  return (
    <AnimatePresence>
      {isVisible && (
        <motion.nav
          initial={{ y: -100, opacity: 0 }}
          animate={{ y: 0, opacity: 1 }}
          exit={{ y: -100, opacity: 0 }}
          transition={{ duration: 0.35 / speed, ease: [0.16, 1, 0.3, 1] }}
          className={cn(
            "z-50 flex items-center justify-between rounded-full border border-border bg-background/80 backdrop-blur-xl shadow-2xl transition-colors duration-300",
            variant === "underline" ? "px-6 py-2" : "p-2",
            !hasPosition && "fixed top-6 left-1/2 -translate-x-1/2",
            className
          )}
          style={{
            transform: scale !== 1 ? `scale(${scale})` : undefined,
          }}
        >
          <div className={cn("flex items-center", variant === "underline" ? "gap-6" : "gap-1.5")}>
            {navItems.map((item, idx) => (
              <a
                key={idx}
                href={item.href}
                onMouseEnter={() => setHoveredIndex(idx)}
                onMouseLeave={() => setHoveredIndex(null)}
                className={cn(
                  "relative transition-colors",
                  variant === "underline" ? "py-2 text-sm" : "px-4 py-2 rounded-full text-xs",
                  "font-medium text-muted-foreground hover:text-foreground"
                )}
              >
                {hoveredIndex === idx && (
                  <motion.span
                    layoutId={`navHover-${variant}`}
                    className={cn(
                      "absolute -z-10",
                      variant === "underline"
                        ? "bottom-0 left-0 right-0 h-[2px] bg-foreground rounded-full"
                        : variant === "block"
                        ? "inset-0 bg-foreground rounded-full"
                        : "inset-0 bg-muted border border-border/50 rounded-full" // default pill
                    )}
                    style={
                      variant === "underline"
                        ? { backgroundColor: color || "currentColor" }
                        : variant === "block"
                        ? { backgroundColor: color ? `${color}30` : undefined }
                        : {
                            backgroundColor: color ? `${color}15` : undefined,
                            borderColor: color ? `${color}40` : undefined,
                          }
                    }
                    transition={{ type: "spring", stiffness: activeStiffness, damping: activeDamping }}
                  />
                )}
                {item.label}
              </a>
            ))}
          </div>
        </motion.nav>
      )}
    </AnimatePresence>
  );
}

"use client";

import React, { useRef, useMemo, useEffect } from "react";
import { Canvas, useFrame, useThree } from "@react-three/fiber";
import * as THREE from "three";
import { cn } from "@/lib/utils";

const vertexShader = `
varying vec2 vUv;
void main() {
  vUv = uv;
  gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
}
`;

const fragmentShader = `
uniform float uTime;
uniform vec2 uResolution;
uniform vec2 uMouse;
uniform vec3 uColor1;
uniform vec3 uColor2;
uniform vec3 uColor3;

varying vec2 vUv;

// Simplex 2D noise
vec3 permute(vec3 x) { return mod(((x*34.0)+1.0)*x, 289.0); }
float snoise(vec2 v){
  const vec4 C = vec4(0.211324865405187, 0.366025403784439,
           -0.577350269189626, 0.024390243902439);
  vec2 i  = floor(v + dot(v, C.yy) );
  vec2 x0 = v -   i + dot(i, C.xx);
  vec2 i1;
  i1 = (x0.x > x0.y) ? vec2(1.0, 0.0) : vec2(0.0, 1.0);
  vec4 x12 = x0.xyxy + C.xxzz;
  x12.xy -= i1;
  i = mod(i, 289.0);
  vec3 p = permute( permute( i.y + vec3(0.0, i1.y, 1.0 ))
  + i.x + vec3(0.0, i1.x, 1.0 ));
  vec3 m = max(0.5 - vec3(dot(x0,x0), dot(x12.xy,x12.xy), dot(x12.zw,x12.zw)), 0.0);
  m = m*m ;
  m = m*m ;
  vec3 x = 2.0 * fract(p * C.www) - 1.0;
  vec3 h = abs(x) - 0.5;
  vec3 ox = floor(x + 0.5);
  vec3 a0 = x - ox;
  m *= 1.79284291400159 - 0.85373472095314 * ( a0*a0 + h*h );
  vec3 g;
  g.x  = a0.x  * x0.x  + h.x  * x0.y;
  g.yz = a0.yz * x12.xz + h.yz * x12.yw;
  return 130.0 * dot(m, g);
}

void main() {
  vec2 uv = vUv;
  
  // Base distortion
  float noise1 = snoise(uv * 2.0 + uTime * 0.05);
  float noise2 = snoise(uv * 3.0 - uTime * 0.08 + noise1);
  
  // Mouse influence
  float mouseDist = distance(uv, uMouse);
  float mouseInfluence = smoothstep(0.6, 0.0, mouseDist);
  vec2 distortedUv = uv + noise2 * 0.15 + mouseInfluence * 0.2 * vec2(snoise(uv + uTime), snoise(uv - uTime));
  
  // Layered noise for color mixing
  float n1 = snoise(distortedUv * 2.0 + uTime * 0.1);
  float n2 = snoise(distortedUv * 4.0 - uTime * 0.15);
  
  // Mix colors
  vec3 colorA = mix(uColor1, uColor2, n1 * 0.5 + 0.5);
  vec3 finalColor = mix(colorA, uColor3, n2 * 0.5 + 0.5);
  
  // Subtle vignette
  float vignette = 1.0 - smoothstep(0.4, 1.5, length(uv - 0.5));
  
  gl_FragColor = vec4(finalColor * vignette, 1.0);
}
`;

function Scene({
  color1,
  color2,
  color3,
  speed = 1,
}: {
  color1: string;
  color2: string;
  color3: string;
  speed?: number;
}) {
  const { viewport, size } = useThree();
  const materialRef = useRef<THREE.ShaderMaterial>(null);
  
  // Track mouse coordinates globally
  const mouse = useRef(new THREE.Vector2(0.5, 0.5));
  
  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      mouse.current.x = e.clientX / window.innerWidth;
      mouse.current.y = 1.0 - (e.clientY / window.innerHeight); // GLSL coords are bottom-left
    };
    window.addEventListener("mousemove", handleMouseMove);
    return () => window.removeEventListener("mousemove", handleMouseMove);
  }, []);

  const uniforms = useMemo(
    () => ({
      uTime: { value: 0 },
      uResolution: { value: new THREE.Vector2(size.width, size.height) },
      uMouse: { value: new THREE.Vector2(0.5, 0.5) },
      uColor1: { value: new THREE.Color(color1) },
      uColor2: { value: new THREE.Color(color2) },
      uColor3: { value: new THREE.Color(color3) },
    }),
    [color1, color2, color3, size]
  );

  useFrame((state, delta) => {
    if (materialRef.current) {
      materialRef.current.uniforms.uTime.value += delta * speed;
      materialRef.current.uniforms.uResolution.value.set(size.width, size.height);
      // Smoothly interpolate mouse to avoid jerky movement
      materialRef.current.uniforms.uMouse.value.lerp(mouse.current, 0.05);
    }
  });

  return (
    <mesh>
      <planeGeometry args={[viewport.width, viewport.height]} />
      <shaderMaterial
        ref={materialRef}
        vertexShader={vertexShader}
        fragmentShader={fragmentShader}
        uniforms={uniforms}
      />
    </mesh>
  );
}

interface FluidBackgroundProps {
