"use client";

import React, { useState, useRef, useEffect } from "react";
import { motion, useSpring, AnimatePresence } from "framer-motion";
import { cn } from "@/lib/utils";

export interface HoverImageItem {
  id: string;
  label: string;
  subtext?: string;
  image: string;
  href?: string;
}

export interface HoverImagePreviewProps extends React.HTMLAttributes<HTMLDivElement> {
  items: HoverImageItem[];
  imageWidth?: number;
  imageHeight?: number;
  springConfig?: { stiffness: number; damping: number; mass?: number };
  containerRef?: React.RefObject<HTMLElement | null>;
}

export function HoverImagePreview({
  items,
  imageWidth = 300,
  imageHeight = 400,
  springConfig = { stiffness: 150, damping: 20 },
  containerRef,
  className,
  ...props
}: HoverImagePreviewProps) {
  const [activeItem, setActiveItem] = useState<HoverImageItem | null>(null);
  const [isVisible, setIsVisible] = useState(false);
  const wrapperRef = useRef<HTMLDivElement>(null);

  // Smooth springs for x and y cursor position
  const cursorX = useSpring(-imageWidth, springConfig);
  const cursorY = useSpring(-imageHeight, springConfig);

  useEffect(() => {
    // If containerRef is provided, bind to it. Otherwise bind to the immediate wrapper
    const container = containerRef?.current || wrapperRef.current || window;

    const handleMouseMove = (e: MouseEvent | TouchEvent) => {
      let clientX, clientY;

      if ("touches" in e) {
        clientX = e.touches[0].clientX;
        clientY = e.touches[0].clientY;
      } else {
        clientX = (e as MouseEvent).clientX;
        clientY = (e as MouseEvent).clientY;
      }

      if (containerRef?.current || wrapperRef.current) {
        const targetContainer = (containerRef?.current || wrapperRef.current) as HTMLElement;
        const rect = targetContainer.getBoundingClientRect();

        // Offset by half image size to center the image on the cursor
        cursorX.set(clientX - rect.left - (imageWidth / 2));
        cursorY.set(clientY - rect.top - (imageHeight / 2));
      } else {
        cursorX.set(clientX - (imageWidth / 2));
        cursorY.set(clientY - (imageHeight / 2));
      }
    };

    container.addEventListener("mousemove", handleMouseMove as EventListener);
    container.addEventListener("touchmove", handleMouseMove as EventListener);

    return () => {
      container.removeEventListener("mousemove", handleMouseMove as EventListener);
      container.removeEventListener("touchmove", handleMouseMove as EventListener);
    };
  }, [cursorX, cursorY, imageWidth, imageHeight, containerRef]);

  return (
    <div 
      ref={wrapperRef}
      className={cn("relative w-full flex flex-col", className)}
      onMouseLeave={() => {
        setIsVisible(false);
        setActiveItem(null);
      }}
      {...props}
    >
      <ul className="w-full relative z-10 flex flex-col">
        {items.map((item) => (
          <li 
            key={item.id}
            onMouseEnter={() => {
              setActiveItem(item);
              setIsVisible(true);
            }}
            className="group relative"
          >
            {item.href ? (
              <a 
                href={item.href}
                className="flex items-center justify-between py-6 border-b border-white/5 cursor-pointer hover:bg-white/5 transition-colors px-4"
              >
                <span className="text-3xl md:text-5xl font-black text-white mix-blend-difference group-hover:pl-4 transition-all duration-300">
                  {item.label}
                </span>
                {item.subtext && (
                  <span className="text-sm font-medium text-zinc-400 group-hover:text-indigo-400 transition-colors">
                    {item.subtext}
                  </span>
                )}
              </a>
            ) : (
              <div className="flex items-center justify-between py-6 border-b border-white/5 cursor-pointer hover:bg-white/5 transition-colors px-4">
                <span className="text-3xl md:text-5xl font-black text-white mix-blend-difference group-hover:pl-4 transition-all duration-300">
                  {item.label}
                </span>
                {item.subtext && (
                  <span className="text-sm font-medium text-zinc-400 group-hover:text-indigo-400 transition-colors">
                    {item.subtext}
                  </span>
                )}
              </div>
            )}
          </li>
        ))}
      </ul>

      {/* Floating Preview Image */}
      <motion.div
        className={cn(
          "pointer-events-none rounded-xl overflow-hidden z-0 shadow-2xl",
          (containerRef || wrapperRef.current) ? "absolute" : "fixed"
        )}
        style={{
          width: imageWidth,
          height: imageHeight,
          x: cursorX,
          y: cursorY,
        }}
        initial={{ opacity: 0, scale: 0.8 }}
        animate={{ 
          opacity: isVisible && activeItem ? 1 : 0, 
          scale: isVisible && activeItem ? 1 : 0.8 
        }}
        transition={{ duration: 0.3, ease: "easeOut" }}
      >
        <AnimatePresence mode="wait">
          {activeItem && (
            <motion.img
              key={activeItem.id}
              src={activeItem.image}
              alt={activeItem.label}
              initial={{ opacity: 0, scale: 1.1 }}
              animate={{ opacity: 1, scale: 1 }}
              exit={{ opacity: 0, scale: 1.1 }}
              transition={{ duration: 0.4, ease: "easeOut" }}
              className="w-full h-full object-cover absolute inset-0"
            />
          )}
        </AnimatePresence>
      </motion.div>
    </div>
  );
}

"use client";

import React, { useRef, useState, useCallback, ReactNode } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { cn } from "@/lib/utils";

export type TrailEffect = "pop" | "rotate" | "stretch" | "glitch" | "wave";

interface ImageTrailProps extends React.HTMLAttributes<HTMLDivElement> {
  children: ReactNode;
  images: string[];
  /** Minimum distance (px) cursor must travel before spawning next image. Default: 50 */
  distanceThreshold?: number;
  /** Time (ms) before the trail image fades out. Default: 800 */
  fadeDuration?: number;
  /** Classes applied to each trail image element */
  imageClass?: string;
  /** Animation effect for the trail images. Default: "pop" */
  effect?: TrailEffect;
  /** Maximum number of trail images visible at once. Default: 10 */
  maxTrails?: number;
  /** Width of trail images in px. Default: 128 */
  imageWidth?: number;
  /** Height of trail images in px. Default: 160 */
  imageHeight?: number;
}

interface TrailItem {
  id: string;
  x: number;
  y: number;
  src: string;
  angle: number;
  velocity: number;
}

// ── Animation variants per effect ──────────────────────────────────────────
function getTrailVariants(effect: TrailEffect) {
  switch (effect) {
    case "pop":
      return {
        initial: { opacity: 0, scale: 0.3, x: "-50%", y: "-50%" },
        animate: { opacity: 1, scale: 1, x: "-50%", y: "-50%" },
        exit: { opacity: 0, scale: 0.6, x: "-50%", y: "-50%" },
        transition: { duration: 0.35, ease: [0.22, 1, 0.36, 1] },
      };
    case "rotate":
      return {
        initial: (item: TrailItem) => ({
          opacity: 0,
          scale: 0.4,
          rotate: item.angle * 0.5,
          x: "-50%",
          y: "-50%",
        }),
        animate: (item: TrailItem) => ({
          opacity: 1,
          scale: 1,
          rotate: (item.angle % 30) - 15,
          x: "-50%",
          y: "-50%",
        }),
        exit: (item: TrailItem) => ({
          opacity: 0,
          scale: 0.7,
          rotate: (item.angle % 30) - 15 + 10,
          x: "-50%",
          y: "-50%",
        }),
        transition: { duration: 0.4, ease: "easeOut" },
      };
    case "stretch":
      return {
        initial: (item: TrailItem) => ({
          opacity: 0,
          scaleX: 0.2,
          scaleY: 1.4,
          x: "-50%",
          y: "-50%",
        }),
        animate: { opacity: 1, scaleX: 1, scaleY: 1, x: "-50%", y: "-50%" },
        exit: { opacity: 0, scaleX: 0.3, scaleY: 1.2, x: "-50%", y: "-50%" },
        transition: { duration: 0.35, ease: [0.22, 1, 0.36, 1] },
      };
    case "glitch":
      return {
        initial: {
          opacity: 0,
          x: "-50%",
          y: "-50%",
          clipPath: "inset(0 0 100% 0)",
        },
        animate: {
          opacity: 1,
          x: "-50%",
          y: "-50%",
          clipPath: "inset(0 0 0% 0)",
        },
        exit: {
          opacity: 0,
          x: "-50%",
          y: "-50%",
          clipPath: "inset(100% 0 0 0)",
        },
        transition: { duration: 0.3, ease: "easeOut" },
      };
    case "wave":
      return {
        initial: { opacity: 0, scale: 0.5, y: "-30%", x: "-50%" },
        animate: { opacity: 1, scale: 1, y: "-50%", x: "-50%" },
        exit: { opacity: 0, scale: 0.8, y: "-70%", x: "-50%" },
        transition: { type: "spring", stiffness: 300, damping: 20 },
      };
    default:
      return {
        initial: { opacity: 0, scale: 0.5, x: "-50%", y: "-50%" },
        animate: { opacity: 1, scale: 1, x: "-50%", y: "-50%" },
        exit: { opacity: 0, scale: 0.8, x: "-50%", y: "-50%" },
        transition: { duration: 0.3, ease: "easeOut" },
      };
  }
}

export function HoverImageTrails({
  children,
  images = [],
  distanceThreshold = 50,
  fadeDuration = 800,
  className,
  imageClass,
  effect = "pop",
  maxTrails = 10,
  imageWidth = 128,
  imageHeight = 160,
  ...props
}: ImageTrailProps) {
  const containerRef = useRef<HTMLDivElement>(null);
  const [trails, setTrails] = useState<TrailItem[]>([]);
  const lastPosition = useRef<{ x: number; y: number } | null>(null);
  const imageIndex = useRef(0);
  const trailCounter = useRef(0);

  const handlePointerMove = useCallback(
    (e: React.PointerEvent<HTMLDivElement>) => {
      if (!containerRef.current || images.length === 0) return;

      const rect = containerRef.current.getBoundingClientRect();
      const x = e.clientX - rect.left;
      const y = e.clientY - rect.top;

      if (lastPosition.current) {
        const dx = x - lastPosition.current.x;
        const dy = y - lastPosition.current.y;
        const distance = Math.sqrt(dx * dx + dy * dy);

        if (distance < distanceThreshold) return;

        const angle = (Math.atan2(dy, dx) * 180) / Math.PI;
        const velocity = Math.min(distance / distanceThreshold, 3);

        lastPosition.current = { x, y };

        const newId = `trail_${trailCounter.current++}`;
        const newTrail: TrailItem = {
          id: newId,
          x,
          y,
          src: images[imageIndex.current % images.length],
          angle,
          velocity,
        };

        imageIndex.current += 1;

        setTrails((prev) => {
          const updated = [...prev, newTrail];
          // Cap active trails
          if (updated.length > maxTrails) {
            return updated.slice(updated.length - maxTrails);
          }
          return updated;
        });

        // Auto-remove after duration
        setTimeout(() => {
          setTrails((prev) => prev.filter((t) => t.id !== newId));
        }, fadeDuration);
      } else {
        lastPosition.current = { x, y };
      }
    },
    [distanceThreshold, fadeDuration, images, maxTrails]
  );

  const handlePointerLeave = useCallback(() => {
    lastPosition.current = null;
  }, []);

  const variants = getTrailVariants(effect);

  return (
    <div
      ref={containerRef}
      onPointerMove={handlePointerMove}
      onPointerLeave={handlePointerLeave}
      className={cn("relative w-full h-full overflow-hidden touch-none", className)}
      {...props}
    >
      {children}

      <div className="pointer-events-none absolute inset-0 z-50">
        <AnimatePresence>
          {trails.map((trail, i) => (
            <motion.img
              key={trail.id}
              src={trail.src}
              custom={trail}
              initial={
                typeof variants.initial === "function"
                  ? (variants.initial as Function)(trail)
                  : variants.initial
              }
              animate={
                typeof variants.animate === "function"
                  ? (variants.animate as Function)(trail)
                  : variants.animate
              }
              exit={
                typeof variants.exit === "function"
                  ? (variants.exit as Function)(trail)
                  : variants.exit
              }
              transition={variants.transition as any}
              className={cn(
                "absolute object-cover rounded-xl shadow-2xl",
                imageClass
              )}
              style={{
                left: trail.x,
                top: trail.y,
                width: imageWidth,
                height: imageHeight,
                zIndex: i,
              }}
              alt=""
              draggable={false}
            />
          ))}
        </AnimatePresence>
      </div>
    </div>
  );
}

