import React, { useState } from "react";
import { motion } from "framer-motion";
import { cn } from "@/lib/utils";

export interface AccordionImage {
  id: string;
  imageUrl: string;
  title: string;
  subtitle?: string;
}

export interface ImageAccordionProps {
  items: AccordionImage[];
  className?: string;
}

export function ImageAccordion({ items, className }: ImageAccordionProps) {
  // If no item is hovered, all items share equal space
  const [activeItem, setActiveItem] = useState<string | null>(null);

  return (
    <div 
      className={cn("w-full h-[500px] flex gap-2 overflow-hidden", className)}
      onMouseLeave={() => setActiveItem(null)}
    >
      {items.map((item) => {
        const isActive = activeItem === item.id;
        const isDefault = activeItem === null;

        return (
          <motion.div
            key={item.id}
            onMouseEnter={() => setActiveItem(item.id)}
            // We use standard CSS transition for flex-grow because it's hardware accelerated 
            // and performs exceptionally well for this specific use case
            className={cn(
              "relative h-full overflow-hidden rounded-3xl cursor-pointer transition-[flex] duration-700 ease-[cubic-bezier(0.76,0,0.24,1)]",
              isActive ? "flex-[5]" : isDefault ? "flex-1" : "flex-[0.5]"
            )}
          >
            {/* The background image */}
            <motion.img 
              src={item.imageUrl} 
              alt={item.title} 
              // Scale the image slightly to create a slow parallax effect as the container expands
              animate={{
                scale: isActive ? 1.05 : 1.2
              }}
              transition={{ duration: 0.7, ease: [0.76, 0, 0.24, 1] }}
              className="absolute inset-0 w-full h-full object-cover origin-center pointer-events-none"
            />

            {/* Dark overlay that fades when active */}
            <div 
              className={cn(
                "absolute inset-0 bg-black transition-opacity duration-700 pointer-events-none",
                isActive ? "opacity-20" : isDefault ? "opacity-40" : "opacity-70"
              )} 
            />

            {/* Gradient shadow for text readability */}
            <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-transparent to-transparent opacity-80 pointer-events-none" />

            {/* Text Content */}
            <motion.div 
              className="absolute bottom-0 left-0 w-full p-8 pointer-events-none flex flex-col justify-end"
              animate={{
                opacity: isActive ? 1 : 0,
                y: isActive ? 0 : 20
              }}
              transition={{ duration: 0.5, delay: isActive ? 0.2 : 0 }}
            >
              <h3 className="text-3xl md:text-5xl font-black text-white whitespace-nowrap mb-2">
                {item.title}
              </h3>
              {item.subtitle && (
                <p className="text-white/70 font-mono text-sm tracking-widest uppercase whitespace-nowrap">
                  {item.subtitle}
                </p>
              )}
            </motion.div>

            {/* Vertical Title (visible when NOT active) */}
            <motion.div
              className="absolute bottom-8 left-1/2 -translate-x-1/2 pointer-events-none origin-bottom-left -rotate-90 whitespace-nowrap"
              animate={{
                opacity: isActive ? 0 : 1,
                scale: isActive ? 0.8 : 1
              }}
              transition={{ duration: 0.3 }}
            >
              <span className="text-white font-bold tracking-widest uppercase text-sm drop-shadow-md">
                {item.title}
              </span>
            </motion.div>

          </motion.div>
        );
      })}
    </div>
  );
}

"use client";

import React, { useRef } from "react";
import { motion, useInView, Variants } from "framer-motion";
import { cn } from "@/lib/utils";

export interface ImageRevealProps extends React.HTMLAttributes<HTMLDivElement> {
  src: string;
  alt: string;
  direction?: "left" | "right" | "top" | "bottom" | "circle" | "curtain-h" | "curtain-v";
  delay?: number;
  duration?: number;
  imageClassName?: string;
  once?: boolean;
}

export function ImageReveal({
  src,
  alt,
  direction = "left",
  delay = 0,
  duration = 1.2,
  className,
  imageClassName,
  once = true,
  ...props
}: ImageRevealProps) {
  const ref = useRef<HTMLDivElement>(null);
  const isInView = useInView(ref, { once, amount: 0.3 });

  const getVariants = (): Variants => {
    switch (direction) {
      case "left":
        return {
          hidden: { clipPath: "inset(0 100% 0 0)" },
          visible: { clipPath: "inset(0 0% 0 0)" },
        };
      case "right":
        return {
          hidden: { clipPath: "inset(0 0 0 100%)" },
          visible: { clipPath: "inset(0 0 0 0%)" },
        };
      case "top":
        return {
          hidden: { clipPath: "inset(100% 0 0 0)" },
          visible: { clipPath: "inset(0% 0 0 0)" },
        };
      case "bottom":
        return {
          hidden: { clipPath: "inset(0 0 100% 0)" },
          visible: { clipPath: "inset(0 0 0% 0)" },
        };
      case "circle":
        return {
          hidden: { clipPath: "circle(0% at 50% 50%)" },
          visible: { clipPath: "circle(100% at 50% 50%)" },
        };
      case "curtain-h":
        return {
          hidden: { clipPath: "inset(0 50% 0 50%)" },
          visible: { clipPath: "inset(0 0% 0 0%)" },
        };
      case "curtain-v":
        return {
          hidden: { clipPath: "inset(50% 0 50% 0)" },
          visible: { clipPath: "inset(0% 0 0% 0)" },
        };
      default:
        return {
          hidden: { clipPath: "inset(0 100% 0 0)" },
          visible: { clipPath: "inset(0 0% 0 0)" },
        };
    }
  };

  return (
    <div
      ref={ref}
      className={cn("relative overflow-hidden w-full h-full", className)}
      {...props}
    >
      <motion.div
        initial="hidden"
        animate={isInView ? "visible" : "hidden"}
        variants={getVariants()}
        transition={{
          duration,
          delay,
          ease: [0.25, 1, 0.5, 1], // Custom easing for premium feel
        }}
        className="w-full h-full origin-center"
      >
        <motion.img
          src={src}
          alt={alt}
          className={cn("w-full h-full object-cover block", imageClassName)}
          // Optional: slight scale down as it reveals for an extra parallax-like feel
          initial={{ scale: 1.1 }}
          animate={isInView ? { scale: 1 } : { scale: 1.1 }}
          transition={{
            duration: duration * 1.2,
            delay,
            ease: [0.25, 1, 0.5, 1],
          }}
        />
      </motion.div>
    </div>
  );
}

"use client";

import { cn } from "@/lib/utils";
import React, { useEffect, useState } from "react";

export const InfiniteMovingCards = ({
  items,
  direction = "left",
  speed = "normal",
  pauseOnHover = true,
  className,
}: {
  items: {
    quote: string;
    name: string;
    title: string;
  }[];
  direction?: "left" | "right";
  speed?: "fast" | "normal" | "slow";
  pauseOnHover?: boolean;
  className?: string;
}) => {
  const containerRef = React.useRef<HTMLDivElement>(null);
  const scrollerRef = React.useRef<HTMLUListElement>(null);

  useEffect(() => {
    addAnimation();
  }, []);

  const [start, setStart] = useState(false);

  function addAnimation() {
    if (containerRef.current && scrollerRef.current) {
      const scrollerContent = Array.from(scrollerRef.current.children);

      scrollerContent.forEach((item) => {
        const duplicatedItem = item.cloneNode(true);
        if (scrollerRef.current) {
          scrollerRef.current.appendChild(duplicatedItem);
        }
      });

      getDirection();
      getSpeed();
      setStart(true);
    }
  }

  const getDirection = () => {
    if (containerRef.current) {
      if (direction === "left") {
        containerRef.current.style.setProperty(
          "--animation-direction",
          "forwards"
        );
      } else {
        containerRef.current.style.setProperty(
          "--animation-direction",
          "reverse"
        );
      }
    }
  };

  const getSpeed = () => {
    if (containerRef.current) {
      if (speed === "fast") {
        containerRef.current.style.setProperty("--animation-duration", "20s");
      } else if (speed === "normal") {
        containerRef.current.style.setProperty("--animation-duration", "40s");
      } else {
        containerRef.current.style.setProperty("--animation-duration", "80s");
      }
    }
  };

  return (
    <div
      ref={containerRef}
      className={cn(
        "@container scroller relative z-20 w-full overflow-hidden [mask-image:linear-gradient(to_right,transparent,white_20%,white_80%,transparent)]",
        className
      )}
    >
      <ul
        ref={scrollerRef}
        className={cn(
          "flex min-w-full shrink-0 gap-4 py-8 w-max flex-nowrap",
          start && "animate-scroll",
          pauseOnHover && "hover:[animation-play-state:paused]"
        )}
      >
        {items.map((item, idx) => (
          <li
            className="w-[280px] @md:w-[350px] @lg:w-[450px] max-w-full relative rounded-2xl border border-white/10 flex-shrink-0 px-5 py-4 @md:px-8 @md:py-6 bg-zinc-900/40 backdrop-blur-md shadow-xl"
            key={item.name + idx}
          >
            <blockquote>
              <div
                aria-hidden="true"
                className="user-select-none -z-1 pointer-events-none absolute -left-0.5 -top-0.5 h-[calc(100%_+_4px)] w-[calc(100%_+_4px)]"
              ></div>
              <span className="relative z-20 text-xs @md:text-sm leading-[1.6] text-gray-300 font-normal">
                "{item.quote}"
              </span>
              <div className="relative z-20 mt-4 @md:mt-6 flex flex-row items-center justify-between">
                <span className="flex flex-col gap-0.5 @md:gap-1">
                  <span className="text-xs @md:text-sm leading-[1.6] text-white font-semibold">
                    {item.name}
                  </span>
                  <span className="text-[10px] @md:text-xs leading-[1.6] text-gray-500 font-normal uppercase tracking-wider">
                    {item.title}
                  </span>
                </span>
              </div>
            </blockquote>
          </li>
        ))}
      </ul>
    </div>
  );
};

"use client";

import React, { useRef, useEffect } from "react";
import { useGesture } from "@use-gesture/react";
import { motion, useMotionValue, useSpring } from "framer-motion";
import { cn } from "@/lib/utils";
import { LocateFixed } from "lucide-react";

export interface InfiniteZoomCanvasProps extends React.HTMLAttributes<HTMLDivElement> {
  children: React.ReactNode;
  /** Initial scale of the canvas. Default 1. */
  initialScale?: number;
  /** Minimum zoom level. Default 0.1 */
  minScale?: number;
  /** Maximum zoom level. Default 5 */
  maxScale?: number;
  /** Whether to show the grid background. Default true. */
  showGrid?: boolean;
}

export function InfiniteZoomCanvas({
  children,
  className,
  initialScale = 1,
  minScale = 0.1,
  maxScale = 5,
  showGrid = true,
  ...props
}: InfiniteZoomCanvasProps) {
  const containerRef = useRef<HTMLDivElement>(null);

  // Motion values for instant updates
  const x = useMotionValue(0);
  const y = useMotionValue(0);
  const scale = useMotionValue(initialScale);

  // Spring physics for smooth panning/zooming after release
  const springX = useSpring(x, { damping: 30, stiffness: 300 });
  const springY = useSpring(y, { damping: 30, stiffness: 300 });
  const springScale = useSpring(scale, { damping: 30, stiffness: 300 });

  useGesture(
    {
      onDrag: ({ offset: [dx, dy] }) => {
        x.set(dx);
        y.set(dy);
      },
      onPinch: ({ origin: [ox, oy], offset: [s], memo }) => {
        // Enforce scale limits
        const newScale = Math.min(Math.max(s, minScale), maxScale);
        scale.set(newScale);
        return memo;
      },
      onWheel: ({ delta: [dx, dy], ctrlKey }) => {
        // If holding ctrl/cmd, zoom instead of pan (like Figma)
        if (ctrlKey) {
          const currentScale = scale.get();
          // Adjust zoom speed
          const zoomFactor = dy > 0 ? 0.9 : 1.1;
          const newScale = Math.min(Math.max(currentScale * zoomFactor, minScale), maxScale);
          scale.set(newScale);
        } else {
          // Standard pan
          x.set(x.get() - dx);
          y.set(y.get() - dy);
        }
      }
    },
    {
      target: containerRef,
      drag: { from: () => [x.get(), y.get()] },
      pinch: { from: () => [scale.get(), 0], scaleBounds: { min: minScale, max: maxScale } },
      eventOptions: { passive: false }
    }
  );

  // Prevent default zoom on trackpad pinch so we can handle it via onWheel
  useEffect(() => {
    const handler = (e: WheelEvent) => {
      if (e.ctrlKey) {
        e.preventDefault();
      }
    };
    const el = containerRef.current;
    if (el) {
      el.addEventListener('wheel', handler, { passive: false });
      return () => el.removeEventListener('wheel', handler);
    }
  }, []);

  const resetView = () => {
    // Reset back to center and initial scale using springs for a smooth transition
    x.set(0);
    y.set(0);
    scale.set(initialScale);
  };

  return (
    <div 
      ref={containerRef} 
      className={cn("relative w-full h-full overflow-hidden bg-[#0a0a0a] touch-none cursor-grab active:cursor-grabbing", className)}
      {...props}
    >
      {/* Dynamic Grid Background that scales with the view */}
      {showGrid && (
        <motion.div
          className="absolute inset-0 pointer-events-none"
          style={{
            backgroundSize: "40px 40px",
            backgroundImage: "linear-gradient(to right, rgba(255, 255, 255, 0.05) 1px, transparent 1px), linear-gradient(to bottom, rgba(255, 255, 255, 0.05) 1px, transparent 1px)",
            x: springX,
            y: springY,
            scale: springScale,
            transformOrigin: "0 0" // This ensures the grid scales correctly from top-left, but centering is complex. For a simple background, scaling from center is fine.
          }}
        />
      )}

      {/* The actual canvas content */}
      <motion.div
        className="absolute w-full h-full origin-center flex items-center justify-center"
        style={{
          x: springX,
          y: springY,
          scale: springScale,
        }}
      >
        {children}
      </motion.div>

      {/* Controls */}
      <div className="absolute bottom-6 right-6 flex flex-col gap-2 z-50">
        <button 
          onClick={resetView}
          className="p-3 rounded-full bg-zinc-900 border border-white/10 text-white hover:bg-zinc-800 transition-colors shadow-lg"
          title="Reset View"
        >
          <LocateFixed className="w-5 h-5" />
        </button>
      </div>

      {/* Instructions */}
      <div className="absolute top-6 left-6 pointer-events-none z-50">
        <div className="bg-black/50 backdrop-blur-md px-4 py-2 rounded-xl border border-white/10 flex flex-col gap-1">
          <p className="text-xs font-mono text-zinc-300"><span className="font-bold text-white">Pan:</span> Drag or Scroll</p>
          <p className="text-xs font-mono text-zinc-300"><span className="font-bold text-white">Zoom:</span> Pinch or Ctrl+Scroll</p>
        </div>
      </div>
    </div>
  );
}

"use client";

import React, { useState, useRef, useEffect } from "react";
import { cn } from "@/lib/utils";
import { Loader2 } from "lucide-react";

export interface Interactive360ViewerProps {
  images: string[];
  sensitivity?: number; // How many pixels to drag to change one frame. Default 10.
  className?: string;
}

export function Interactive360Viewer({
  images,
  sensitivity = 15,
  className,
}: Interactive360ViewerProps) {
  const [currentFrame, setCurrentFrame] = useState(0);
  const [isDragging, setIsDragging] = useState(false);
  const [isLoaded, setIsLoaded] = useState(false);
  const [loadingProgress, setLoadingProgress] = useState(0);

  const containerRef = useRef<HTMLDivElement>(null);
  const startXRef = useRef(0);
  const startFrameRef = useRef(0);

  // Preload all images to ensure 60fps scrubbing without flickering
  useEffect(() => {
    let loadedCount = 0;
    const total = images.length;

    if (total === 0) return;

    images.forEach((src) => {
      const img = new Image();
      img.src = src;
      img.onload = () => {
        loadedCount++;
        setLoadingProgress(Math.round((loadedCount / total) * 100));
        if (loadedCount === total) {
          setIsLoaded(true);
        }
      };
      img.onerror = () => {
        // Handle error gracefully so we don't block forever
        loadedCount++;
        if (loadedCount === total) setIsLoaded(true);
      };
    });
  }, [images]);

  const handlePointerDown = (e: React.PointerEvent) => {
    if (!isLoaded) return;
    setIsDragging(true);
    startXRef.current = e.clientX;
    startFrameRef.current = currentFrame;
    // Capture pointer so it tracks even if mouse leaves the container slightly
    e.currentTarget.setPointerCapture(e.pointerId);
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    if (!isDragging || !isLoaded) return;

    const deltaX = e.clientX - startXRef.current;

    // Calculate how many frames to advance based on sensitivity
    const frameDelta = Math.floor(deltaX / sensitivity);

    // Calculate new frame with wrap-around modulo logic
    const totalFrames = images.length;
    let newFrame = (startFrameRef.current + frameDelta) % totalFrames;
    if (newFrame < 0) {
      newFrame += totalFrames;
    }

    setCurrentFrame(newFrame);
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    setIsDragging(false);
    e.currentTarget.releasePointerCapture(e.pointerId);
  };

  if (!images || images.length === 0) return null;

  return (
    <div 
      ref={containerRef}
      className={cn(
        "relative w-full aspect-square md:aspect-video select-none touch-none",
        isDragging ? "cursor-grabbing" : "cursor-grab",
        className
      )}
      onPointerDown={handlePointerDown}
      onPointerMove={handlePointerMove}
      onPointerUp={handlePointerUp}
      onPointerCancel={handlePointerUp}
    >
      {!isLoaded && (
        <div className="absolute inset-0 flex flex-col items-center justify-center bg-zinc-900/50 backdrop-blur-md rounded-xl z-20">
          <Loader2 className="w-8 h-8 text-white animate-spin mb-4" />
          <p className="text-sm font-medium text-zinc-300">Loading 3D Model... {loadingProgress}%</p>
        </div>
      )}

      {/* Render the current image */}
      <img
        src={images[currentFrame]}
        alt={`360 view frame ${currentFrame}`}
        className="w-full h-full object-contain pointer-events-none"
        draggable={false}
      />

      {/* Interaction Hint Overlay */}
      {isLoaded && !isDragging && (
        <div className="absolute bottom-4 left-1/2 -translate-x-1/2 bg-black/60 backdrop-blur-md text-white text-xs font-medium px-4 py-2 rounded-full pointer-events-none animate-pulse">
          Drag to Rotate
        </div>
      )}
    </div>
  );
}

