"use client";

import React, { useRef, useMemo, useEffect } from "react";
import { Canvas, useFrame, useThree } from "@react-three/fiber";
import * as THREE from "three";
import { cn } from "@/lib/utils";

const vertexShader = `
varying vec2 vUv;
void main() {
  vUv = uv;
  gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
}
`;

const fragmentShader = `
uniform float uTime;
uniform vec2 uResolution;
uniform vec2 uMouse;
uniform vec2 uMouseVelocity;
uniform vec3 uColor1;
uniform vec3 uColor2;

varying vec2 vUv;

// Simplex 2D noise
vec3 permute(vec3 x) { return mod(((x*34.0)+1.0)*x, 289.0); }
float snoise(vec2 v){
  const vec4 C = vec4(0.211324865405187, 0.366025403784439,
           -0.577350269189626, 0.024390243902439);
  vec2 i  = floor(v + dot(v, C.yy) );
  vec2 x0 = v -   i + dot(i, C.xx);
  vec2 i1;
  i1 = (x0.x > x0.y) ? vec2(1.0, 0.0) : vec2(0.0, 1.0);
  vec4 x12 = x0.xyxy + C.xxzz;
  x12.xy -= i1;
  i = mod(i, 289.0);
  vec3 p = permute( permute( i.y + vec3(0.0, i1.y, 1.0 ))
  + i.x + vec3(0.0, i1.x, 1.0 ));
  vec3 m = max(0.5 - vec3(dot(x0,x0), dot(x12.xy,x12.xy), dot(x12.zw,x12.zw)), 0.0);
  m = m*m ;
  m = m*m ;
  vec3 x = 2.0 * fract(p * C.www) - 1.0;
  vec3 h = abs(x) - 0.5;
  vec3 ox = floor(x + 0.5);
  vec3 a0 = x - ox;
  m *= 1.79284291400159 - 0.85373472095314 * ( a0*a0 + h*h );
  vec3 g;
  g.x  = a0.x  * x0.x  + h.x  * x0.y;
  g.yz = a0.yz * x12.xz + h.yz * x12.yw;
  return 130.0 * dot(m, g);
}

void main() {
  vec2 uv = vUv;

  // Calculate distance from mouse
  float dist = distance(uv, uMouse);

  // Base noise for fluid movement
  float noise1 = snoise(uv * 3.0 + uTime * 0.1);
  float noise2 = snoise(uv * 5.0 - uTime * 0.15 + noise1);

  // Velocity influence (trails)
  float velocityMag = length(uMouseVelocity);
  float influence = smoothstep(0.5, 0.0, dist) * min(velocityMag * 100.0, 1.0);

  // Distort UVs based on noise and mouse influence
  vec2 distortedUv = uv + vec2(snoise(uv + uTime), snoise(uv - uTime)) * 0.1;
  distortedUv += normalize(uv - uMouse) * influence * 0.1;

  // Create color blobs
  float blob1 = snoise(distortedUv * 2.0 + uTime * 0.2);
  float blob2 = snoise(distortedUv * 4.0 - uTime * 0.3);

  // Mix colors based on blobs and influence
  vec3 finalColor = mix(uColor1, uColor2, blob1 * 0.5 + 0.5);
  finalColor = mix(finalColor, vec3(1.0), influence * 0.5); // Add white flash on fast movement

  // Vignette to darken edges
  float vignette = 1.0 - smoothstep(0.2, 1.5, length(uv - 0.5));

  gl_FragColor = vec4(finalColor * vignette, 1.0);
}
`;

function FluidScene({
  color1,
  color2,
}: {
  color1: string;
  color2: string;
}) {
  const { viewport, size } = useThree();
  const materialRef = useRef<THREE.ShaderMaterial>(null);

  const mouse = useRef(new THREE.Vector2(0.5, 0.5));
  const targetMouse = useRef(new THREE.Vector2(0.5, 0.5));
  const velocity = useRef(new THREE.Vector2(0, 0));

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      targetMouse.current.x = e.clientX / window.innerWidth;
      targetMouse.current.y = 1.0 - (e.clientY / window.innerHeight);
    };
    window.addEventListener("mousemove", handleMouseMove);
    return () => window.removeEventListener("mousemove", handleMouseMove);
  }, []);

  const uniforms = useMemo(
    () => ({
      uTime: { value: 0 },
      uResolution: { value: new THREE.Vector2(size.width, size.height) },
      uMouse: { value: new THREE.Vector2(0.5, 0.5) },
      uMouseVelocity: { value: new THREE.Vector2(0, 0) },
      uColor1: { value: new THREE.Color(color1) },
      uColor2: { value: new THREE.Color(color2) },
    }),
    [color1, color2, size]
  );

  useFrame((state, delta) => {
    if (materialRef.current) {
      // Calculate smooth velocity
      const lastMouse = mouse.current.clone();
      mouse.current.lerp(targetMouse.current, 0.1);

      const currentVelocity = new THREE.Vector2().subVectors(mouse.current, lastMouse);
      velocity.current.lerp(currentVelocity, 0.1);

      // Decay velocity when not moving
      velocity.current.multiplyScalar(0.95);

      materialRef.current.uniforms.uTime.value += delta;
      materialRef.current.uniforms.uResolution.value.set(size.width, size.height);
      materialRef.current.uniforms.uMouse.value.copy(mouse.current);
      materialRef.current.uniforms.uMouseVelocity.value.copy(velocity.current);
    }
  });

  return (
    <mesh>
      <planeGeometry args={[viewport.width, viewport.height]} />
      <shaderMaterial
        ref={materialRef}
        vertexShader={vertexShader}
        fragmentShader={fragmentShader}
        uniforms={uniforms}
      />
    </mesh>
  );
}

export interface InteractiveFluidProps {
  color1?: string;
  color2?: string;
  className?: string;
}

export function InteractiveFluid({
  color1 = "#1e1b4b", // Deep indigo
  color2 = "#38bdf8", // Sky blue
  className,
}: InteractiveFluidProps) {
  return (
    <div className={cn("absolute inset-0 z-0 overflow-hidden pointer-events-none", className)}>
      <Canvas camera={{ position: [0, 0, 1] }}>
        <FluidScene color1={color1} color2={color2} />
      </Canvas>
    </div>
  );
}

"use client";

import React, { useRef, useMemo } from "react";
import { Canvas, useFrame } from "@react-three/fiber";
import * as THREE from "three";
import { cn } from "@/lib/utils";

const vertexShader = `
uniform float uTime;
uniform vec3 uMouse;
attribute float size;

void main() {
  vec3 pos = position;

  // Interactive repulsion from mouse
  float dist = distance(pos, uMouse);
  if(dist < 3.0) {
    vec3 dir = normalize(pos - uMouse);
    // Exponential falloff for smooth repulsion
    pos += dir * (3.0 - dist) * 0.8;
  }

  // Ambient floating motion
  pos.y += sin(uTime * 0.5 + pos.x * 2.0) * 0.2;
  pos.x += cos(uTime * 0.5 + pos.y * 2.0) * 0.2;

  vec4 mvPosition = modelViewMatrix * vec4(pos, 1.0);

  // Perspective scaling for particle sizes
  gl_PointSize = size * (400.0 / -mvPosition.z);
  gl_Position = projectionMatrix * mvPosition;
}
`;

const fragmentShader = `
void main() {
  // Make particles perfectly circular
  vec2 xy = gl_PointCoord.xy - vec2(0.5);
  float ll = length(xy);
  if(ll > 0.5) discard;

  // Radial gradient for a soft, glowing orb effect
  float alpha = (0.5 - ll) * 2.0;

  // Cyberpunk cyan glow
  gl_FragColor = vec4(0.0, 1.0, 0.8, alpha);
}
`;

function Swarm({ count = 15000 }: { count?: number }) {
  const pointsRef = useRef<THREE.Points>(null);
  const materialRef = useRef<THREE.ShaderMaterial>(null);

  const [positions, sizes] = useMemo(() => {
    const positions = new Float32Array(count * 3);
    const sizes = new Float32Array(count);

    // Generate particles in a hollow sphere formation
    for (let i = 0; i < count; i++) {
      const radius = 6 + Math.random() * 2; // Radius between 6 and 8
      const theta = Math.random() * 2 * Math.PI;
      const phi = Math.acos((Math.random() * 2) - 1);

      positions[i * 3] = radius * Math.sin(phi) * Math.cos(theta);
      positions[i * 3 + 1] = radius * Math.sin(phi) * Math.sin(theta);
      positions[i * 3 + 2] = radius * Math.cos(phi);

      sizes[i] = Math.random() * 1.5; // Random initial sizes
    }

    return [positions, sizes];
  }, [count]);

  const uniforms = useMemo(() => ({
    uTime: { value: 0 },
    uMouse: { value: new THREE.Vector3(999, 999, 999) }
  }), []);

  useFrame((state) => {
    if (materialRef.current && pointsRef.current) {
      materialRef.current.uniforms.uTime.value = state.clock.elapsedTime;

      // Map screen mouse coordinates to 3D world space
      const { mouse, camera } = state;
      const vector = new THREE.Vector3(mouse.x, mouse.y, 0.5);
      vector.unproject(camera);
      const dir = vector.sub(camera.position).normalize();
      const distance = -camera.position.z / dir.z;
      const pos = camera.position.clone().add(dir.multiplyScalar(distance));

      // Smoothly interpolate the repulsion center towards the mouse
      materialRef.current.uniforms.uMouse.value.lerp(pos, 0.1);

      // Slowly rotate the entire swarm
      pointsRef.current.rotation.y = state.clock.elapsedTime * 0.1;
      pointsRef.current.rotation.x = state.clock.elapsedTime * 0.05;
    }
  });

  return (
    <points ref={pointsRef}>
      <bufferGeometry>
        <bufferAttribute attach="attributes-position" args={[positions, 3]} count={count} />
        <bufferAttribute attach="attributes-size" args={[sizes, 1]} count={count} />
      </bufferGeometry>
      <shaderMaterial
        ref={materialRef}
        vertexShader={vertexShader}
        fragmentShader={fragmentShader}
        uniforms={uniforms}
        transparent
        depthWrite={false}
        blending={THREE.AdditiveBlending}
      />
    </points>
  );
}

export interface InteractiveParticleSwarmProps {
  className?: string;
  particleCount?: number;
}

export function InteractiveParticleSwarm({ className, particleCount = 15000 }: InteractiveParticleSwarmProps) {
  return (
    <div className={cn("relative w-full h-[600px] bg-black overflow-hidden", className)}>
      {/* Fallback text while WebGL context initializes */}
      <div className="absolute inset-0 flex items-center justify-center pointer-events-none z-0">
        <span className="text-cyan-900/30 font-mono text-xs tracking-[1em]">INITIALIZING_SWARM</span>
      </div>
      <Canvas camera={{ position: [0, 0, 15], fov: 60 }} className="z-10">
        <Swarm count={particleCount} />
      </Canvas>
    </div>
  );
}

"use client";

import React from "react";
import { motion, Variants, HTMLMotionProps } from "framer-motion";
import { cn } from "@/lib/utils";

export type KineticLoaderVariant = "flip" | "bounce" | "wave" | "pulse";

interface KineticLoaderProps extends HTMLMotionProps<"div"> {
  /** Text to display while loading. Default: "LOADING..." */
  text?: string;
  size?: "sm" | "md" | "lg";
  /** Animation speed multiplier. Default: 1 */
  speed?: number;
  /** Animation variant. Default: "flip" */
  variant?: KineticLoaderVariant;
  color?: string;
}

const getVariants = (variant: KineticLoaderVariant, speed: number): { container: Variants; child: Variants } => {
  const baseDuration = 0.8 / speed;
  const staggerDelay = 0.1 / speed;

  switch (variant) {
    case "bounce":
      return {
        container: {
          hidden: {},
          visible: {
            transition: { staggerChildren: staggerDelay },
          },
        },
        child: {
          hidden: { y: "0%" },
          visible: {
            y: ["0%", "-40%", "0%"],
            transition: { 
              duration: baseDuration, 
              repeat: Infinity, 
              ease: "easeInOut" 
            },
          },
        },
      };
    case "wave":
      return {
        container: {
          hidden: {},
          visible: {
            transition: { staggerChildren: staggerDelay },
          },
        },
        child: {
          hidden: { y: "0%", rotateZ: 0 },
          visible: {
            y: ["0%", "-20%", "0%"],
            rotateZ: [0, 10, -10, 0],
            transition: { 
              duration: baseDuration * 1.5, 
              repeat: Infinity, 
              ease: "easeInOut" 
            },
          },
        },
      };
    case "pulse":
      return {
        container: {
          hidden: {},
          visible: {
            transition: { staggerChildren: staggerDelay },
          },
        },
        child: {
          hidden: { opacity: 0.2, scale: 0.8 },
          visible: {
            opacity: [0.2, 1, 0.2],
            scale: [0.8, 1.1, 0.8],
            transition: { 
              duration: baseDuration, 
              repeat: Infinity, 
              ease: "easeInOut" 
            },
          },
        },
      };
    case "flip":
    default:
      return {
        container: {
          hidden: {},
          visible: {
            transition: { staggerChildren: staggerDelay },
          },
        },
        child: {
          hidden: { rotateX: -90, opacity: 0, y: 10 },
          visible: {
            rotateX: 0,
            opacity: 1,
            y: 0,
            transition: {
              duration: baseDuration,
              repeat: Infinity,
              repeatType: "reverse",
              repeatDelay: 0.5 / speed,
              ease: "easeOut",
            },
          },
        },
      };
  }
};

export function KineticLoader({
  text = "LOADING...",
  size = "md",
  speed = 1,
  variant = "flip",
  color,
  className,
  ...props
}: KineticLoaderProps) {
  const sizeClasses = {
    sm: "text-lg",
    md: "text-3xl",
    lg: "text-6xl",
  };

  const hasColorText = className?.includes("text-");
  const { container, child } = getVariants(variant, speed);

  return (
    <motion.div
      variants={container}
      initial="hidden"
      animate="visible"
      className={cn(
        "flex items-center justify-center font-bold tracking-widest perspective-1000",
        !hasColorText && !color && "text-indigo-500",
        sizeClasses[size],
        className
      )}
      style={{
        color: color || undefined,
        ...props.style,
      }}
      {...props}
    >
      {text.split("").map((char, index) => (
        <motion.span
          key={index}
          variants={child}
          className="inline-block origin-bottom transform-style-3d mr-[0.1em]"
        >
          {char === " " ? "\u00A0" : char}
        </motion.span>
      ))}
    </motion.div>
  );
}

"use client";

import React, { useRef, useEffect, useState } from "react";
import { motion, useMotionValue, useSpring, useTransform, AnimatePresence } from "framer-motion";
import { cn } from "@/lib/utils";

export type KineticVariant = "elastic" | "wave" | "jump" | "float" | "decode";

interface KineticTypographyProps extends React.HTMLAttributes<HTMLDivElement> {
  /** The text string to animate */
  text: string;
  className?: string;
  /** Intensity of the elastic distortion. Default: 50 */
  intensity?: number;
  /** Animation variant. Default: "elastic" */
  variant?: KineticVariant;
}

// ── Elastic (3D Mouse Distortion) ───────────────────────────────────────────
function ElasticLetter({ char, index, total, mouseX, mouseY, intensity }: any) {
  const normalizedIndex = (index / total) * 2 - 1; 

  const x = useTransform(mouseX, [-500, 500], [-intensity * normalizedIndex, intensity * normalizedIndex]);
  const y = useTransform(mouseY, [-500, 500], [-intensity, intensity]);
  const rotateX = useTransform(mouseY, [-500, 500], [45, -45]);
  const rotateY = useTransform(mouseX, [-500, 500], [-45, 45]);

  const scale = useTransform(
    mouseX, 
    [-500, 0, 500], 
    [1, Math.abs(normalizedIndex) < 0.2 ? 1.5 : 1, 1]
  );

  return (
    <motion.span
      style={{
        display: "inline-block",
        whiteSpace: char === " " ? "pre" : "normal",
        x, y, rotateX, rotateY, scale,
      }}
    >
      {char}
    </motion.span>
  );
}

// ── Jump (Hover Interaction) ────────────────────────────────────────────────
function JumpLetter({ char }: { char: string }) {
  return (
    <motion.span
      style={{ display: "inline-block", whiteSpace: char === " " ? "pre" : "normal" }}
      whileHover={{
        y: -20,
        scale: 1.1,
        color: "#818cf8", // indigo-400
        transition: { type: "spring", stiffness: 400, damping: 10 }
      }}
    >
      {char}
    </motion.span>
  );
}

// ── Wave (Continuous Sine Wave) ─────────────────────────────────────────────
function WaveLetter({ char, index }: { char: string; index: number }) {
  return (
    <motion.span
      style={{ display: "inline-block", whiteSpace: char === " " ? "pre" : "normal" }}
      animate={{
        y: ["0%", "-25%", "0%"],
        rotateZ: [0, 5, 0, -5, 0],
      }}
      transition={{
        duration: 2,
        repeat: Infinity,
        ease: "easeInOut",
        delay: index * 0.1,
      }}
    >
      {char}
    </motion.span>
  );
}

// ── Float (Random Floating) ─────────────────────────────────────────────────
function FloatLetter({ char, index }: { char: string; index: number }) {
  return (
    <motion.span
      style={{ display: "inline-block", whiteSpace: char === " " ? "pre" : "normal" }}
      animate={{
        y: [0, -10 + Math.random() * -10, 0],
        x: [0, -5 + Math.random() * 10, 0],
        rotate: [0, -3 + Math.random() * 6, 0],
      }}
      transition={{
        duration: 3 + Math.random() * 2,
        repeat: Infinity,
        ease: "easeInOut",
        delay: index * 0.2,
      }}
    >
      {char}
    </motion.span>
  );
}

// ── Decode (Hacker Text on Mount/Hover) ─────────────────────────────────────
const ALPHABET = "ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789!@#$%^&*";
function DecodeLetter({ char, index }: { char: string; index: number }) {
  const [displayChar, setDisplayChar] = useState(char);
  const [isHovered, setIsHovered] = useState(false);

  useEffect(() => {
    if (char === " ") return;

    let iterations = 0;
    const maxIterations = 10 + index * 2;

    const interval = setInterval(() => {
      if (iterations >= maxIterations) {
        clearInterval(interval);
        setDisplayChar(char);
      } else {
        setDisplayChar(ALPHABET[Math.floor(Math.random() * ALPHABET.length)]);
        iterations++;
      }
    }, 40);

    return () => clearInterval(interval);
  }, [char, index, isHovered]);

  return (
    <motion.span
      onMouseEnter={() => setIsHovered(!isHovered)}
      style={{ display: "inline-block", whiteSpace: char === " " ? "pre" : "normal" }}
      className={displayChar !== char ? "text-cyan-400" : ""}
    >
      {displayChar}
    </motion.span>
  );
}


export function KineticTypography({
  text,
  className,
  intensity = 50,
  variant = "elastic",
  ...props
}: KineticTypographyProps) {
  const containerRef = useRef<HTMLDivElement>(null);
  const mouseX = useMotionValue(0);
  const mouseY = useMotionValue(0);

  const smoothMouseX = useSpring(mouseX, { stiffness: 100, damping: 20 });
  const smoothMouseY = useSpring(mouseY, { stiffness: 100, damping: 20 });

  useEffect(() => {
    if (variant !== "elastic") return;

    const handleMouseMove = (e: MouseEvent) => {
      if (!containerRef.current) return;
      const rect = containerRef.current.getBoundingClientRect();
      const x = e.clientX - rect.left - rect.width / 2;
      const y = e.clientY - rect.top - rect.height / 2;
      mouseX.set(x);
      mouseY.set(y);
    };

    const handleMouseLeave = () => {
      mouseX.set(0);
      mouseY.set(0);
    };

    const element = containerRef.current;
    if (element) {
      element.addEventListener("mousemove", handleMouseMove);
      element.addEventListener("mouseleave", handleMouseLeave);
    }

    return () => {
      if (element) {
        element.removeEventListener("mousemove", handleMouseMove);
        element.removeEventListener("mouseleave", handleMouseLeave);
      }
    };
  }, [mouseX, mouseY, variant]);

  const renderLetter = (char: string, index: number) => {
    switch (variant) {
      case "wave":
        return <WaveLetter key={index} char={char} index={index} />;
      case "jump":
        return <JumpLetter key={index} char={char} />;
      case "float":
        return <FloatLetter key={index} char={char} index={index} />;
      case "decode":
        return <DecodeLetter key={index} char={char} index={index} />;
      case "elastic":
      default:
        return (
          <ElasticLetter 
            key={index} 
            char={char} 
            index={index} 
            total={text.length} 
            mouseX={smoothMouseX} 
            mouseY={smoothMouseY}
            intensity={intensity}
          />
        );
    }
  };

  return (
    <div
      ref={containerRef}
      className={cn("relative flex items-center justify-center p-8 perspective-1000", className)}
      {...props}
    >
      <div className="flex flex-wrap justify-center text-5xl md:text-7xl font-black uppercase tracking-tighter cursor-default">
        {text.split("").map((char, index) => renderLetter(char, index))}
      </div>
    </div>
  );
}

