                  onClick={() => setSelectedId(null)}
                  className="absolute top-6 right-6 p-3 bg-white/10 hover:bg-white/20 rounded-full text-white backdrop-blur transition-all active:scale-95"
                >
                  <X className="w-5 h-5" />
                </motion.button>
              </div>
            </motion.div>
          </div>
        )}
      </AnimatePresence>
    </div>
  );
}

"use client";

import React from "react";
import { motion, HTMLMotionProps, Variants } from "framer-motion";
import { cn } from "@/lib/utils";

// ── Fade In ─────────────────────────────────────────────────────────────────
interface FadeInProps extends HTMLMotionProps<"div"> {
  delay?: number;
  duration?: number;
}
export function FadeIn({ children, className, delay = 0, duration = 0.5, ...props }: FadeInProps) {
  return (
    <motion.div
      initial={{ opacity: 0 }}
      whileInView={{ opacity: 1 }}
      viewport={{ once: true, margin: "-50px" }}
      transition={{ duration, delay, ease: "easeOut" }}
      className={cn(className)}
      {...props}
    >
      {children}
    </motion.div>
  );
}

// ── Slide Up ────────────────────────────────────────────────────────────────
interface SlideUpProps extends HTMLMotionProps<"div"> {
  delay?: number;
  duration?: number;
  yOffset?: number;
}
export function SlideUp({ children, className, delay = 0, duration = 0.6, yOffset = 40, ...props }: SlideUpProps) {
  return (
    <motion.div
      initial={{ opacity: 0, y: yOffset }}
      whileInView={{ opacity: 1, y: 0 }}
      viewport={{ once: true, margin: "-50px" }}
      transition={{ duration, delay, ease: [0.21, 0.47, 0.32, 0.98] }}
      className={cn(className)}
      {...props}
    >
      {children}
    </motion.div>
  );
}

// ── Scale In ────────────────────────────────────────────────────────────────
interface ScaleInProps extends HTMLMotionProps<"div"> {
  delay?: number;
  duration?: number;
  initialScale?: number;
}
export function ScaleIn({ children, className, delay = 0, duration = 0.5, initialScale = 0.8, ...props }: ScaleInProps) {
  return (
    <motion.div
      initial={{ opacity: 0, scale: initialScale }}
      whileInView={{ opacity: 1, scale: 1 }}
      viewport={{ once: true, margin: "-50px" }}
      transition={{ duration, delay, ease: [0.175, 0.885, 0.32, 1.275] }} // BackOut ease
      className={cn(className)}
      {...props}
    >
      {children}
    </motion.div>
  );
}

// ── Blur In ─────────────────────────────────────────────────────────────────
interface BlurInProps extends HTMLMotionProps<"div"> {
  delay?: number;
  duration?: number;
  initialBlur?: string;
}
export function BlurIn({ children, className, delay = 0, duration = 0.8, initialBlur = "10px", ...props }: BlurInProps) {
  return (
    <motion.div
      initial={{ opacity: 0, filter: `blur(${initialBlur})` }}
      whileInView={{ opacity: 1, filter: "blur(0px)" }}
      viewport={{ once: true, margin: "-50px" }}
      transition={{ duration, delay, ease: "easeOut" }}
      className={cn(className)}
      {...props}
    >
      {children}
    </motion.div>
  );
}

// ── Rotate In ───────────────────────────────────────────────────────────────
interface RotateInProps extends HTMLMotionProps<"div"> {
  delay?: number;
  duration?: number;
  initialRotation?: number;
}
export function RotateIn({ children, className, delay = 0, duration = 0.6, initialRotation = -15, ...props }: RotateInProps) {
  return (
    <motion.div
      initial={{ opacity: 0, rotate: initialRotation, scale: 0.95 }}
      whileInView={{ opacity: 1, rotate: 0, scale: 1 }}
      viewport={{ once: true, margin: "-50px" }}
      transition={{ duration, delay, ease: [0.21, 0.47, 0.32, 0.98] }}
      className={cn(className)}
      {...props}
    >
      {children}
    </motion.div>
  );
}


// ── Stagger Container & Item ────────────────────────────────────────────────
interface StaggerContainerProps extends HTMLMotionProps<"div"> {
  delayChildren?: number;
  staggerChildren?: number;
}

export function StaggerContainer({
  children,
  className,
  delayChildren = 0.1,
  staggerChildren = 0.1,
  ...props
}: StaggerContainerProps) {
  const variants: Variants = {
    hidden: {},
    visible: {
      transition: {
        delayChildren,
        staggerChildren,
      },
    },
  };

  return (
    <motion.div
      variants={variants}
      initial="hidden"
      whileInView="visible"
      viewport={{ once: true, margin: "-50px" }}
      className={cn(className)}
      {...props}
    >
      {children}
    </motion.div>
  );
}

interface StaggerItemProps extends HTMLMotionProps<"div"> {
  yOffset?: number;
}

export function StaggerItem({ children, className, yOffset = 30, ...props }: StaggerItemProps) {
  const itemVariants: Variants = {
    hidden: { opacity: 0, y: yOffset },
    visible: {
      opacity: 1,
      y: 0,
      transition: { duration: 0.5, ease: [0.21, 0.47, 0.32, 0.98] },
    },
  };

  return (
    <motion.div variants={itemVariants} className={cn(className)} {...props}>
      {children}
    </motion.div>
  );
}

"use client";

import React, { useRef, useEffect } from "react";
import {
  motion,
  useMotionValue,
  useSpring,
  useTransform,
  useAnimationFrame,
  wrap,
} from "framer-motion";
import { cn } from "@/lib/utils";

interface MouseMarqueeProps {
  children: React.ReactNode;
  maxSpeed?: number;
  className?: string;
  itemClassName?: string;
  repeatCount?: number;
}

export function MouseMarquee({
  children,
  maxSpeed = 5,
  className,
  itemClassName,
  repeatCount = 4,
}: MouseMarqueeProps) {
  const containerRef = useRef<HTMLDivElement>(null);
  const baseX = useMotionValue(0);

  // The raw speed calculated from mouse position (-1 to 1)
  const normalizedSpeed = useMotionValue(0);

  // Smooth out the speed changes
  const smoothSpeed = useSpring(normalizedSpeed, {
    damping: 50,
    stiffness: 400,
  });

  // Calculate X transform wrapped between 0% and -50% (assuming 2 full sets)
  // For safety with higher repeat counts, we wrap based on -100 / (repeatCount/2)
  const wrapLimit = -100 / (repeatCount / 2);
  const x = useTransform(baseX, (v) => `${wrap(0, wrapLimit, v)}%`);

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (!containerRef.current) return;

      const rect = containerRef.current.getBoundingClientRect();

      // Check if mouse is hovering over the container (optional, we'll track globally for now)
      // For global tracking, we measure distance from center of screen
      const windowCenterX = window.innerWidth / 2;
      const mouseX = e.clientX;

      // Normalize between -1 (far left) and 1 (far right)
      const normalized = (mouseX - windowCenterX) / windowCenterX;
      normalizedSpeed.set(normalized);
    };

    const handleMouseLeave = () => {
      // Gently return to 0 speed when mouse leaves window
      normalizedSpeed.set(0);
    };

    window.addEventListener("mousemove", handleMouseMove);
    document.addEventListener("mouseleave", handleMouseLeave);

    return () => {
      window.removeEventListener("mousemove", handleMouseMove);
      document.removeEventListener("mouseleave", handleMouseLeave);
    };
  }, [normalizedSpeed]);

  useAnimationFrame((t, delta) => {
    // Current smoothed speed factor (-1 to 1)
    const currentSpeedFactor = smoothSpeed.get();

    // Convert to actual movement (delta normalized * maxSpeed)
    // If speed is 0, it stops.
    const moveBy = currentSpeedFactor * maxSpeed * (delta / 16); // Normalize delta to roughly 60fps

    baseX.set(baseX.get() - moveBy);
  });

  return (
    <div 
      ref={containerRef}
      className={cn("overflow-hidden whitespace-nowrap flex m-0 relative", className)}
    >
      <motion.div
        className="flex whitespace-nowrap"
        style={{ x }}
      >
        {Array.from({ length: repeatCount }).map((_, i) => (
          <div key={i} className={cn("flex shrink-0 items-center", itemClassName)}>
            {children}
          </div>
        ))}
      </motion.div>
    </div>
  );
}

"use client";

import React, { useEffect, useState, useRef } from "react";
import { motion, useSpring } from "framer-motion";
import { MousePointer2 } from "lucide-react";
import { cn } from "@/lib/utils";

export interface CursorData {
  id: string;
  x: number;
  y: number;
  color: string;
  name: string;
}

export interface MultiplayerCursorEcosystemProps {
  children: React.ReactNode;
  className?: string;
  /** Live cursor data. If empty, the component will spawn AI Ghost cursors. */
  cursors?: CursorData[];
}

// Separate component for a single cursor to manage its own spring state
function RemoteCursor({ cursor }: { cursor: CursorData }) {
  // Use springs for ultra-smooth interpolation (like Figma)
  const springX = useSpring(cursor.x, { stiffness: 300, damping: 30, mass: 0.8 });
  const springY = useSpring(cursor.y, { stiffness: 300, damping: 30, mass: 0.8 });

  useEffect(() => {
    springX.set(cursor.x);
    springY.set(cursor.y);
  }, [cursor.x, cursor.y, springX, springY]);

  return (
    <motion.div
      className="absolute top-0 left-0 pointer-events-none z-50 flex flex-col items-start"
      style={{
        x: springX,
        y: springY,
      }}
    >
      <MousePointer2 
        className="w-5 h-5 drop-shadow-md" 
        style={{ color: cursor.color, fill: cursor.color }}
      />
      <motion.div
        initial={{ opacity: 0, scale: 0.8 }}
        animate={{ opacity: 1, scale: 1 }}
        transition={{ delay: 0.1 }}
        className="ml-4 mt-1 px-2 py-1 rounded-md text-[10px] font-bold text-white shadow-lg whitespace-nowrap"
        style={{ backgroundColor: cursor.color }}
      >
        {cursor.name}
      </motion.div>
    </motion.div>
  );
}

export function MultiplayerCursorEcosystem({ 
  children, 
  className,
  cursors = [] 
}: MultiplayerCursorEcosystemProps) {
  const containerRef = useRef<HTMLDivElement>(null);
  const [ghostCursors, setGhostCursors] = useState<CursorData[]>([]);

  // Simulation logic for Ghost Mode if no real cursors are provided
  useEffect(() => {
    if (cursors.length > 0) return;

    // We are in ghost mode. Spawn 3 fake users.
    const fakeUsers = [
      { id: "ghost-1", color: "#f43f5e", name: "Alice (AI)" },
      { id: "ghost-2", color: "#3b82f6", name: "Bob (AI)" },
      { id: "ghost-3", color: "#10b981", name: "Charlie (AI)" },
    ];

    // Initialize random positions
    let currentGhosts = fakeUsers.map(u => ({
      ...u,
      x: Math.random() * (window.innerWidth - 100),
      y: Math.random() * (window.innerHeight - 100)
    }));

    setGhostCursors(currentGhosts);

    const interval = setInterval(() => {
      if (!containerRef.current) return;
      const rect = containerRef.current.getBoundingClientRect();

      currentGhosts = currentGhosts.map(ghost => {
        // Move towards a random target, simulating reading/inspecting behavior
        const targetX = Math.max(0, Math.min(rect.width - 50, ghost.x + (Math.random() - 0.5) * 300));
        const targetY = Math.max(0, Math.min(rect.height - 50, ghost.y + (Math.random() - 0.5) * 300));

        return {
          ...ghost,
          x: targetX,
          y: targetY
        };
      });

      setGhostCursors(currentGhosts);
    }, 1500); // Move every 1.5 seconds

    return () => clearInterval(interval);
  }, [cursors.length]);

  const activeCursors = cursors.length > 0 ? cursors : ghostCursors;

  return (
    <div ref={containerRef} className={cn("relative w-full h-full overflow-hidden", className)}>
      {/* Cursors Layer */}
      {activeCursors.map((cursor) => (
        <RemoteCursor key={cursor.id} cursor={cursor} />
      ))}

      {/* Content */}
      <div className="w-full h-full">
        {children}
      </div>

      {/* Ghost Mode Indicator */}
      {cursors.length === 0 && (
        <div className="absolute bottom-4 right-4 bg-black/50 backdrop-blur-md px-3 py-1 rounded-full border border-white/10 z-40 pointer-events-none">
          <p className="text-[10px] text-zinc-400 font-mono tracking-widest uppercase">
            Ghost Mode Active
          </p>
        </div>
      )}
    </div>
  );
}

