"use client";

import React, { useRef, useState } from "react";
import { motion, useMotionValue, useSpring, useTransform } from "framer-motion";
import { ArrowUpRight } from "lucide-react";
import { cn } from "@/lib/utils";

export interface ProjectCardProps extends React.AnchorHTMLAttributes<HTMLAnchorElement> {
  title: string;
  description: string;
  image: string;
  tags?: string[];
  href?: string;
}

export function ProjectCard({
  title,
  description,
  image,
  tags = [],
  href = "#",
  className,
  ...props
}: ProjectCardProps) {
  const ref = useRef<HTMLAnchorElement>(null);
  const [isHovered, setIsHovered] = useState(false);

  // Parallax effect for the image
  const mouseX = useMotionValue(0);
  const mouseY = useMotionValue(0);

  const handleMouseMove = (e: React.MouseEvent<HTMLAnchorElement>) => {
    if (!ref.current) return;
    const { left, top, width, height } = ref.current.getBoundingClientRect();
    const x = (e.clientX - left - width / 2) / 25;
    const y = (e.clientY - top - height / 2) / 25;
    mouseX.set(x);
    mouseY.set(y);
  };

  const handleMouseLeave = () => {
    setIsHovered(false);
    mouseX.set(0);
    mouseY.set(0);
  };

  const springConfig = { stiffness: 150, damping: 20 };
  const x = useSpring(mouseX, springConfig);
  const y = useSpring(mouseY, springConfig);

  return (
    <a
      ref={ref}
      href={href}
      className={cn(
        "group relative block w-full overflow-hidden rounded-2xl bg-zinc-900 border border-white/10 aspect-[4/5] md:aspect-[3/4]",
        className
      )}
      onMouseEnter={() => setIsHovered(true)}
      onMouseMove={handleMouseMove}
      onMouseLeave={handleMouseLeave}
      {...props}
    >
      {/* Background Image with Parallax */}
      <motion.div
        className="absolute inset-0 z-0 origin-center"
        style={{ x, y }}
        animate={{ scale: isHovered ? 1.05 : 1.1 }}
        transition={{ duration: 0.8, ease: [0.16, 1, 0.3, 1] }}
      >
        <img
          src={image}
          alt={title}
          className="w-full h-full object-cover block"
        />
        <div 
          className={cn(
            "absolute inset-0 bg-black/40 transition-opacity duration-500",
            isHovered ? "opacity-60" : "opacity-0"
          )}
        />
      </motion.div>

      {/* Content Overlay */}
      <div className="absolute inset-0 z-10 flex flex-col justify-between p-6 md:p-8">

        {/* Top: Tags */}
        <div className="flex flex-wrap gap-2 overflow-hidden">
          {tags.map((tag, i) => (
            <motion.span
              key={i}
              initial={{ opacity: 0, y: -20 }}
              animate={{ opacity: isHovered ? 1 : 0, y: isHovered ? 0 : -20 }}
              transition={{ duration: 0.4, delay: i * 0.05, ease: "easeOut" }}
              className="px-3 py-1 text-xs font-medium bg-black/50 backdrop-blur-md text-white rounded-full border border-white/10"
            >
              {tag}
            </motion.span>
          ))}
        </div>

        {/* Bottom: Title & Description */}
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: isHovered ? 1 : 0, y: isHovered ? 0 : 20 }}
          transition={{ duration: 0.5, ease: "easeOut" }}
          className="flex justify-between items-end gap-4"
        >
          <div>
            <h3 className="text-2xl md:text-3xl font-bold text-white mb-2">{title}</h3>
            <p className="text-sm md:text-base text-zinc-300 font-medium line-clamp-2 max-w-sm">
              {description}
            </p>
          </div>
          <div className="shrink-0 w-12 h-12 rounded-full bg-white text-black flex items-center justify-center">
            <ArrowUpRight className="w-5 h-5" />
          </div>
        </motion.div>
      </div>
    </a>
  );
}

"use client";

import React, { useState, useEffect } from "react";
import { motion, AnimatePresence, HTMLMotionProps } from "framer-motion";
import { cn } from "@/lib/utils";

export interface RadialMenuItem {
  id: string;
  label: string;
  icon?: React.ReactNode;
  href?: string;
  onClick?: () => void;
}

export interface RadialMenuProps extends HTMLMotionProps<"div"> {
  items: RadialMenuItem[];
  centerIcon?: React.ReactNode;
  activeIcon?: React.ReactNode;
  radius?: number;
  startAngle?: number;
  endAngle?: number;
  staggerDelay?: number;
  itemSize?: number;
  buttonSize?: number;
  activeColor?: string;
}

export function RadialMenu({
  items,
  centerIcon,
  activeIcon,
  radius = 100,
  startAngle = -90, // Top
  endAngle = 90,    // Bottom (creates a 180 degree semi-circle on the right)
  staggerDelay = 0.05,
  itemSize = 48,
  buttonSize = 64,
  activeColor = "bg-white text-black",
  className,
  ...props
}: RadialMenuProps) {
  const [isOpen, setIsOpen] = useState(false);

  // Calculate position for an item based on its index
  const getPosition = (index: number, total: number) => {
    // If there's only 1 item, put it in the middle of the arc
    const angleRange = endAngle - startAngle;
    const angleStep = total > 1 ? angleRange / (total - 1) : 0;
    const currentAngle = startAngle + index * angleStep;

    // Convert angle to radians
    const radians = (currentAngle * Math.PI) / 180;

    const x = Math.cos(radians) * radius;
    const y = Math.sin(radians) * radius;

    return { x, y };
  };

  return (
    <div className={cn("relative flex items-center justify-center", className)} {...props}>
      <AnimatePresence>
        {isOpen && (
          <>
            {items.map((item, index) => {
              const { x, y } = getPosition(index, items.length);

              const itemElement = (
                <motion.div
                  key={item.id}
                  initial={{ opacity: 0, x: 0, y: 0, scale: 0.5 }}
                  animate={{ 
                    opacity: 1, 
                    x, 
                    y, 
                    scale: 1,
                    transition: {
                      type: "spring",
                      stiffness: 260,
                      damping: 20,
                      delay: index * staggerDelay
                    }
                  }}
                  exit={{ 
                    opacity: 0, 
                    x: 0, 
                    y: 0, 
                    scale: 0.5,
                    transition: {
                      type: "spring",
                      stiffness: 260,
                      damping: 20,
                      delay: (items.length - 1 - index) * staggerDelay
                    }
                  }}
                  className="absolute z-0 flex items-center justify-center group cursor-pointer"
                  style={{
                    width: itemSize,
                    height: itemSize,
                  }}
                  onClick={() => {
                    item.onClick?.();
                    // Optional: Close menu on click
                    // setIsOpen(false);
                  }}
                >
                  <div className="relative w-full h-full rounded-full bg-zinc-900 border border-white/10 flex items-center justify-center text-white hover:bg-white/10 transition-colors shadow-xl">
                    {item.icon}
                  </div>
                  {/* Tooltip */}
                  <div className="absolute opacity-0 group-hover:opacity-100 transition-opacity -top-10 px-3 py-1.5 rounded bg-zinc-800 text-xs text-white whitespace-nowrap border border-white/10 pointer-events-none">
                    {item.label}
                  </div>
                </motion.div>
              );

              if (item.href) {
                return (
                  <a href={item.href} key={item.id} className="absolute inset-0 flex items-center justify-center">
                    {itemElement}
                  </a>
                );
              }

              return (
                <div key={item.id} className="absolute inset-0 flex items-center justify-center pointer-events-none [&>*]:pointer-events-auto">
                  {itemElement}
                </div>
              );
            })}
          </>
        )}
      </AnimatePresence>

      <motion.button
        className={cn(
          "relative z-10 rounded-full flex items-center justify-center shadow-2xl border transition-colors duration-300",
          isOpen ? activeColor : "bg-zinc-900 text-white border-white/10 hover:bg-zinc-800"
        )}
        style={{
          width: buttonSize,
          height: buttonSize,
        }}
        onClick={() => setIsOpen(!isOpen)}
        whileHover={{ scale: 1.05 }}
        whileTap={{ scale: 0.95 }}
      >
        <motion.div
          initial={false}
          animate={{ rotate: isOpen ? 135 : 0 }}
          transition={{ type: "spring", stiffness: 300, damping: 20 }}
          className="flex items-center justify-center w-full h-full"
        >
          {isOpen && activeIcon ? activeIcon : centerIcon || (
            <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
              <line x1="12" y1="5" x2="12" y2="19"></line>
              <line x1="5" y1="12" x2="19" y2="12"></line>
            </svg>
          )}
        </motion.div>
      </motion.button>
    </div>
  );
}

"use client";

import React, { useRef, useMemo } from "react";
import { Canvas, useFrame, extend } from "@react-three/fiber";
import * as THREE from "three";
import { cn } from "@/lib/utils";

// A simple Raymarching Shader for volumetric-like glowing nebulas/clouds
const vertexShader = `
varying vec2 vUv;
void main() {
  vUv = uv;
  gl_Position = vec4(position, 1.0);
}
`;

const fragmentShader = `
uniform float uTime;
uniform vec2 uResolution;
uniform vec3 uColor1;
uniform vec3 uColor2;

varying vec2 vUv;

// Classic 3D noise (Simplex/Perlin approximation)
mat2 rot(float a) {
  float c = cos(a), s = sin(a);
  return mat2(c, -s, s, c);
}

// Simple fractal noise
float fbm(vec3 p) {
  float f = 0.0;
  float amp = 0.5;
  float freq = 1.0;
  for(int i = 0; i < 4; i++) {
    // A cheap fake noise by combining sines
    float n = sin(p.x*freq) * cos(p.y*freq) * sin(p.z*freq);
    f += n * amp;
    p.xy *= rot(1.2);
    p.yz *= rot(0.9);
    amp *= 0.5;
    freq *= 2.0;
  }
  return f;
}

void main() {
  // Normalize pixel coordinates (from -1 to 1)
  vec2 uv = (vUv - 0.5) * 2.0;
  uv.x *= uResolution.x / uResolution.y;

  // Ray setup
  vec3 ro = vec3(0.0, 0.0, -3.0); // Ray origin (camera)
  vec3 rd = normalize(vec3(uv, 1.0)); // Ray direction

  // Slowly move the camera forward
  ro.z += uTime * 0.5;

  // Raymarching loop
  float t = 0.0;
  float density = 0.0;

  // We do a fixed number of steps for performance
  for(int i = 0; i < 30; i++) {
    vec3 p = ro + rd * t;

    // Evaluate density function (noise) at current point
    float d = fbm(p * 0.8 + vec3(0.0, uTime * 0.2, 0.0));

    // Accumulate density if it's "thick" enough
    if(d > 0.1) {
      density += (d - 0.1) * 0.1;
    }

    // Step forward
    t += max(0.1, d * 0.5); // Variable step size based on distance field

    if(t > 10.0 || density > 1.0) break;
  }

  // Color mapping based on density
  vec3 col = mix(vec3(0.0), mix(uColor1, uColor2, density), density * 2.0);

  // Add some ambient glowing fog
  col += vec3(0.05, 0.02, 0.1) * t * 0.1;

  gl_FragColor = vec4(col, 1.0);
}
`;

function RaymarchingScene({ color1 = "#4f46e5", color2 = "#db2777" }) {
  const materialRef = useRef<THREE.ShaderMaterial>(null);

  const uniforms = useMemo(() => ({
    uTime: { value: 0 },
    uResolution: { value: new THREE.Vector2(window.innerWidth, window.innerHeight) },
    uColor1: { value: new THREE.Color(color1) },
    uColor2: { value: new THREE.Color(color2) },
  }), [color1, color2]);

  useFrame((state) => {
    if (materialRef.current) {
      materialRef.current.uniforms.uTime.value = state.clock.elapsedTime;
      // Update resolution on resize (simplified: assuming fullscreen or resizing correctly via viewport)
      materialRef.current.uniforms.uResolution.value.set(
        state.size.width * state.viewport.dpr,
        state.size.height * state.viewport.dpr
      );
    }
  });

  return (
    <mesh>
      {/* Fullscreen quad */}
      <planeGeometry args={[2, 2]} />
      <shaderMaterial
        ref={materialRef}
        vertexShader={vertexShader}
        fragmentShader={fragmentShader}
        uniforms={uniforms}
        depthWrite={false}
        depthTest={false}
      />
    </mesh>
  );
}

export interface RaymarchingCloudsProps {
  className?: string;
  color1?: string;
  color2?: string;
}

export function RaymarchingClouds({ className, color1, color2 }: RaymarchingCloudsProps) {
  return (
    <div className={cn("relative w-full h-screen bg-black overflow-hidden", className)}>
      <Canvas camera={{ position: [0, 0, 1] }} className="absolute inset-0 pointer-events-none">
        <RaymarchingScene color1={color1} color2={color2} />
      </Canvas>
    </div>
  );
}

"use client";

import React, { useRef, useState, useEffect } from "react";
import { motion, useSpring, useMotionValue, useTransform } from "framer-motion";
import { cn } from "@/lib/utils";

export interface RefractionCursorProps {
  imageUrl: string;
  children: React.ReactNode;
  lensSize?: number;
  magnification?: number;
  className?: string;
}

export function RefractionCursor({
  imageUrl,
  children,
  lensSize = 250,
  magnification = 1.5,
  className
}: RefractionCursorProps) {
  const containerRef = useRef<HTMLDivElement>(null);
  const [isHovered, setIsHovered] = useState(false);
  const [dimensions, setDimensions] = useState({ width: 1000, height: 1000 });

  useEffect(() => {
    if (containerRef.current) {
      setDimensions({
        width: containerRef.current.offsetWidth,
        height: containerRef.current.offsetHeight
      });
    }
  }, []);

  const mouseX = useMotionValue(0);
  const mouseY = useMotionValue(0);

  const springConfig = { damping: 25, stiffness: 200, mass: 0.5 };
  const smoothX = useSpring(mouseX, springConfig);
  const smoothY = useSpring(mouseY, springConfig);

  const handleMouseMove = (e: React.MouseEvent) => {
    if (!containerRef.current) return;
    const rect = containerRef.current.getBoundingClientRect();

    // Calculate mouse position relative to the container
    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;

    mouseX.set(x);
    mouseY.set(y);
  };

  return (
    <div 
      ref={containerRef}
      className={cn("relative overflow-hidden cursor-none", className)}
      onMouseMove={handleMouseMove}
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
    >
      {/* Background Image Layer */}
      <div 
        className="absolute inset-0 z-0 bg-cover bg-center pointer-events-none"
        style={{ backgroundImage: `url(${imageUrl})` }}
      />

      {/* Foreground Content */}
      <div className="relative z-10 w-full h-full pointer-events-none">
        {children}
      </div>

      {/* The Lens */}
      <motion.div
        className="absolute top-0 left-0 z-20 rounded-full pointer-events-none overflow-hidden border border-white/20 shadow-[0_0_20px_rgba(0,0,0,0.5),inset_0_0_20px_rgba(255,255,255,0.2)]"
        style={{
          width: lensSize,
          height: lensSize,
          x: smoothX,
          y: smoothY,
          translateX: "-50%",
          translateY: "-50%",
          backdropFilter: "blur(10px)", // Adds the glass effect to anything underneath
          WebkitBackdropFilter: "blur(10px)",
        }}
        animate={{
          scale: isHovered ? 1 : 0,
          opacity: isHovered ? 1 : 0,
        }}
        transition={{ type: "spring", stiffness: 300, damping: 25 }}
      >
        {/* The Magnified Background Image */}
        {/* We map the background position inversely to the mouse position to keep it perfectly aligned, then scale it up */}
        <motion.div
          className="absolute inset-0 bg-cover bg-no-repeat pointer-events-none"
          style={{
            backgroundImage: `url(${imageUrl})`,
            // Formula to keep the image perfectly aligned while scaling inside a moving container
            backgroundPositionX: useMotionValue(0), // We'll compute this inline if needed, but a simpler way is using CSS transform
            backgroundSize: `${containerRef.current?.clientWidth || 1000}px ${containerRef.current?.clientHeight || 1000}px`,
          }}
        />
        {/* Actually, mapping background position dynamically via framer motion inside the lens is tricky because we need the container dimensions.
            A more elegant and CSS-native way to achieve true DOM-agnostic glass refraction without duplicating images is: 
            mix-blend-mode tricks or feDisplacementMap. Since we have the image URL, duplicating it is easiest.
            Let's use a nested motion div to counter-move the image. */}
        <motion.div
          className="absolute top-0 left-0 pointer-events-none origin-center"
          style={{
            width: dimensions.width,
            height: dimensions.height,
            backgroundImage: `url(${imageUrl})`,
            backgroundSize: "cover",
            backgroundPosition: "center",
            // Pin the image exactly to the background by counter-moving the lens position
            x: useTransform(smoothX, (x) => -x + lensSize / 2),
            y: useTransform(smoothY, (y) => -y + lensSize / 2),
            scale: magnification,
          }}
        />

        {/* Lens Glare */}
        <div className="absolute inset-0 rounded-full bg-gradient-to-tr from-transparent via-white/10 to-white/30 z-10 mix-blend-overlay" />
      </motion.div>
    </div>
  );
}

"use client";

import React, { useRef, useEffect, useState } from "react";
import { cn } from "@/lib/utils";
import { motion, useAnimation } from "framer-motion";

export interface ScratchToRevealProps {
  children: React.ReactNode;
  width: number;
  height: number;
  brushSize?: number;
  coverColor?: string;
  coverImage?: string;
  onReveal?: () => void;
  revealThreshold?: number; // 0 to 1, percentage of area scratched to trigger onReveal
  className?: string;
}

export function ScratchToReveal({
  children,
  width,
  height,
  brushSize = 40,
  coverColor = "#18181b", // zinc-900
  coverImage,
  onReveal,
  revealThreshold = 0.5,
  className,
}: ScratchToRevealProps) {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isScratching, setIsScratching] = useState(false);
  const [isRevealed, setIsRevealed] = useState(false);
  const lastPos = useRef<{x: number, y: number} | null>(null);
  const controls = useAnimation();

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext("2d");
    if (!ctx) return;

    // Set real size
    canvas.width = width;
    canvas.height = height;

    // Fill cover
    if (coverImage) {
      const img = new Image();
      img.crossOrigin = "anonymous";
      img.src = coverImage;
      img.onload = () => {
        ctx.drawImage(img, 0, 0, width, height);
      };
    } else {
      ctx.fillStyle = coverColor;
      ctx.fillRect(0, 0, width, height);
    }
  }, [width, height, coverColor, coverImage]);

  const scratch = (x: number, y: number) => {
    const canvas = canvasRef.current;
    if (!canvas || isRevealed) return;

    const ctx = canvas.getContext("2d");
    if (!ctx) return;

    ctx.globalCompositeOperation = "destination-out";
    ctx.lineCap = "round";
    ctx.lineJoin = "round";
    ctx.lineWidth = brushSize;

    if (lastPos.current) {
      ctx.beginPath();
      ctx.moveTo(lastPos.current.x, lastPos.current.y);
      ctx.lineTo(x, y);
      ctx.stroke();
    } else {
      ctx.beginPath();
      ctx.arc(x, y, brushSize / 2, 0, Math.PI * 2);
      ctx.fill();
    }

    lastPos.current = { x, y };

    checkReveal();
  };

  const getCoordinates = (e: React.MouseEvent | React.TouchEvent | MouseEvent | TouchEvent) => {
    const canvas = canvasRef.current;
    if (!canvas) return { x: 0, y: 0 };

    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;

    let clientX, clientY;

    if ("touches" in e) {
      clientX = e.touches[0].clientX;
      clientY = e.touches[0].clientY;
    } else {
      clientX = (e as React.MouseEvent).clientX;
      clientY = (e as React.MouseEvent).clientY;
    }

    return {
      x: (clientX - rect.left) * scaleX,
      y: (clientY - rect.top) * scaleY,
    };
  };

  const handlePointerDown = (e: React.MouseEvent | React.TouchEvent) => {
    if (isRevealed) return;
    setIsScratching(true);
    const { x, y } = getCoordinates(e);
    scratch(x, y);
  };

  const handlePointerMove = (e: React.MouseEvent | React.TouchEvent) => {
    if (!isScratching || isRevealed) return;
    const { x, y } = getCoordinates(e);
    scratch(x, y);
  };

  const handlePointerUp = () => {
    setIsScratching(false);
    lastPos.current = null;
  };

  // Check how much of the canvas is cleared
  const checkReveal = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext("2d");
    if (!ctx) return;

    const imageData = ctx.getImageData(0, 0, width, height);
    const pixels = imageData.data;
    let transparentPixels = 0;

    // Check alpha channel of every 4th pixel (RGBA) to save performance
    // Skip some pixels for speed
    const step = 4 * 10; 
    const totalPixelsToCheck = pixels.length / step;

    for (let i = 3; i < pixels.length; i += step) {
      if (pixels[i] === 0) {
        transparentPixels++;
      }
    }

    const percentage = transparentPixels / totalPixelsToCheck;

    if (percentage > revealThreshold && !isRevealed) {
      setIsRevealed(true);
      onReveal?.();

      // Auto-clear the rest smoothly and trigger child animation
      controls.start({
        scale: 1,
        transition: { type: "spring", stiffness: 300, damping: 15 }
      });

      const canvasElement = canvasRef.current;
      if (canvasElement) {
        canvasElement.style.transition = "all 0.5s ease-out";
        canvasElement.style.opacity = "0";
        canvasElement.style.transform = "scale(1.1)";
      }
    }
  };

  return (
    <div 
      className={cn("relative overflow-hidden cursor-crosshair select-none", className)}
      style={{ width, height }}
      onMouseDown={handlePointerDown}
      onMouseMove={handlePointerMove}
      onMouseUp={handlePointerUp}
      onMouseLeave={handlePointerUp}
      onTouchStart={handlePointerDown}
      onTouchMove={handlePointerMove}
      onTouchEnd={handlePointerUp}
      onTouchCancel={handlePointerUp}
    >
      <motion.div 
        className="absolute inset-0 pointer-events-none"
        animate={controls}
        initial={{ scale: 0.8 }}
      >
        {children}
      </motion.div>
      <canvas
        ref={canvasRef}
        className="absolute inset-0 z-10 touch-none"
      />
    </div>
  );
}

