import React, { useEffect, useState } from "react";
import { cn } from "@/lib/utils";
import { motion } from "framer-motion";

export interface ScrollSpySection {
  id: string;
  label: string;
}

export interface ScrollSpyProps extends React.HTMLAttributes<HTMLDivElement> {
  sections: ScrollSpySection[];
  scrollContainerRef?: React.RefObject<HTMLElement | null>;
  alignment?: "left" | "right";
  showLabels?: boolean;
  offset?: number;
}

export function ScrollSpy({
  sections,
  scrollContainerRef,
  alignment = "right",
  showLabels = true,
  offset = 100, // Trigger offset from top
  className,
  ...props
}: ScrollSpyProps) {
  const [activeId, setActiveId] = useState<string>(sections[0]?.id || "");

  useEffect(() => {
    // If we have a local container, use it; otherwise use window
    const container = scrollContainerRef?.current || window;

    const handleScroll = () => {
      // Find the current section
      let currentActiveId = activeId;

      for (const section of sections) {
        const element = document.getElementById(section.id);
        if (element) {
          const rect = element.getBoundingClientRect();

          // If the container is local, we need to calculate relative to container
          if (scrollContainerRef?.current) {
            const containerRect = scrollContainerRef.current.getBoundingClientRect();
            // If the element's top is within the container's top + offset
            if (rect.top - containerRect.top <= offset) {
              currentActiveId = section.id;
            }
          } else {
            // Global window scroll
            if (rect.top <= offset) {
              currentActiveId = section.id;
            }
          }
        }
      }

      if (currentActiveId !== activeId) {
        setActiveId(currentActiveId);
      }
    };

    container.addEventListener("scroll", handleScroll);
    handleScroll(); // Check on mount

    return () => {
      container.removeEventListener("scroll", handleScroll);
    };
  }, [sections, activeId, scrollContainerRef, offset]);

  const scrollTo = (id: string) => {
    const element = document.getElementById(id);
    if (!element) return;

    if (scrollContainerRef?.current) {
      // Local scroll
      const container = scrollContainerRef.current;
      const elementRect = element.getBoundingClientRect();
      const containerRect = container.getBoundingClientRect();
      const relativeTop = elementRect.top - containerRect.top + container.scrollTop;

      container.scrollTo({
        top: relativeTop - offset + 50, // Slight adjustment for visuals
        behavior: "smooth"
      });
    } else {
      // Global scroll
      const elementPosition = element.getBoundingClientRect().top + window.scrollY;
      window.scrollTo({
        top: elementPosition - offset + 50,
        behavior: "smooth"
      });
    }
  };

  return (
    <div
      className={cn(
        "fixed top-1/2 -translate-y-1/2 z-50 flex flex-col gap-3",
        alignment === "right" ? "right-8 items-end" : "left-8 items-start",
        className
      )}
      {...props}
    >
      {sections.map((section) => {
        const isActive = activeId === section.id;

        return (
          <button
            key={section.id}
            onClick={() => scrollTo(section.id)}
            className="group flex items-center gap-3 relative focus:outline-none"
          >
            {/* Label (Left aligned mode) */}
            {alignment === "left" && showLabels && (
              <span 
                className={cn(
                  "text-xs font-medium transition-all duration-300 pointer-events-none absolute left-8 w-max",
                  isActive 
                    ? "text-white opacity-100 translate-x-0" 
                    : "text-zinc-500 opacity-0 -translate-x-2 group-hover:opacity-100 group-hover:translate-x-0"
                )}
              >
                {section.label}
              </span>
            )}

            {/* Indicator Dot */}
            <div className="relative w-4 h-4 flex items-center justify-center shrink-0">
              {/* Inactive background */}
              <div className="absolute w-2 h-2 rounded-full bg-zinc-700 transition-transform duration-300 group-hover:scale-150" />

              {/* Active animated dot */}
              {isActive && (
                <motion.div
                  layoutId="scroll-spy-active"
                  className="absolute w-3 h-3 rounded-full bg-white shadow-[0_0_10px_rgba(255,255,255,0.5)]"
                  initial={false}
                  transition={{ type: "spring", stiffness: 300, damping: 30 }}
                />
              )}
            </div>

            {/* Label (Right aligned mode) */}
            {alignment === "right" && showLabels && (
              <span 
                className={cn(
                  "text-xs font-medium transition-all duration-300 pointer-events-none absolute right-8 w-max",
                  isActive 
                    ? "text-white opacity-100 translate-x-0" 
                    : "text-zinc-500 opacity-0 translate-x-2 group-hover:opacity-100 group-hover:translate-x-0"
                )}
              >
                {section.label}
              </span>
            )}
          </button>
        );
      })}
    </div>
  );
}

"use client";

import React, { useRef } from "react";
import {
  motion,
  useScroll,
  useSpring,
  useTransform,
  useVelocity,
  useAnimationFrame,
  useMotionValue,
} from "framer-motion";
import { cn } from "@/lib/utils";

const wrap = (min: number, max: number, v: number) => {
  const rangeSize = max - min;
  return ((((v - min) % rangeSize) + rangeSize) % rangeSize) + min;
};

interface VelocityScrollProps {
  text: string;
  defaultVelocity?: number;
  className?: string;
}

export function ScrollVelocityText({ text, defaultVelocity = 5, className }: VelocityScrollProps) {
  const baseX = useMotionValue(0);
  const { scrollY } = useScroll();
  const scrollVelocity = useVelocity(scrollY);
  const smoothVelocity = useSpring(scrollVelocity, {
    damping: 50,
    stiffness: 400
  });

  // Velocity multiplier for speed
  const velocityFactor = useTransform(smoothVelocity, [0, 1000], [0, 5], {
    clamp: false
  });

  // Subtle skew effect for a kinetic typography feel
  const skewX = useTransform(smoothVelocity, [-1000, 1000], [-5, 5]);

  const x = useTransform(baseX, (v) => `${wrap(-20, -45, v)}%`);
  const directionFactor = useRef<number>(1);

  useAnimationFrame((t, delta) => {
    let moveBy = directionFactor.current * defaultVelocity * (delta / 1000);

    // Reverse direction if scrolling up
    if (velocityFactor.get() < 0) {
      directionFactor.current = -1;
    } else if (velocityFactor.get() > 0) {
      directionFactor.current = 1;
    }

    moveBy += directionFactor.current * moveBy * velocityFactor.get();
    baseX.set(baseX.get() + moveBy);
  });

  return (
    <div className={cn("relative w-full overflow-hidden", className)}>
      <motion.div
        className="flex whitespace-nowrap flex-nowrap"
        style={{ x, skewX }}
      >
        {/* We render the text multiple times to ensure seamless looping */}
        {Array.from({ length: 8 }).map((_, i) => (
          <span 
            key={i} 
            className="block mr-12 text-6xl md:text-8xl font-black uppercase tracking-tighter shrink-0"
          >
            {text}
          </span>
        ))}
      </motion.div>
    </div>
  );
}

"use client";

import React, { useRef, useState, useEffect } from "react";
import { motion, useScroll, useMotionValueEvent, useTransform } from "framer-motion";
import { cn } from "@/lib/utils";

export interface TextNode {
  content: React.ReactNode;
  /** Scroll progress value (0 to 1) when the text starts fading in */
  start: number;
  /** Scroll progress value (0 to 1) when the text has fully faded out */
  end: number;
}

export interface ScrollVideoScrubProps {
  videoUrl: string;
  className?: string;
  fallbackImage?: string;
  /** Array of text overlays tied to scroll progress timestamps */
  textNodes?: TextNode[];
}

export function ScrollVideoScrub({ videoUrl, className, fallbackImage, textNodes = [] }: ScrollVideoScrubProps) {
  const containerRef = useRef<HTMLDivElement>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const [isVideoLoaded, setIsVideoLoaded] = useState(false);
  const [duration, setDuration] = useState(0);

  // We track the scroll progress over a massive container (e.g., 300vh)
  const { scrollYProgress } = useScroll({
    target: containerRef,
    offset: ["start start", "end end"]
  });

  // When metadata loads, we know exactly how long the video is
  const handleLoadedMetadata = () => {
    if (videoRef.current) {
      setDuration(videoRef.current.duration);
      setIsVideoLoaded(true);
    }
  };

  // Every time the scroll position changes, we update the video's current time
  // to perfectly match the scroll percentage!
  useMotionValueEvent(scrollYProgress, "change", (latest) => {
    if (videoRef.current && isVideoLoaded) {
      // Small math to ensure we don't try to seek past the very end, which sometimes causes a glitch
      const targetTime = latest * duration;
      // Use requestAnimationFrame for smoother performance when rapidly scrolling
      requestAnimationFrame(() => {
        if (videoRef.current) {
          videoRef.current.currentTime = targetTime;
        }
      });
    }
  });

  // Optional: We can add a fade-in text overlay that triggers at certain scroll points
  const titleOpacity = useTransform(scrollYProgress, [0, 0.2, 0.8, 1], [1, 0, 0, 1]);
  const titleScale = useTransform(scrollYProgress, [0, 0.2, 0.8, 1], [1, 0.9, 0.9, 1]);

  return (
    <div 
      ref={containerRef} 
      className={cn("relative h-[400vh] w-full bg-zinc-950", className)}
    >
      <div className="sticky top-0 w-full h-screen overflow-hidden flex items-center justify-center bg-black">

        {/* The scrubbing video */}
        <video
          ref={videoRef}
          src={videoUrl}
          preload="auto"
          muted
          playsInline
          onLoadedMetadata={handleLoadedMetadata}
          className={cn(
            "w-full h-full object-cover transition-opacity duration-1000",
            isVideoLoaded ? "opacity-100" : "opacity-0"
          )}
        />

        {/* Fallback while loading */}
        {!isVideoLoaded && fallbackImage && (
          <img 
            src={fallbackImage} 
            alt="Loading video" 
            className="absolute inset-0 w-full h-full object-cover opacity-50"
          />
        )}

        {/* Dynamic Text Overlays */}
        {textNodes.map((node, i) => (
          <TextNodeOverlay 
            key={i} 
            node={node} 
            scrollYProgress={scrollYProgress} 
          />
        ))}

        {/* Progress indicator at the bottom */}
        <div className="absolute bottom-10 left-10 right-10 h-1 bg-white/20 rounded-full overflow-hidden">
          <motion.div 
            className="h-full bg-white origin-left"
            style={{ scaleX: scrollYProgress }}
          />
        </div>

      </div>
    </div>
  );
}

// Sub-component to safely call useTransform for each dynamic node
function TextNodeOverlay({ 
  node, 
  scrollYProgress 
}: { 
  node: TextNode; 
  scrollYProgress: any;
}) {
  // We want to fade in from start, stay fully visible for a bit, then fade out by end.
  // We'll calculate a small transition window (e.g., 5% of scroll).
  const transitionWindow = 0.05;
  const fadeInEnd = Math.min(node.start + transitionWindow, node.end);
  const fadeOutStart = Math.max(node.end - transitionWindow, node.start);

  const opacity = useTransform(
    scrollYProgress, 
    [node.start, fadeInEnd, fadeOutStart, node.end], 
    [0, 1, 1, 0]
  );

  const y = useTransform(
    scrollYProgress,
    [node.start, fadeInEnd, fadeOutStart, node.end],
    [30, 0, 0, -30]
  );

  return (
    <motion.div 
      className="absolute inset-0 flex items-center justify-center pointer-events-none"
      style={{ opacity, y }}
    >
      <div className="bg-black/60 p-8 md:p-12 backdrop-blur-md rounded-3xl border border-white/10 text-center max-w-3xl">
        {node.content}
      </div>
    </motion.div>
  );
}

"use client";

import React, { useRef } from "react";
import { motion, useScroll, useTransform, MotionValue } from "framer-motion";
import { cn } from "@/lib/utils";

export interface ScrollytellingTextProps {
  text: string;
  className?: string;
}

export function ScrollytellingText({ text, className }: ScrollytellingTextProps) {
  const containerRef = useRef<HTMLDivElement>(null);

  const { scrollYProgress } = useScroll({
    target: containerRef,
    offset: ["start 0.8", "start 0.25"]
  });

  const words = text.split(" ");

  return (
    <div 
      ref={containerRef} 
      className={cn("flex flex-wrap text-4xl md:text-6xl font-bold leading-tight tracking-tight", className)}
    >
      {words.map((word, i) => {
        const start = i / words.length;
        const end = start + (1 / words.length);

        return (
          <Word key={i} progress={scrollYProgress} range={[start, end]}>
            {word}
          </Word>
        );
      })}
    </div>
  );
}

interface WordProps {
  children: string;
  progress: MotionValue<number>;
  range: [number, number];
}

function Word({ children, progress, range }: WordProps) {
  const opacity = useTransform(progress, range, [0.1, 1]);
  return (
    <span className="mr-[0.25em] mt-[0.1em] relative">
      <span className="absolute opacity-10">{children}</span>
      <motion.span style={{ opacity }}>{children}</motion.span>
    </span>
  );
}

"use client";

import React, { useRef, useState, useMemo, Suspense } from "react";
import { Canvas, useFrame } from "@react-three/fiber";
import { useTexture, shaderMaterial } from "@react-three/drei";
import * as THREE from "three";
import { cn } from "@/lib/utils";

// --- Liquid Ripple Shader ---
const LiquidRippleMaterial = shaderMaterial(
  {
    uTex1: new THREE.Texture(),
    uTex2: new THREE.Texture(),
    uProgress: 0,
    uIntensity: 0.5,
  },
  // Vertex Shader
  `
  varying vec2 vUv;
  void main() {
    vUv = uv;
    gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
  }
  `,
  // Fragment Shader
  `
  varying vec2 vUv;
  uniform sampler2D uTex1;
  uniform sampler2D uTex2;
  uniform float uProgress;
  uniform float uIntensity;

  void main() {
    vec2 uv = vUv;

    // Ripple calculation
    vec2 center = vec2(0.5, 0.5);
    float dist = distance(uv, center);

    // Distort UVs based on distance and progress
    vec2 distortedUv1 = uv + (uv - center) * sin(dist * 20.0 - uProgress * 10.0) * uProgress * uIntensity;
    vec2 distortedUv2 = uv + (uv - center) * sin(dist * 20.0 - uProgress * 10.0) * (1.0 - uProgress) * uIntensity;

    // Sample both textures
    vec4 tex1 = texture2D(uTex1, distortedUv1);
    vec4 tex2 = texture2D(uTex2, distortedUv2);

    // Mix based on progress
    gl_FragColor = mix(tex1, tex2, uProgress);
  }
  `
);

// --- Noise Dissolve Shader ---
const NoiseDissolveMaterial = shaderMaterial(
  {
    uTex1: new THREE.Texture(),
    uTex2: new THREE.Texture(),
    uProgress: 0,
    uIntensity: 1.0,
  },
  // Vertex Shader
  `
  varying vec2 vUv;
  void main() {
    vUv = uv;
    gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
  }
  `,
  // Fragment Shader
  `
  varying vec2 vUv;
  uniform sampler2D uTex1;
  uniform sampler2D uTex2;
  uniform float uProgress;
  uniform float uIntensity;

  // Simple pseudo-random 2D noise function
  float rand(vec2 n) { 
    return fract(sin(dot(n, vec2(12.9898, 4.1414))) * 43758.5453);
  }

  float noise(vec2 p){
    vec2 ip = floor(p);
    vec2 u = fract(p);
    u = u*u*(3.0-2.0*u);

    float res = mix(
      mix(rand(ip), rand(ip+vec2(1.0,0.0)), u.x),
      mix(rand(ip+vec2(0.0,1.0)), rand(ip+vec2(1.0,1.0)), u.x), u.y);
    return res*res;
  }

  void main() {
    vec2 uv = vUv;

    // Generate noise value
    float n = noise(uv * 20.0 * uIntensity);

    // Smoothstep threshold based on progress
    float threshold = smoothstep(uProgress - 0.2, uProgress + 0.2, n);

    // Reverse logic: at progress 0, we want tex1. So when progress is low, threshold is high.
    // Actually, simple step:
    float mixFactor = smoothstep(1.0 - uProgress, 1.0 - uProgress + 0.1, n);

    vec4 tex1 = texture2D(uTex1, uv);
    vec4 tex2 = texture2D(uTex2, uv);

    gl_FragColor = mix(tex1, tex2, uProgress);

    // Apply dissolve organically
    // If progress is higher than noise, show tex2, else tex1
    float stepMask = step(n, uProgress * 1.2); 
    gl_FragColor = mix(tex1, tex2, stepMask);
  }
  `
);

// Register materials with R3F
import { extend } from '@react-three/fiber';
extend({ LiquidRippleMaterial, NoiseDissolveMaterial });

// Add types for JSX
declare global {
  namespace JSX {
    interface IntrinsicElements {
      liquidRippleMaterial: any;
      noiseDissolveMaterial: any;
    }
  }
}

interface ShaderPlaneProps {
  image1: string;
  image2: string;
  effect: "liquid" | "noise";
  isHovered: boolean;
  intensity?: number;
}

function ShaderPlane({ image1, image2, effect, isHovered, intensity = 0.5 }: ShaderPlaneProps) {
  const meshRef = useRef<THREE.Mesh>(null);
  const materialRef = useRef<any>(null);

  // Load textures
  const [tex1, tex2] = useTexture([image1, image2]);

  useFrame((state, delta) => {
    if (materialRef.current) {
      // Lerp progress to target (1 if hovered, 0 if not)
      const target = isHovered ? 1 : 0;
      // Damped lerp for smooth animation
      materialRef.current.uProgress = THREE.MathUtils.lerp(
        materialRef.current.uProgress,
        target,
        delta * 6.0
      );
    }
  });

  return (
    <mesh ref={meshRef}>
      <planeGeometry args={[2, 2]} />
      {effect === "liquid" ? (
        <liquidRippleMaterial 
          ref={materialRef} 
          uTex1={tex1} 
          uTex2={tex2} 
          uIntensity={intensity}
          transparent={true}
        />
      ) : (
        <noiseDissolveMaterial 
          ref={materialRef} 
          uTex1={tex1} 
          uTex2={tex2} 
          uIntensity={intensity}
          transparent={true}
        />
      )}
    </mesh>
  );
}

export interface ShaderImageProps {
  /** The default image URL */
  image1: string;
  /** The image URL to transition to on hover */
  image2: string;
  /** The shader effect to use */
  effect?: "liquid" | "noise";
  /** The intensity of the shader distortion */
  intensity?: number;
  /** Optional class name for the wrapper div */
  className?: string;
}

export function ShaderImage({
  image1,
  image2,
  effect = "liquid",
  intensity = 0.5,
  className,
}: ShaderImageProps) {
  const [isHovered, setIsHovered] = useState(false);

  return (
    <div 
      className={cn("relative overflow-hidden", className)}
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
    >
      <Canvas
        camera={{ position: [0, 0, 1], fov: 90 }} // Orthographic-like setup to fill plane
        dpr={[1, 2]}
        className="absolute inset-0 w-full h-full"
      >
        <Suspense fallback={null}>
          <ShaderPlane 
            image1={image1} 
            image2={image2} 
            effect={effect} 
            isHovered={isHovered} 
            intensity={intensity}
          />
        </Suspense>
      </Canvas>
    </div>
  );
}

