import React from "react";
import { cn } from "@/lib/utils";

export interface SplitScreenLayoutProps extends React.HTMLAttributes<HTMLDivElement> {
  leftContent: React.ReactNode;
  rightContent: React.ReactNode;
  stickySide?: "left" | "right" | "none";
  splitRatio?: "50/50" | "40/60" | "60/40" | "30/70" | "70/30";
  stackOnMobile?: boolean;
  stickyHeight?: string;
}

const ratioClasses = {
  "50/50": "md:grid-cols-2",
  "40/60": "md:grid-cols-[4fr_6fr]",
  "60/40": "md:grid-cols-[6fr_4fr]",
  "30/70": "md:grid-cols-[3fr_7fr]",
  "70/30": "md:grid-cols-[7fr_3fr]",
};

export function SplitScreenLayout({
  leftContent,
  rightContent,
  stickySide = "left",
  splitRatio = "50/50",
  stackOnMobile = true,
  stickyHeight = "100vh",
  className,
  ...props
}: SplitScreenLayoutProps) {
  return (
    <div
      className={cn(
        "w-full",
        stackOnMobile ? "grid grid-cols-1" : "grid",
        ratioClasses[splitRatio],
        className
      )}
      {...props}
    >
      <div
        className={cn(
          "w-full",
          stickySide === "left" ? "md:sticky md:top-0 md:h-[var(--sticky-height)] md:overflow-y-auto hidden-scrollbar" : "h-full"
        )}
        style={{ "--sticky-height": stickyHeight } as React.CSSProperties}
      >
        {leftContent}
      </div>
      <div
        className={cn(
          "w-full",
          stickySide === "right" ? "md:sticky md:top-0 md:h-[var(--sticky-height)] md:overflow-y-auto hidden-scrollbar" : "h-full"
        )}
        style={{ "--sticky-height": stickyHeight } as React.CSSProperties}
      >
        {rightContent}
      </div>
    </div>
  );
}

"use client";

import React, { useRef } from "react";
import { motion, useScroll, useTransform } from "framer-motion";
import { cn } from "@/lib/utils";

interface SplitTextScrollytellingProps {
  text: string;
  className?: string;
  wordClassName?: string;
}

export function SplitTextScrollytelling({
  text,
  className,
  wordClassName,
}: SplitTextScrollytellingProps) {
  const container = useRef<HTMLDivElement>(null);
  const { scrollYProgress } = useScroll({
    target: container,
    offset: ["start 0.8", "start 0.2"],
  });

  const words = text.split(" ");

  return (
    <p
      ref={container}
      className={cn(
        "flex flex-wrap gap-[0.2em] text-4xl md:text-6xl font-bold leading-tight",
        className
      )}
    >
      {words.map((word, i) => {
        const start = i / words.length;
        const end = start + 1 / words.length;

        return (
          <Word
            key={i}
            progress={scrollYProgress}
            range={[start, end]}
            className={wordClassName}
          >
            {word}
          </Word>
        );
      })}
    </p>
  );
}

interface WordProps {
  children: string;
  progress: any;
  range: [number, number];
  className?: string;
}

function Word({ children, progress, range, className }: WordProps) {
  const opacity = useTransform(progress, range, [0.1, 1]);
  return (
    <span className="relative">
      <span className="absolute opacity-10">{children}</span>
      <motion.span style={{ opacity: opacity }} className={className}>
        {children}
      </motion.span>
    </span>
  );
}

"use client";

import React, { useRef, useState } from "react";
import { cn } from "@/lib/utils";
import { motion, useAnimationFrame } from "framer-motion";

export type SpotlightVariant = "soft" | "strong" | "ring" | "pulse";

interface SpotlightCardProps extends React.HTMLAttributes<HTMLDivElement> {
  children: React.ReactNode;
  /** The color of the spotlight. Default: "rgba(99, 102, 241, 0.15)" */
  spotlightColor?: string;
  /** An alias for spotlightColor */
  color?: string;
  /** Size multiplier for the spotlight. Default: 1 */
  scale?: number;
  /** Visual variant of the spotlight. Default: "soft" */
  variant?: SpotlightVariant;
}

export function SpotlightCard({
  children,
  className,
  spotlightColor = "rgba(99, 102, 241, 0.15)",
  color,
  scale = 1,
  variant = "soft",
  ...props
}: SpotlightCardProps) {
  const divRef = useRef<HTMLDivElement>(null);
  const [isFocused, setIsFocused] = useState(false);
  const [position, setPosition] = useState({ x: 0, y: 0 });
  const [opacity, setOpacity] = useState(0);

  // For the pulse variant
  const timeRef = useRef(0);
  const [pulseRadius, setPulseRadius] = useState(0);

  useAnimationFrame((t, delta) => {
    if (variant === "pulse" && opacity > 0) {
      timeRef.current += delta;
      // Oscillate between 0.8 and 1.2
      const sine = Math.sin(timeRef.current / 400);
      setPulseRadius(sine * 0.2 + 1);
    }
  });

  const handleMouseMove = (e: React.MouseEvent<HTMLDivElement>) => {
    if (!divRef.current || isFocused) return;
    const rect = divRef.current.getBoundingClientRect();
    setPosition({ x: e.clientX - rect.left, y: e.clientY - rect.top });
  };

  const handleFocus = () => {
    setIsFocused(true);
    setOpacity(1);
  };

  const handleBlur = () => {
    setIsFocused(false);
    setOpacity(0);
  };

  const handleMouseEnter = () => setOpacity(1);
  const handleMouseLeave = () => setOpacity(0);

  const activeColor = color
    ? color.startsWith("#")
      ? `${color}25`
      : color
    : spotlightColor;

  const baseRadius = scale * 600;
  const currentRadius = variant === "pulse" ? baseRadius * pulseRadius : baseRadius;

  let gradientString = "";
  switch (variant) {
    case "strong":
      gradientString = `radial-gradient(${currentRadius * 0.7}px circle at ${position.x}px ${position.y}px, ${activeColor}, transparent 70%)`;
      break;
    case "ring":
      gradientString = `radial-gradient(${currentRadius}px circle at ${position.x}px ${position.y}px, transparent 20%, ${activeColor} 40%, transparent 60%)`;
      break;
    case "soft":
    case "pulse":
    default:
      gradientString = `radial-gradient(${currentRadius}px circle at ${position.x}px ${position.y}px, ${activeColor}, transparent 40%)`;
      break;
  }

  return (
    <div
      ref={divRef}
      onMouseMove={handleMouseMove}
      onFocus={handleFocus}
      onBlur={handleBlur}
      onMouseEnter={handleMouseEnter}
      onMouseLeave={handleMouseLeave}
      className={cn(
        "relative overflow-hidden rounded-2xl border border-border/50 bg-background/50 shadow-sm transition-colors hover:border-border",
        className
      )}
      {...props}
    >
      <div
        className="pointer-events-none absolute -inset-px opacity-0 transition-opacity duration-300"
        style={{
          opacity,
          background: gradientString,
        }}
      />
      {children}
    </div>
  );
}

"use client";

import React, { useRef, useState, useCallback } from "react";
import { motion } from "framer-motion";
import { cn } from "@/lib/utils";

export type SpotlightEffect = "glow" | "reveal" | "border" | "gradient" | "halo";

interface SpotlightCursorProps extends React.HTMLAttributes<HTMLDivElement> {
  children: React.ReactNode;
  className?: string;
  /** Spotlight diameter in px. Default: 400 */
  spotlightSize?: number;
  /** Spotlight color as rgba or hex. Default: "rgba(255,255,255,0.15)" */
  spotlightColor?: string;
  /** Visual effect style. Default: "glow" */
  effect?: SpotlightEffect;
  /** Accent color used by some effects (hex). Default: "#818cf8" */
  color?: string;
}

export function SpotlightCursor({
  children,
  className,
  spotlightSize = 400,
  spotlightColor = "rgba(255, 255, 255, 0.15)",
  effect = "glow",
  color = "#818cf8",
  ...props
}: SpotlightCursorProps) {
  const containerRef = useRef<HTMLDivElement>(null);
  const [position, setPosition] = useState({ x: -1000, y: -1000 });
  const [isHovered, setIsHovered] = useState(false);

  const handleMouseMove = useCallback((e: React.MouseEvent<HTMLDivElement>) => {
    if (!containerRef.current) return;
    const rect = containerRef.current.getBoundingClientRect();
    setPosition({ x: e.clientX - rect.left, y: e.clientY - rect.top });
  }, []);

  const handleMouseEnter = useCallback(() => setIsHovered(true), []);
  const handleMouseLeave = useCallback(() => setIsHovered(false), []);

  // ── Build the spotlight background per effect ──────────────────────────────
  const getSpotlightStyle = (): React.CSSProperties => {
    const { x, y } = position;
    const size = spotlightSize;

    switch (effect) {
      case "glow":
        return {
          background: `radial-gradient(${size}px circle at ${x}px ${y}px, ${spotlightColor}, transparent 40%)`,
        };

      case "reveal":
        return {
          background: `radial-gradient(${size}px circle at ${x}px ${y}px, transparent 20%, rgba(0,0,0,0.85) 60%)`,
          mixBlendMode: "darken" as const,
        };

      case "border":
        return {
          background: `radial-gradient(${size * 0.6}px circle at ${x}px ${y}px, ${color}30, transparent 50%)`,
          WebkitMaskImage: `radial-gradient(${size}px circle at ${x}px ${y}px, black 30%, transparent 60%)`,
          maskImage: `radial-gradient(${size}px circle at ${x}px ${y}px, black 30%, transparent 60%)`,
        };

      case "gradient":
        return {
          background: `
            radial-gradient(${size * 0.8}px circle at ${x}px ${y}px, ${color}25 0%, transparent 50%),
            radial-gradient(${size * 1.2}px circle at ${x}px ${y}px, ${color}10 0%, transparent 60%)
          `,
        };

      case "halo":
        return {
          background: `
            radial-gradient(${size * 0.3}px circle at ${x}px ${y}px, transparent 50%, ${color}15 60%, transparent 70%),
            radial-gradient(${size * 0.6}px circle at ${x}px ${y}px, transparent 50%, ${color}08 60%, transparent 70%)
          `,
        };

      default:
        return {
          background: `radial-gradient(${size}px circle at ${x}px ${y}px, ${spotlightColor}, transparent 40%)`,
        };
    }
  };

  return (
    <div
      ref={containerRef}
      onMouseMove={handleMouseMove}
      onMouseEnter={handleMouseEnter}
      onMouseLeave={handleMouseLeave}
      className={cn("relative overflow-hidden group", className)}
      {...props}
    >
      {/* Spotlight layer */}
      <motion.div
        className="pointer-events-none absolute inset-0 z-10"
        initial={{ opacity: 0 }}
        animate={{ opacity: isHovered ? 1 : 0 }}
        transition={{ duration: 0.3, ease: "easeOut" }}
        style={getSpotlightStyle()}
      />
      {/* Content layer */}
      <div className="relative z-0">{children}</div>
    </div>
  );
}

"use client";

import React, { useRef } from "react";
import { motion, useInView, Variants } from "framer-motion";
import { cn } from "@/lib/utils";

export interface StaggeredTextProps extends React.HTMLAttributes<HTMLDivElement> {
  text: string;
  type?: "word" | "char";
  staggerDelay?: number;
  animation?: "fade" | "slide-up" | "blur-in";
  once?: boolean;
  wrapperClassName?: string;
}

export function StaggeredText({
  text,
  type = "word",
  staggerDelay = 0.05,
  animation = "slide-up",
  once = true,
  wrapperClassName,
  className,
  ...props
}: StaggeredTextProps) {
  const ref = useRef<HTMLDivElement>(null);
  const isInView = useInView(ref, { once, amount: 0.5 });

  const getVariants = (): Variants => {
    switch (animation) {
      case "fade":
        return {
          hidden: { opacity: 0 },
          visible: { opacity: 1, transition: { duration: 0.5, ease: "easeOut" } },
        };
      case "blur-in":
        return {
          hidden: { opacity: 0, filter: "blur(10px)" },
          visible: { opacity: 1, filter: "blur(0px)", transition: { duration: 0.6, ease: "easeOut" } },
        };
      case "slide-up":
      default:
        return {
          hidden: { opacity: 0, y: 20 },
          visible: { opacity: 1, y: 0, transition: { duration: 0.5, ease: [0.2, 0.65, 0.3, 0.9] } },
        };
    }
  };

  const itemVariants = getVariants();

  const renderWords = () => {
    const words = text.split(" ");
    return words.map((word, index) => (
      <span key={index} className="inline-block whitespace-nowrap overflow-hidden">
        <motion.span
          variants={itemVariants}
          className="inline-block"
        >
          {word}
        </motion.span>
        {/* Add space back */}
        <span className="inline-block">&nbsp;</span>
      </span>
    ));
  };

  const renderChars = () => {
    const words = text.split(" ");
    return words.map((word, wordIndex) => (
      <span key={wordIndex} className="inline-block whitespace-nowrap overflow-hidden">
        {word.split("").map((char, charIndex) => (
          <motion.span
            key={`${wordIndex}-${charIndex}`}
            variants={itemVariants}
            className="inline-block"
          >
            {char}
          </motion.span>
        ))}
        {/* Add space back */}
        <span className="inline-block">&nbsp;</span>
      </span>
    ));
  };

  return (
    <div ref={ref} className={cn("inline-block", wrapperClassName)} {...props}>
      <motion.div
        initial="hidden"
        animate={isInView ? "visible" : "hidden"}
        variants={{
          visible: {
            transition: {
              staggerChildren: staggerDelay,
            },
          },
        }}
        className={cn("flex flex-wrap", className)}
      >
        {type === "word" ? renderWords() : renderChars()}
      </motion.div>
    </div>
  );
}

