"use client";

import React from "react";
import { motion } from "framer-motion";
import { Check } from "lucide-react";
import { cn } from "@/lib/utils";

export interface Step {
  id: string | number;
  label: string;
  description?: string;
}

export interface StepperProps extends React.HTMLAttributes<HTMLDivElement> {
  steps: Step[];
  currentStep: number; // 0-indexed
  direction?: "horizontal" | "vertical";
}

export function Stepper({
  steps,
  currentStep,
  direction = "horizontal",
  className,
  ...props
}: StepperProps) {
  return (
    <div
      className={cn(
        "flex w-full",
        direction === "horizontal" ? "flex-row items-start justify-between" : "flex-col gap-8",
        className
      )}
      role="list"
      aria-label="Progress"
      {...props}
    >
      {steps.map((step, index) => {
        const isCompleted = currentStep > index;
        const isActive = currentStep === index;
        const isUpcoming = currentStep < index;

        return (
          <div
            key={step.id}
            className={cn(
              "relative flex",
              direction === "horizontal" 
                ? "flex-col items-center flex-1 text-center" 
                : "flex-row items-start gap-4"
            )}
            role="listitem"
            aria-current={isActive ? "step" : undefined}
          >
            {/* Connecting Line (except for last item) */}
            {index < steps.length - 1 && (
              <div
                className={cn(
                  "absolute bg-white/10 transition-colors duration-500",
                  direction === "horizontal"
                    ? "top-5 left-1/2 w-full h-[2px] -translate-y-1/2 ml-4"
                    : "top-10 left-5 w-[2px] h-full -ml-[1px]"
                )}
              >
                {/* Active portion of the line */}
                <motion.div
                  className="bg-indigo-500 w-full h-full origin-left top-0 left-0"
                  initial={{ scaleX: 0, scaleY: 0 }}
                  animate={{
                    scaleX: direction === "horizontal" ? (isCompleted ? 1 : 0) : 1,
                    scaleY: direction === "vertical" ? (isCompleted ? 1 : 0) : 1,
                  }}
                  transition={{ duration: 0.5, ease: "easeInOut" }}
                />
              </div>
            )}

            {/* Step Indicator */}
            <div className="relative z-10 flex shrink-0 items-center justify-center w-10 h-10 rounded-full border-2 bg-zinc-950 transition-colors duration-300"
              style={{
                borderColor: isActive ? "#6366f1" : isCompleted ? "#10b981" : "rgba(255,255,255,0.1)"
              }}
            >
              {isCompleted ? (
                <Check className="w-5 h-5 text-emerald-500" />
              ) : (
                <span className={cn("text-sm font-semibold", isActive ? "text-indigo-400" : "text-zinc-500")}>
                  {index + 1}
                </span>
              )}

              {/* Active Pulse Effect */}
              {isActive && (
                <motion.div
                  className="absolute inset-0 rounded-full border-2 border-indigo-500"
                  animate={{ scale: [1, 1.3, 1], opacity: [0.5, 0, 0.5] }}
                  transition={{ duration: 2, repeat: Infinity, ease: "easeInOut" }}
                />
              )}
            </div>

            {/* Step Content */}
            <div className={cn(
              "flex flex-col",
              direction === "horizontal" ? "mt-4 items-center" : "mt-1"
            )}>
              <h4 className={cn(
                "text-sm font-bold transition-colors duration-300",
                isActive ? "text-white" : isCompleted ? "text-zinc-300" : "text-zinc-600"
              )}>
                {step.label}
              </h4>
              {step.description && (
                <p className={cn(
                  "text-xs mt-1 transition-colors duration-300",
                  isActive ? "text-zinc-400" : "text-zinc-600"
                )}>
                  {step.description}
                </p>
              )}
            </div>
          </div>
        );
      })}
    </div>
  );
}

"use client";

import React, { useRef } from "react";
import { motion, useScroll, useTransform, useSpring } from "framer-motion";
import { cn } from "@/lib/utils";

interface StickyImageMaskProps {
  text: string;
  imageUrl?: string;
  videoUrl?: string;
  className?: string;
}

export function StickyImageMask({ text, imageUrl, videoUrl, className }: StickyImageMaskProps) {
  const containerRef = useRef<HTMLDivElement>(null);

  // Track scroll progress over the container's height (e.g., 300vh)
  const { scrollYProgress } = useScroll({
    target: containerRef,
    offset: ["start start", "end end"]
  });

  // Smooth out the scroll for a buttery cinematic feel
  const smoothProgress = useSpring(scrollYProgress, { damping: 20, stiffness: 100 });

  // 1. Scale the text aggressively as we scroll down.
  // It stays at scale 1 for the first 20%, then rapidly explodes to scale 100
  const scale = useTransform(smoothProgress, [0, 0.2, 0.8, 1], [1, 1, 50, 150]);

  // 2. Fade out the black overlay at the very end so the video is fully visible without the text edges
  const opacity = useTransform(smoothProgress, [0.8, 1], [1, 0]);

  return (
    <div 
      ref={containerRef} 
      className={cn("relative h-[300vh] w-full bg-zinc-950", className)}
    >
      <div className="sticky top-0 h-screen w-full overflow-hidden flex items-center justify-center">

        {/* Background Media (Video or Image) */}
        <div className="absolute inset-0 w-full h-full z-0">
          {videoUrl ? (
            <video 
              src={videoUrl} 
              autoPlay 
              loop 
              muted 
              playsInline 
              className="w-full h-full object-cover"
            />
          ) : imageUrl ? (
            <img 
              src={imageUrl} 
              alt="Background reveal" 
              className="w-full h-full object-cover"
            />
          ) : (
            <div className="w-full h-full bg-gradient-to-br from-indigo-500 via-purple-500 to-pink-500" />
          )}
        </div>

        {/* The Mask Layer using Mix-Blend-Mode: Multiply */}
        {/* Black background stays black, White text becomes perfectly transparent to reveal the media behind it */}
        <motion.div 
          className="absolute inset-0 w-full h-full bg-black z-10 flex items-center justify-center"
          style={{ 
            mixBlendMode: "multiply",
            opacity // Fade out entirely at the end of the scroll
          }}
        >
          <motion.div
            style={{ scale }}
            className="flex items-center justify-center origin-center"
          >
            <h1 className="text-[20vw] font-black uppercase text-white tracking-tighter leading-none whitespace-nowrap">
              {text}
            </h1>
          </motion.div>
        </motion.div>

        {/* Optional: Add a subtle overlay to the media so it's not too bright when fully revealed */}
        <div className="absolute inset-0 bg-black/20 z-0 pointer-events-none" />

      </div>
    </div>
  );
}

"use client";

import React, { useEffect, useRef, useState } from "react";
import { useScroll, useTransform, motion } from "framer-motion";
import { cn } from "@/lib/utils";

export interface StickySequenceProps {
  frameUrls: string[];
  scrollDistance?: string;
  stickyHeight?: string;
  className?: string;
  children?: React.ReactNode;
  scrollContainerRef?: React.RefObject<HTMLElement | null>;
}

export function StickySequenceContainer({
  frameUrls,
  scrollDistance = "300vh",
  stickyHeight = "100vh",
  className,
  children,
  scrollContainerRef,
}: StickySequenceProps) {
  const containerRef = useRef<HTMLDivElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [images, setImages] = useState<HTMLImageElement[]>([]);
  const [loaded, setLoaded] = useState(0);

  // Load all images for perfect scrubbing without network flashing
  useEffect(() => {
    let loadedCount = 0;
    const imgArray: HTMLImageElement[] = [];

    frameUrls.forEach((url, index) => {
      const img = new Image();
      img.src = url;
      img.onload = () => {
        loadedCount++;
        setLoaded(loadedCount);
        if (index === 0) {
          // Draw the first frame immediately once loaded
          drawFrame(0, img);
        }
      };
      imgArray.push(img);
    });
    setImages(imgArray);
  }, [frameUrls]);

  // We map the scroll progress of the entire container (scrollDistance)
  const { scrollYProgress } = useScroll({
    target: containerRef,
    container: scrollContainerRef,
    offset: ["start start", "end end"],
  });

  const smoothProgress = useTransform(scrollYProgress, [0, 1], [0, 1], { clamp: true });

  const drawFrame = (frameIndex: number, specificImg?: HTMLImageElement) => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d");
    if (!ctx) return;

    const img = specificImg || images[frameIndex];
    if (!img) return;

    // Handle high-DPI scaling
    const dpr = window.devicePixelRatio || 1;
    const rect = canvas.getBoundingClientRect();

    // Only resize canvas buffer if the display size changed
    if (canvas.width !== rect.width * dpr || canvas.height !== rect.height * dpr) {
      canvas.width = rect.width * dpr;
      canvas.height = rect.height * dpr;
      ctx.scale(dpr, dpr);
    }

    // Draw image covering the canvas (object-fit: cover equivalent)
    const imgRatio = img.width / img.height;
    const canvasRatio = rect.width / rect.height;
    let drawWidth = rect.width;
    let drawHeight = rect.height;
    let offsetX = 0;
    let offsetY = 0;

    if (imgRatio > canvasRatio) {
      drawWidth = rect.height * imgRatio;
      offsetX = (rect.width - drawWidth) / 2;
    } else {
      drawHeight = rect.width / imgRatio;
      offsetY = (rect.height - drawHeight) / 2;
    }

    ctx.clearRect(0, 0, rect.width, rect.height);
    ctx.drawImage(img, offsetX, offsetY, drawWidth, drawHeight);
  };

  useEffect(() => {
    if (images.length === 0) return;

    const unsubscribe = smoothProgress.on("change", (latest) => {
      const targetFrameIndex = Math.min(
        Math.floor(latest * frameUrls.length),
        frameUrls.length - 1
      );

      requestAnimationFrame(() => {
        drawFrame(targetFrameIndex);
      });
    });

    return () => unsubscribe();
  }, [smoothProgress, images, frameUrls.length]);

  return (
    <div 
      ref={containerRef} 
      className={cn("relative w-full", className)}
      style={{ height: scrollDistance }}
    >
      <div 
        className="sticky top-0 w-full overflow-hidden flex items-center justify-center bg-zinc-900"
        style={{ height: stickyHeight }}
      >
        <canvas
          ref={canvasRef}
          className="w-full h-full object-cover opacity-80"
          style={{ touchAction: "none" }}
        />
        {/* Loading Indicator */}
        {loaded < frameUrls.length && (
          <div className="absolute top-4 right-4 text-xs font-mono text-zinc-500 bg-black/50 px-2 py-1 rounded">
            Buffer: {Math.round((loaded / frameUrls.length) * 100)}%
          </div>
        )}
        {/* Overlay Content */}
        <div className="absolute inset-0 z-10 flex flex-col items-center justify-center pointer-events-none">
          {children}
        </div>
      </div>
    </div>
  );
}

"use client";

import React, { useRef } from "react";
import { motion, useScroll, useTransform } from "framer-motion";
import { cn } from "@/lib/utils";

interface StickyStackingCardProps {
  children: React.ReactNode;
  index: number;
  totalCards: number;
  className?: string;
}

export function StickyStackingCard({ children, index, totalCards, className }: StickyStackingCardProps) {
  const containerRef = useRef<HTMLDivElement>(null);

  const { scrollYProgress } = useScroll({
    target: containerRef,
    // Track from when the top of this card hits the top of the viewport,
    // to when the top of the next card hits the top of the viewport.
    // By default, offset: ['start start', 'end start'] works well if the container height is 100vh.
    // To allow the next card to overlap, we set height to 100vh and position to sticky.
    offset: ["start start", "end start"]
  });

  // Calculate top margin based on index to create a stacked look
  const topOffset = `calc(${index * 2}vh + 20px)`;

  // The card scales down and dims as you scroll past it, creating depth
  const scale = useTransform(scrollYProgress, [0, 1], [1, 0.9]);
  const opacity = useTransform(scrollYProgress, [0, 1], [1, 0.4]);
  const y = useTransform(scrollYProgress, [0, 1], [0, -50]); // slight push up

  return (
    <div 
      ref={containerRef} 
      className={cn("sticky h-screen flex items-center justify-center overflow-hidden", className)}
      style={{ top: topOffset }}
    >
      <motion.div 
        style={{ scale, opacity, y }} 
        className="w-full h-[80vh] flex flex-col justify-center origin-top relative"
      >
        {children}
      </motion.div>
    </div>
  );
}

"use client";

import React, { useState, useEffect } from "react";
import { motion } from "framer-motion";
import { cn } from "@/lib/utils";

export interface StreamingMarkdownRendererProps {
  content: string;
  isStreaming?: boolean;
  className?: string;
  speed?: number; // ms per chunk
}

export function StreamingMarkdownRenderer({
  content,
  isStreaming = false,
  speed = 10,
  className,
}: StreamingMarkdownRendererProps) {
  const [displayedContent, setDisplayedContent] = useState("");

  // This simulates streaming if the content is provided all at once.
  // In a real app with true streaming, the `content` prop updates continuously,
  // and we just render it. We'll handle both by syncing displayedContent.
  useEffect(() => {
    if (!isStreaming) {
      setDisplayedContent(content);
      return;
    }

    if (content.length > displayedContent.length) {
      const timeout = setTimeout(() => {
        setDisplayedContent(content.slice(0, displayedContent.length + 1));
      }, speed);
      return () => clearTimeout(timeout);
    }
  }, [content, displayedContent, isStreaming, speed]);

  // For this component, since it's a "markdown renderer", we would ideally use a markdown parser.
  // To keep it simple and dependency-light, we'll split by newlines for paragraphs.
  const paragraphs = displayedContent.split('\n\n');

  return (
    <div className={cn("text-zinc-200 leading-relaxed font-sans", className)}>
      {paragraphs.map((p, pIdx) => {
        // Split paragraph into words for staggered animation
        const words = p.split(' ');
        return (
          <p key={pIdx} className="mb-4 last:mb-0">
            {words.map((word, wIdx) => {
              // Only animate words if we are actively streaming. Otherwise just render them.
              if (isStreaming && pIdx === paragraphs.length - 1 && wIdx >= words.length - 3) {
                // Animate the very last few words being added
                return (
                  <motion.span
                    key={`${pIdx}-${wIdx}`}
                    initial={{ opacity: 0, filter: "blur(4px)", y: 2 }}
                    animate={{ opacity: 1, filter: "blur(0px)", y: 0 }}
                    transition={{ duration: 0.2 }}
                    className="inline-block mr-1"
                  >
                    {word}
                  </motion.span>
                );
              }

              // Standard rendering for already streamed words
              return (
                <span key={`${pIdx}-${wIdx}`} className="mr-[0.25em]">
                  {word}
                </span>
              );
            })}
          </p>
        );
      })}

      {/* Blinking Cursor at the end if streaming */}
      {isStreaming && (
        <motion.span
          animate={{ opacity: [1, 0, 1] }}
          transition={{ repeat: Infinity, duration: 0.8 }}
          className="inline-block w-2 h-4 bg-indigo-500 ml-1 translate-y-0.5"
        />
      )}
    </div>
  );
}

"use client";

import React, { useId, useState, useRef, useEffect } from "react";
import { animate } from "framer-motion";
import { cn } from "@/lib/utils";

export interface SVGLiquidDistortionProps extends React.HTMLAttributes<HTMLDivElement> {
  children: React.ReactNode;
  /** How much the pixels are displaced. Higher = more warped. */
  intensity?: number;
  /** Base frequency of the noise. Lower = larger waves, Higher = tight ripples. */
  frequency?: number;
  /** Speed of the ripple animation on hover. */
  speed?: number;
  className?: string;
}

export function SVGLiquidDistortion({
  children,
  intensity = 20,
  frequency = 0.02,
  speed = 2,
  className,
  ...props
}: SVGLiquidDistortionProps) {
  const filterId = useId();
  const [isHovered, setIsHovered] = useState(false);

  const turbulenceRef = useRef<SVGFETurbulenceElement>(null);
  const displacementRef = useRef<SVGFEDisplacementMapElement>(null);

  // Keep track of active animations so we can cancel them
  const animRefs = useRef<any[]>([]);

  const handleMouseEnter = () => {
    setIsHovered(true);

    // Clear existing animations
    animRefs.current.forEach(anim => anim.stop());
    animRefs.current = [];

    // Animate scale (displacement intensity)
    const scaleAnim = animate(0, intensity, {
      type: "spring",
      stiffness: 100,
      damping: 10,
      onUpdate: (latest) => {
        if (displacementRef.current) {
          displacementRef.current.setAttribute("scale", latest.toString());
        }
      }
    });

    // Animate baseFrequency (liquid flow)
    const freqAnim = animate(frequency, frequency * 1.5, {
      repeat: Infinity,
      repeatType: "mirror",
      duration: speed,
      ease: "linear",
      onUpdate: (latest) => {
        if (turbulenceRef.current) {
          turbulenceRef.current.setAttribute("baseFrequency", latest.toString());
        }
      }
    });

    animRefs.current.push(scaleAnim, freqAnim);
  };

  const handleMouseLeave = () => {
    setIsHovered(false);

    // Clear existing animations
    animRefs.current.forEach(anim => anim.stop());
    animRefs.current = [];

    // Animate scale back to 0
    const scaleAnim = animate(intensity, 0, {
      type: "spring",
      stiffness: 100,
      damping: 15,
      onUpdate: (latest) => {
        if (displacementRef.current) {
          displacementRef.current.setAttribute("scale", latest.toString());
        }
      }
    });

    // Smoothly return frequency to base
    const freqAnim = animate(frequency * 1.5, frequency, {
      duration: 0.5,
      ease: "easeOut",
      onUpdate: (latest) => {
        if (turbulenceRef.current) {
          turbulenceRef.current.setAttribute("baseFrequency", latest.toString());
        }
      }
    });

    animRefs.current.push(scaleAnim, freqAnim);
  };

  // Cleanup animations on unmount
  useEffect(() => {
    return () => {
      animRefs.current.forEach(anim => anim.stop());
    };
  }, []);

  return (
    <div
      className={cn("relative inline-block", className)}
      onMouseEnter={handleMouseEnter}
      onMouseLeave={handleMouseLeave}
      // Note: filter URL must be applied exactly like this for cross-browser support
      style={{ filter: `url(#${filterId.replace(/:/g, '')})` }}
      {...props}
    >
      <svg className="absolute w-0 h-0 pointer-events-none">
        {/* We strip colons from useId because some browsers dislike colons in SVG IDs */}
        <filter id={filterId.replace(/:/g, '')} x="-20%" y="-20%" width="140%" height="140%">
          <feTurbulence
            ref={turbulenceRef}
            type="fractalNoise"
            baseFrequency={frequency}
            numOctaves={3}
            result="noise"
          />
          <feDisplacementMap
            ref={displacementRef}
            in="SourceGraphic"
            in2="noise"
            scale={0}
            xChannelSelector="R"
            yChannelSelector="G"
          />
        </filter>
      </svg>

      {/* 
        Slight padding prevents the SVG displacement from clipping at the absolute edges 
        of the bounding box when warped aggressively.
      */}
      <span className="inline-block p-2">
        {children}
      </span>
    </div>
  );
}

"use client";

import React, { useState } from "react";
import { motion, useMotionValue, useTransform, AnimatePresence } from "framer-motion";
import { cn } from "@/lib/utils";

export interface StackCard {
  id: string;
  imageUrl: string;
  title: string;
  subtitle?: string;
}

export interface SwipeableStackProps {
  cards: StackCard[];
  className?: string;
  onSwipeRight?: (card: StackCard) => void;
  onSwipeLeft?: (card: StackCard) => void;
}

export function SwipeableStack({ cards: initialCards, className, onSwipeLeft, onSwipeRight }: SwipeableStackProps) {
  const [cards, setCards] = useState<StackCard[]>(initialCards);

  // When a card is thrown off screen, remove it from the array
  const handleRemove = (id: string, direction: "left" | "right") => {
    const card = cards.find((c) => c.id === id);
    if (!card) return;

    if (direction === "right" && onSwipeRight) onSwipeRight(card);
    if (direction === "left" && onSwipeLeft) onSwipeLeft(card);

    setCards((prev) => prev.filter((c) => c.id !== id));
  };

  return (
    <div className={cn("relative w-full h-[600px] flex items-center justify-center bg-zinc-950", className)}>
      <AnimatePresence>
        {cards.map((card, index) => {
          // The last item in the array is rendered on top.
          // So if index === cards.length - 1, it's the top card.
          const isTop = index === cards.length - 1;

          // How far from the top of the stack is this card visually?
          // (0 is top, 1 is the one right behind it, etc.)
          const stackDepth = cards.length - 1 - index;

          return (
            <Card
              key={card.id}
              card={card}
              isTop={isTop}
              stackDepth={stackDepth}
              onRemove={handleRemove}
            />
          );
        })}
      </AnimatePresence>

      {cards.length === 0 && (
        <div className="absolute flex flex-col items-center justify-center text-zinc-600 font-mono text-sm">
          <span>All cards reviewed</span>
          <button 
            onClick={() => setCards(initialCards)}
            className="mt-4 px-4 py-2 border border-zinc-700 rounded-md hover:bg-zinc-800 text-zinc-300"
          >
            Reset Stack
          </button>
        </div>
      )}
    </div>
  );
}

interface CardProps {
  card: StackCard;
  isTop: boolean;
  stackDepth: number;
  onRemove: (id: string, direction: "left" | "right") => void;
}

function Card({ card, isTop, stackDepth, onRemove }: CardProps) {
  const x = useMotionValue(0);

  // Rotate slightly as you drag horizontally
  const rotate = useTransform(x, [-200, 200], [-15, 15]);
  // Opacity fades as it gets dragged far out
  const opacity = useTransform(x, [-200, -100, 0, 100, 200], [0, 1, 1, 1, 0]);

  // Swipe indicator opacities
  const likeOpacity = useTransform(x, [0, 100], [0, 1]);
  const nopeOpacity = useTransform(x, [0, -100], [0, 1]);

  const handleDragEnd = (event: any, info: any) => {
    // If dragged further than 100px, trigger remove
    if (info.offset.x > 100) {
      onRemove(card.id, "right");
    } else if (info.offset.x < -100) {
      onRemove(card.id, "left");
    }
  };

  // Stack styling logic:
  // - Top card (stackDepth=0) is full scale, y=0, highest z-index.
  // - Deeper cards scale down, move up (or down), and get darker.
  return (
    <motion.div
      className="absolute w-[300px] h-[400px] rounded-3xl overflow-hidden shadow-2xl cursor-grab active:cursor-grabbing border border-white/10"
      style={{
        zIndex: 50 - stackDepth,
        x: isTop ? x : 0,
        rotate: isTop ? rotate : 0,
      }}
      initial={{ 
        scale: 1 - stackDepth * 0.05, 
        y: stackDepth * 20, 
        opacity: 0 
      }}
      animate={{ 
        scale: 1 - stackDepth * 0.05, 
        y: stackDepth * 20, 
        opacity: stackDepth > 2 ? 0 : 1 // Only show top 3 cards for performance/visuals
      }}
      exit={{
        // When it gets removed, throw it completely off screen in the direction it was dragged
        x: x.get() > 0 ? 300 : -300,
        opacity: 0,
        transition: { duration: 0.2 }
      }}
      transition={{ type: "spring", stiffness: 300, damping: 20 }}
      drag={isTop ? "x" : false}
      dragConstraints={{ left: 0, right: 0, top: 0, bottom: 0 }}
      onDragEnd={handleDragEnd}
    >
      <img 
        src={card.imageUrl} 
        alt={card.title} 
        className="absolute inset-0 w-full h-full object-cover pointer-events-none"
      />

      {/* Dynamic shadow based on depth */}
      <div 
        className="absolute inset-0 bg-black transition-opacity duration-300 pointer-events-none"
        style={{ opacity: stackDepth * 0.2 }}
      />

      <div className="absolute bottom-0 left-0 w-full p-6 bg-gradient-to-t from-black/80 to-transparent pointer-events-none text-left">
        <h3 className="text-2xl font-black text-white">{card.title}</h3>
        {card.subtitle && (
          <p className="text-white/70 font-mono text-sm mt-1">{card.subtitle}</p>
        )}
      </div>

      {/* Swipe Indicators (LIKE / NOPE) */}
      {isTop && (
        <>
          <motion.div 
            className="absolute top-6 left-6 px-4 py-1 border-2 border-green-500 text-green-500 font-black rounded-lg rotate-[-15deg] pointer-events-none"
            style={{ opacity: likeOpacity }}
          >
            LIKE
          </motion.div>
          <motion.div 
            className="absolute top-6 right-6 px-4 py-1 border-2 border-red-500 text-red-500 font-black rounded-lg rotate-[15deg] pointer-events-none"
            style={{ opacity: nopeOpacity }}
          >
            NOPE
          </motion.div>
        </>
      )}
    </motion.div>
  );
}

