"use client";
import { useEffect } from "react";
import { motion, stagger, useAnimate } from "framer-motion";
import { cn } from "@/lib/utils";

export const TextGenerateEffect = ({
  words,
  className,
  filter = true,
  duration = 0.5,
}: {
  words: string;
  className?: string;
  filter?: boolean;
  duration?: number;
}) => {
  const [scope, animate] = useAnimate();
  let wordsArray = words.split(" ");
  useEffect(() => {
    animate(
      "span",
      {
        opacity: 1,
        filter: filter ? "blur(0px)" : "none",
      },
      {
        duration: duration ? duration : 1,
        delay: stagger(0.2),
      }
    );
  }, [scope.current]);

  const renderWords = () => {
    return (
      <motion.div ref={scope}>
        {wordsArray.map((word, idx) => {
          return (
            <motion.span
              key={word + idx}
              className="dark:text-white text-black opacity-0"
              style={{
                filter: filter ? "blur(10px)" : "none",
              }}
            >
              {word}{" "}
            </motion.span>
          );
        })}
      </motion.div>
    );
  };

  return (
    <div className={cn("font-bold", className)}>
      <div className="mt-4">
        <div className=" dark:text-white text-black leading-snug tracking-wide">
          {renderWords()}
        </div>
      </div>
    </div>
  );
};

"use client";

import React, { useRef } from "react";
import { motion, useScroll, useTransform } from "framer-motion";
import { cn } from "@/lib/utils";

interface TextMaskVideoRevealProps {
  text: string;
  videoSrc: string;
  className?: string;
  maskScaleFactor?: number;
}

export function TextMaskVideoReveal({
  text,
  videoSrc,
  className,
  maskScaleFactor = 60,
}: TextMaskVideoRevealProps) {
  const containerRef = useRef<HTMLDivElement>(null);

  const { scrollYProgress } = useScroll({
    target: containerRef,
    offset: ["start start", "end end"]
  });

  // Scale the mask hole massively so the video fills the screen.
  // We use exponential scaling for a smoother 'fly-through' effect.
  const scale = useTransform(scrollYProgress, [0, 0.4, 0.8, 1], [1, 5, 20, maskScaleFactor]);

  // Fade out the mask completely at the very end to reveal the pure video
  const opacity = useTransform(scrollYProgress, [0.8, 1], [1, 0]);

  return (
    <div ref={containerRef} className={cn("relative h-[300vh]", className)}>
      <div className="sticky top-0 h-screen w-full overflow-hidden flex items-center justify-center bg-black">

        {/* Background Video */}
        <video 
          src={videoSrc}
          autoPlay 
          loop 
          muted 
          playsInline
          className="absolute inset-0 w-full h-full object-cover z-0"
        />

        {/* Text Mask Layer */}
        {/* We use mix-blend-multiply. Black stays black, White becomes transparent (showing the video). */}
        <motion.div 
          className="absolute inset-0 z-10 flex items-center justify-center bg-black mix-blend-multiply origin-center"
          style={{ scale, opacity }}
        >
          <h1 className="text-[20vw] md:text-[25vw] font-black text-white tracking-tighter text-center leading-none">
            {text}
          </h1>
        </motion.div>

      </div>
    </div>
  );
}

"use client";

import React, { useRef } from "react";
import { motion, useInView, Variants } from "framer-motion";
import { cn } from "@/lib/utils";

export type TextRevealVariant = "slide-up" | "slide-down" | "fade" | "scale";

interface TextRevealProps {
  /** The text to reveal */
  text: string;
  className?: string;
  /** Delay before animation starts (seconds). Default: 0 */
  delay?: number;
  /** Speed multiplier. Higher is faster. Default: 1 */
  speed?: number;
  /** Animation preset. Default: "slide-up" */
  variant?: TextRevealVariant;
}

const getVariants = (variant: TextRevealVariant, speed: number): Variants => {
  const duration = 0.8 / speed;

  switch (variant) {
    case "slide-down":
      return {
        hidden: { y: "-100%", opacity: 0, rotateZ: -5 },
        visible: {
          y: "0%",
          opacity: 1,
          rotateZ: 0,
          transition: { duration, ease: [0.16, 1, 0.3, 1] },
        },
      };
    case "fade":
      return {
        hidden: { opacity: 0, y: 10 },
        visible: {
          opacity: 1,
          y: 0,
          transition: { duration, ease: "easeOut" },
        },
      };
    case "scale":
      return {
        hidden: { opacity: 0, scale: 0.8, y: 20 },
        visible: {
          opacity: 1,
          scale: 1,
          y: 0,
          transition: { duration, ease: [0.175, 0.885, 0.32, 1.275] }, // BackOut
        },
      };
    case "slide-up":
    default:
      return {
        hidden: { y: "100%", opacity: 0, rotateZ: 5 },
        visible: {
          y: "0%",
          opacity: 1,
          rotateZ: 0,
          transition: { duration, ease: [0.16, 1, 0.3, 1] }, // Custom snappy ease
        },
      };
  }
};

export function TextReveal({
  text,
  className,
  delay = 0,
  speed = 1,
  variant = "slide-up",
}: TextRevealProps) {
  const ref = useRef(null);
  // Triggers once when the text is 15% visible
  const isInView = useInView(ref, { once: true, margin: "-15% 0px" });

  const words = text.split(" ");
  const childVariants = getVariants(variant, speed);

  return (
    <div
      ref={ref}
      className={cn("flex flex-wrap gap-[0.25em] overflow-hidden", className)}
    >
      {words.map((word, i) => (
        <span key={i} className="relative overflow-hidden inline-block pb-1">
          <motion.span
            variants={childVariants}
            initial="hidden"
            animate={isInView ? "visible" : "hidden"}
            transition={{ delay: delay + i * (0.05 / speed) }}
            className="inline-block transform origin-bottom-left"
          >
            {word}
          </motion.span>
        </span>
      ))}
    </div>
  );
}

"use client";

import React, { useEffect, useState, useRef } from "react";
import { cn } from "@/lib/utils";

export type ScrambleVariant = "cyber" | "matrix" | "blocks" | "minimal";

interface TextScrambleProps extends React.HTMLAttributes<HTMLSpanElement> {
  text: string;
  /** Speed of the scramble interval in ms. Default: 50 */
  speed?: number;
  /** Delay before starting in ms. Default: 0 */
  delay?: number;
  /** Custom character set. If omitted, uses the variant's default. */
  characterSet?: string;
  /** Whether the scramble should run. Useful for triggering on hover. Default: true */
  trigger?: boolean;
  /** Pre-configured style variant. Default: "cyber" */
  variant?: ScrambleVariant;
}

const CHAR_SETS: Record<ScrambleVariant, string> = {
  cyber: "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789!@#$%^&*()_+",
  matrix: "アァカサタナハマヤャラワガザダバパイィキシチニヒミリヰギジヂビピウゥクスツヌフムユュルグズブヅプエェケセテネヘメレゲゼデベペオォコソトノホモヨョロゴゾドボポヴッン",
  blocks: "░▒▓█▄▀■▖▗▘▙▚▛▜▝▞▟",
  minimal: "+-/",
};

export function TextScramble({
  text,
  speed = 50,
  delay = 0,
  characterSet,
  className,
  trigger = true,
  variant = "cyber",
  ...props
}: TextScrambleProps) {
  const [displayText, setDisplayText] = useState("");
  const timeoutRef = useRef<NodeJS.Timeout | null>(null);
  const intervalRef = useRef<NodeJS.Timeout | null>(null);
  const activeCharSet = characterSet || CHAR_SETS[variant];

  useEffect(() => {
    if (!trigger) {
      setDisplayText(text); // Just show text if not triggered
      return;
    }

    const startScramble = () => {
      let iterations = 0;

      intervalRef.current = setInterval(() => {
        setDisplayText((prev) => {
          const newText = text
            .split("")
            .map((char, index) => {
              if (index < iterations) {
                return text[index];
              }
              if (char === " ") return " ";
              return activeCharSet[Math.floor(Math.random() * activeCharSet.length)];
            })
            .join("");

          if (iterations >= text.length) {
            clearInterval(intervalRef.current!);
          }

          // Speed of reveal relative to text length
          iterations += 1 / 3; 
          return newText;
        });
      }, speed);
    };

    // Reset before starting
    setDisplayText("");
    if (timeoutRef.current) clearTimeout(timeoutRef.current);
    if (intervalRef.current) clearInterval(intervalRef.current);

    if (delay > 0) {
      timeoutRef.current = setTimeout(startScramble, delay);
    } else {
      startScramble();
    }

    return () => {
      if (timeoutRef.current) clearTimeout(timeoutRef.current);
      if (intervalRef.current) clearInterval(intervalRef.current);
    };
  }, [text, speed, delay, activeCharSet, trigger]);

  return (
    <span 
      className={cn("inline-block whitespace-pre-wrap", className)} 
      {...props}
    >
      {displayText || text.replace(/./g, " ")}
    </span>
  );
}

