import React, { useState, useRef, useEffect } from "react";
import { motion, useSpring, useMotionValue } from "framer-motion";
import { cn } from "@/lib/utils";

export interface PortalItem {
  id: string;
  title: string;
  videoUrl: string;
  category: string;
}

export interface VideoPortalProps {
  items: PortalItem[];
  className?: string;
  portalSize?: number;
}

export function VideoPortal({ items, className, portalSize = 300 }: VideoPortalProps) {
  const containerRef = useRef<HTMLDivElement>(null);
  const [activeItem, setActiveItem] = useState<PortalItem | null>(null);
  const [isHovering, setIsHovering] = useState(false);

  const mouseX = useMotionValue(0);
  const mouseY = useMotionValue(0);

  const springConfig = { damping: 20, stiffness: 150, mass: 0.8 };
  const smoothX = useSpring(mouseX, springConfig);
  const smoothY = useSpring(mouseY, springConfig);

  const handleMouseMove = (e: React.MouseEvent) => {
    if (!containerRef.current) return;
    const rect = containerRef.current.getBoundingClientRect();
    mouseX.set(e.clientX - rect.left);
    mouseY.set(e.clientY - rect.top);
  };

  return (
    <div 
      ref={containerRef}
      className={cn("relative w-full py-20 px-8 cursor-crosshair", className)}
      onMouseMove={handleMouseMove}
      onMouseLeave={() => setIsHovering(false)}
    >
      <div className="max-w-4xl mx-auto flex flex-col gap-6 relative z-10">
        {items.map((item) => (
          <div
            key={item.id}
            className="group flex items-center justify-between border-b border-white/10 pb-6 cursor-pointer"
            onMouseEnter={() => {
              setActiveItem(item);
              setIsHovering(true);
            }}
            onMouseLeave={() => {
              setActiveItem(null);
              setIsHovering(false);
            }}
          >
            <h3 className={cn(
              "text-4xl md:text-6xl font-black transition-all duration-500 tracking-tighter uppercase",
              isHovering && activeItem?.id !== item.id ? "text-white/20 blur-[2px]" : "text-white/50",
              isHovering && activeItem?.id === item.id ? "text-white drop-shadow-[0_0_20px_rgba(255,255,255,0.6)] scale-105 origin-left" : ""
            )}>
              {item.title}
            </h3>
            <span className={cn(
              "text-sm font-mono transition-colors duration-500",
              isHovering && activeItem?.id !== item.id ? "text-zinc-700" : "text-zinc-500",
              isHovering && activeItem?.id === item.id ? "text-indigo-400 font-bold" : ""
            )}>
              {item.category}
            </span>
          </div>
        ))}
      </div>

      {/* The Video Portal */}
      <motion.div
        className="absolute top-0 left-0 z-0 pointer-events-none overflow-hidden bg-black flex items-center justify-center border border-white/20 shadow-[0_0_30px_rgba(255,255,255,0.2)]"
        style={{
          width: portalSize,
          height: portalSize,
          x: smoothX,
          y: smoothY,
          translateX: "-50%",
          translateY: "-50%",
          // Animate the border radius to look organic and liquid
          borderRadius: "40% 60% 70% 30% / 40% 50% 60% 50%",
        }}
        animate={{
          scale: isHovering ? 1 : 0,
          opacity: isHovering ? 1 : 0,
          borderRadius: [
            "40% 60% 70% 30% / 40% 50% 60% 50%",
            "60% 40% 30% 70% / 60% 30% 70% 40%",
            "50% 50% 50% 50% / 50% 50% 50% 50%",
            "40% 60% 70% 30% / 40% 50% 60% 50%"
          ],
        }}
        transition={{
          scale: { type: "spring", stiffness: 300, damping: 25 },
          opacity: { duration: 0.2 },
          borderRadius: { duration: 4, repeat: Infinity, ease: "linear" }
        }}
      >
        {activeItem && (
          <motion.video
            key={activeItem.id}
            src={activeItem.videoUrl}
            autoPlay
            loop
            muted
            playsInline
            initial={{ opacity: 0, scale: 1.2 }}
            animate={{ opacity: 1, scale: 1 }}
            exit={{ opacity: 0 }}
            transition={{ duration: 0.4 }}
            className="absolute inset-0 w-full h-full object-cover scale-150"
          />
        )}

        {/* Subtle inner shadow for depth */}
        <div className="absolute inset-0 shadow-[inset_0_0_30px_rgba(0,0,0,0.8)] z-10 rounded-full" />
      </motion.div>
    </div>
  );
}

"use client";

import React, { useRef, useState } from "react";
import { motion, useMotionValue, useSpring, useMotionTemplate } from "framer-motion";
import { cn } from "@/lib/utils";

interface VideoRevealProps extends React.HTMLAttributes<HTMLDivElement> {
  videoSrc: string;
  posterSrc?: string;
  text?: string;
  variant?: "hover-zoom" | "cursor-mask" | "split-door";
}

export function VideoReveal({
  className,
  videoSrc,
  posterSrc,
  text = "Hover to Reveal",
  variant = "hover-zoom",
  ...props
}: VideoRevealProps) {
  const [isHovered, setIsHovered] = useState(false);
  const containerRef = useRef<HTMLDivElement>(null);
  const videoRef = useRef<HTMLVideoElement>(null);

  // For cursor-mask variant
  const mouseX = useMotionValue(0);
  const mouseY = useMotionValue(0);

  // Smooth out the mouse movement for the mask
  const smoothX = useSpring(mouseX, { stiffness: 300, damping: 25 });
  const smoothY = useSpring(mouseY, { stiffness: 300, damping: 25 });
  const maskSize = useSpring(0, { stiffness: 300, damping: 25 });

  const clipPath = useMotionTemplate`circle(${maskSize}px at ${smoothX}px ${smoothY}px)`;

  const handleMouseEnter = () => {
    setIsHovered(true);
    if (variant === "cursor-mask") maskSize.set(200);
    if (videoRef.current) {
      videoRef.current.play().catch(() => {});
    }
  };

  const handleMouseLeave = () => {
    setIsHovered(false);
    if (variant === "cursor-mask") maskSize.set(0);
    if (videoRef.current) {
      videoRef.current.pause();
    }
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    if (variant === "cursor-mask" && containerRef.current) {
      const rect = containerRef.current.getBoundingClientRect();
      mouseX.set(e.clientX - rect.left);
      mouseY.set(e.clientY - rect.top);
    }
  };

  return (
    <div
      ref={containerRef}
      className={cn(
        "relative w-full aspect-[16/9] overflow-hidden rounded-2xl bg-zinc-950 group cursor-crosshair border border-white/5",
        className
      )}
      onMouseEnter={handleMouseEnter}
      onMouseLeave={handleMouseLeave}
      onMouseMove={handleMouseMove}
      {...props}
    >
      {/* ─── Static Foreground Text (Visible when video is hidden) ─── */}
      <div className="absolute inset-0 flex items-center justify-center z-10 pointer-events-none mix-blend-difference">
        <h3 className="text-3xl md:text-5xl font-black text-white tracking-tighter uppercase">
          {text}
        </h3>
      </div>

      {/* ─── Variant: Hover Zoom ─── */}
      {variant === "hover-zoom" && (
        <motion.div
          className="absolute inset-0 origin-center"
          initial={{ scale: 0.8, opacity: 0 }}
          animate={{
            scale: isHovered ? 1 : 0.85,
            opacity: isHovered ? 1 : 0,
            filter: isHovered ? "blur(0px)" : "blur(10px)",
          }}
          transition={{ duration: 0.6, ease: [0.16, 1, 0.3, 1] }}
        >
          <video
            ref={videoRef}
            className="w-full h-full object-cover"
            src={videoSrc}
            poster={posterSrc}
            muted
            loop
            playsInline
          />
          <div className="absolute inset-0 bg-black/20" />
        </motion.div>
      )}

      {/* ─── Variant: Cursor Mask ─── */}
      {variant === "cursor-mask" && (
        <motion.div
          className="absolute inset-0 z-0"
          style={{ clipPath }}
        >
          <video
            ref={videoRef}
            className="w-full h-full object-cover"
            src={videoSrc}
            poster={posterSrc}
            muted
            loop
            playsInline
          />
          <div className="absolute inset-0 bg-black/10" />
        </motion.div>
      )}

      {/* ─── Variant: Split Door ─── */}
      {variant === "split-door" && (
        <>
          <div className="absolute inset-0 z-0">
            <video
              ref={videoRef}
              className="w-full h-full object-cover"
              src={videoSrc}
              poster={posterSrc}
              muted
              loop
              playsInline
            />
            <div className="absolute inset-0 bg-black/20" />
          </div>

          {/* Top Door */}
          <motion.div
            className="absolute top-0 left-0 right-0 h-1/2 bg-zinc-900 border-b border-white/5 z-10 pointer-events-none"
            initial={{ y: 0 }}
            animate={{ y: isHovered ? "-100%" : 0 }}
            transition={{ duration: 0.6, ease: [0.22, 1, 0.36, 1] }}
          />
          {/* Bottom Door */}
          <motion.div
            className="absolute bottom-0 left-0 right-0 h-1/2 bg-zinc-900 border-t border-white/5 z-10 pointer-events-none"
            initial={{ y: 0 }}
            animate={{ y: isHovered ? "100%" : 0 }}
            transition={{ duration: 0.6, ease: [0.22, 1, 0.36, 1] }}
          />
        </>
      )}
    </div>
  );
}

"use client";

import React, { useRef, useState, useEffect, useMemo } from "react";
import { Canvas, useFrame } from "@react-three/fiber";
import * as THREE from "three";
import { Camera, CameraOff, RefreshCw } from "lucide-react";
import { cn } from "@/lib/utils";

// --- GLSL SHADERS ---

const vertexShader = `
varying vec2 vUv;
void main() {
  vUv = uv;
  gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
}
`;

const defaultFragmentShader = `
uniform sampler2D uTexture;
varying vec2 vUv;
void main() {
  gl_FragColor = texture2D(uTexture, vUv);
}
`;

const glitchFragmentShader = `
uniform sampler2D uTexture;
uniform float uTime;
varying vec2 vUv;

// Random function
float random(vec2 st) {
    return fract(sin(dot(st.xy, vec2(12.9898,78.233))) * 43758.5453123);
}

void main() {
  vec2 uv = vUv;

  // Glitch effect based on time
  float glitchIntensity = step(0.9, random(vec2(uTime * 0.1, uTime * 0.2))) * 0.1;
  float glitchLine = step(0.8, random(vec2(uv.y * 10.0, uTime)));

  if (glitchLine > 0.5) {
    uv.x += glitchIntensity * (random(vec2(uTime, uv.y)) - 0.5);
  }

  // RGB Split
  float split = glitchIntensity * 0.5;
  float r = texture2D(uTexture, uv + vec2(split, 0.0)).r;
  float g = texture2D(uTexture, uv).g;
  float b = texture2D(uTexture, uv - vec2(split, 0.0)).b;

  gl_FragColor = vec4(r, g, b, 1.0);
}
`;

const asciiFragmentShader = `
uniform sampler2D uTexture;
uniform vec2 uResolution;
varying vec2 vUv;

float character(float n, vec2 p) {
  p = floor(p*vec2(4.0, -4.0) + 2.5);
  if (clamp(p.x, 0.0, 4.0) == p.x && clamp(p.y, 0.0, 4.0) == p.y) {
    if (int(mod(n/exp2(p.x + 5.0*p.y), 2.0)) == 1) return 1.0;
  }
  return 0.0;
}

void main() {
  vec2 pix = gl_FragCoord.xy;
  vec3 col = texture2D(uTexture, floor(pix/8.0)*8.0/uResolution).rgb;

  float gray = dot(col, vec3(0.299, 0.587, 0.114));
  float n = 65536.0; // Space

  if (gray > 0.2) n = 65600.0;    // .
  if (gray > 0.3) n = 332772.0;   // *
  if (gray > 0.4) n = 15255086.0; // o
  if (gray > 0.5) n = 23385164.0; // &
  if (gray > 0.6) n = 15252014.0; // 8
  if (gray > 0.7) n = 13199452.0; // @
  if (gray > 0.8) n = 11512810.0; // #

  vec2 p = mod(pix/4.0, 2.0) - vec2(1.0);
  col = col * character(n, p);

  // Matrix green tint
  gl_FragColor = vec4(0.0, col.g * 1.5, 0.0, 1.0);
}
`;


// --- R3F COMPONENT ---

function ShaderPlane({ videoTexture, variant }: { videoTexture: THREE.VideoTexture | null, variant: string }) {
  const materialRef = useRef<THREE.ShaderMaterial>(null);

  const fragmentShader = useMemo(() => {
    switch(variant) {
      case "glitch": return glitchFragmentShader;
      case "matrix": return asciiFragmentShader;
      default: return defaultFragmentShader;
    }
  }, [variant]);

  const uniforms = useMemo(() => ({
    uTime: { value: 0 },
    uTexture: { value: videoTexture },
    uResolution: { value: new THREE.Vector2(window.innerWidth, window.innerHeight) }
  }), [videoTexture]);

  useFrame((state) => {
    if (materialRef.current) {
      materialRef.current.uniforms.uTime.value = state.clock.elapsedTime;
      // Update texture if it changes
      if (materialRef.current.uniforms.uTexture.value !== videoTexture) {
        materialRef.current.uniforms.uTexture.value = videoTexture;
      }
    }
  });

  if (!videoTexture) return null;

  return (
    <mesh>
      {/* 16:9 Aspect Ratio Plane */}
      <planeGeometry args={[16/3, 9/3]} />
      <shaderMaterial
        ref={materialRef}
        vertexShader={vertexShader}
        fragmentShader={fragmentShader}
        uniforms={uniforms}
        // Fix mirror effect by inverting the UVs (since webcams are usually mirrored)
        side={THREE.DoubleSide}
      />
    </mesh>
  );
}

// --- MAIN WRAPPER COMPONENT ---

export interface WebcamShaderPortalProps {
  className?: string;
  initialVariant?: "default" | "glitch" | "matrix";
}

export function WebcamShaderPortal({ className, initialVariant = "matrix" }: WebcamShaderPortalProps) {
  const [isActive, setIsActive] = useState(false);
  const [videoTexture, setVideoTexture] = useState<THREE.VideoTexture | null>(null);
  const [variant, setVariant] = useState(initialVariant);

  const videoRef = useRef<HTMLVideoElement | null>(null);
  const streamRef = useRef<MediaStream | null>(null);

  const toggleWebcam = async () => {
    if (isActive) {
      // Stop
      if (streamRef.current) {
        streamRef.current.getTracks().forEach(track => track.stop());
      }
      setVideoTexture(null);
      setIsActive(false);
    } else {
      // Start
      try {
        const stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: "user" }, audio: false });
        streamRef.current = stream;

        if (!videoRef.current) {
          const video = document.createElement("video");
          video.autoplay = true;
          video.muted = true;
          video.playsInline = true;
          videoRef.current = video;
        }

        videoRef.current.srcObject = stream;
        videoRef.current.play();

        const texture = new THREE.VideoTexture(videoRef.current);
        texture.minFilter = THREE.LinearFilter;
        texture.magFilter = THREE.LinearFilter;
        // Flip horizontally so it acts like a mirror
        texture.wrapS = THREE.RepeatWrapping;
        texture.repeat.x = -1;

        setVideoTexture(texture);
        setIsActive(true);
      } catch (err) {
        console.error("Webcam access denied.", err);
        alert("Please allow webcam access to use this feature.");
      }
    }
  };

  const cycleVariant = () => {
    const variants = ["default", "glitch", "matrix"];
    const nextIndex = (variants.indexOf(variant) + 1) % variants.length;
    setVariant(variants[nextIndex] as any);
  };

  useEffect(() => {
    return () => {
      if (streamRef.current) {
        streamRef.current.getTracks().forEach(track => track.stop());
      }
    };
  }, []);

  return (
    <div className={cn("relative w-full h-[500px] bg-black rounded-3xl overflow-hidden group", className)}>
      <Canvas camera={{ position: [0, 0, 3] }}>
        <color attach="background" args={["#000"]} />
        <ShaderPlane videoTexture={videoTexture} variant={variant} />
      </Canvas>

      {/* Controls Overlay */}
      <div className="absolute bottom-6 left-1/2 -translate-x-1/2 flex items-center gap-3">
        <button
          onClick={toggleWebcam}
          className={cn(
            "flex items-center gap-2 px-6 py-3 rounded-full font-semibold transition-all duration-300 shadow-xl backdrop-blur-md",
            isActive 
              ? "bg-red-500/20 text-red-500 border border-red-500/50 hover:bg-red-500/30" 
              : "bg-white/10 text-white border border-white/20 hover:bg-white/20"
          )}
        >
          {isActive ? (
            <>
              <CameraOff className="w-5 h-5" />
              Stop Feed
            </>
          ) : (
            <>
              <Camera className="w-5 h-5" />
              Enable Webcam
            </>
          )}
        </button>

        {isActive && (
          <button
            onClick={cycleVariant}
            className="flex items-center gap-2 px-4 py-3 rounded-full font-semibold bg-white/10 text-white border border-white/20 hover:bg-white/20 transition-all shadow-xl backdrop-blur-md"
            title="Cycle Shader"
          >
            <RefreshCw className="w-5 h-5" />
            <span className="uppercase text-xs tracking-widest">{variant}</span>
          </button>
        )}
      </div>

      {!isActive && (
        <div className="absolute inset-0 pointer-events-none flex flex-col items-center justify-center bg-black/40 backdrop-blur-[2px] transition-opacity duration-500 group-hover:opacity-0">
          <p className="text-zinc-400 font-mono text-sm tracking-widest mt-32">AWAITING CAMERA STREAM</p>
        </div>
      )}
    </div>
  );
}

"use client";

import React, { useRef, useState, useCallback, useEffect, useMemo } from "react";
import { Canvas, useFrame, useThree } from "@react-three/fiber";
import * as THREE from "three";
import { cn } from "@/lib/utils";

// ─────────────────────────────────────────────
// GLSL Fragment Shader: Distorted Transition
// ─────────────────────────────────────────────
const vertexShader = /* glsl */ `
  varying vec2 vUv;
  void main() {
    vUv = uv;
    gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
  }
`;

const fragmentShader = /* glsl */ `
  uniform sampler2D uTextureCurrent;
  uniform sampler2D uTextureNext;
  uniform float uProgress;
  uniform float uIntensity;
  uniform vec2 uResolution;

  varying vec2 vUv;

  // Simple 2D noise for distortion
  float random(vec2 st) {
    return fract(sin(dot(st.xy, vec2(12.9898, 78.233))) * 43758.5453123);
  }

  float noise(vec2 st) {
    vec2 i = floor(st);
    vec2 f = fract(st);
    float a = random(i);
    float b = random(i + vec2(1.0, 0.0));
    float c = random(i + vec2(0.0, 1.0));
    float d = random(i + vec2(1.0, 1.0));
    vec2 u = f * f * (3.0 - 2.0 * f);
    return mix(a, b, u.x) + (c - a) * u.y * (1.0 - u.x) + (d - b) * u.x * u.y;
  }

  void main() {
    vec2 uv = vUv;
    float p = uProgress;

    // ─── Chromatic Aberration (RGB Split) ───
    // As progress increases, each color channel samples from a slightly offset UV.
    float aberrationStrength = uIntensity * p * (1.0 - p) * 4.0; // Peaks at p=0.5
    vec2 redOffset   = vec2(aberrationStrength * 0.02, 0.0);
    vec2 greenOffset = vec2(0.0, 0.0);
    vec2 blueOffset  = vec2(-aberrationStrength * 0.02, aberrationStrength * 0.01);

    // ─── Liquid Noise Distortion ───
    float noiseVal = noise(uv * 8.0 + p * 3.0);
    vec2 distortion = vec2(
      noiseVal * aberrationStrength * 0.05,
      noiseVal * aberrationStrength * 0.03
    );

    // ─── Wave Displacement ───
    float wave = sin(uv.y * 20.0 + p * 12.0) * aberrationStrength * 0.01;
    vec2 waveOffset = vec2(wave, 0.0);

    // Final distorted UVs for both textures
    vec2 uvDistorted = uv + distortion + waveOffset;

    // Sample current image (with RGB split)
    float currentR = texture2D(uTextureCurrent, uvDistorted + redOffset).r;
    float currentG = texture2D(uTextureCurrent, uvDistorted + greenOffset).g;
    float currentB = texture2D(uTextureCurrent, uvDistorted + blueOffset).b;
    vec4 colorCurrent = vec4(currentR, currentG, currentB, 1.0);

    // Sample next image (with RGB split)
    float nextR = texture2D(uTextureNext, uvDistorted + redOffset).r;
    float nextG = texture2D(uTextureNext, uvDistorted + greenOffset).g;
    float nextB = texture2D(uTextureNext, uvDistorted + blueOffset).b;
    vec4 colorNext = vec4(nextR, nextG, nextB, 1.0);

    // ─── Dissolve Mask ───
    // Use noise to create a non-linear transition boundary
    float dissolve = noise(uv * 5.0 + vec2(p * 2.0, 0.0));
    float mixFactor = smoothstep(p - 0.3, p + 0.3, dissolve);

    // Final mix: dissolve from current to next
    vec4 finalColor = mix(colorNext, colorCurrent, mixFactor);

    gl_FragColor = finalColor;
  }
`;

// ─────────────────────────────────────────────
// Internal Scene Component
// ─────────────────────────────────────────────
interface TransitionPlaneProps {
  images: string[];
  currentIndex: number;
  nextIndex: number;
  progress: React.MutableRefObject<number>;
  isTransitioning: boolean;
  intensity: number;
}

function TransitionPlane({ images, currentIndex, nextIndex, progress, isTransitioning, intensity }: TransitionPlaneProps) {
  const meshRef = useRef<THREE.Mesh>(null);
  const materialRef = useRef<THREE.ShaderMaterial>(null);
  const { viewport } = useThree();

  // Load all textures
  const textures = useMemo(() => {
    const loader = new THREE.TextureLoader();
    return images.map((src) => {
      const tex = loader.load(src);
      tex.minFilter = THREE.LinearFilter;
      tex.magFilter = THREE.LinearFilter;
      return tex;
    });
  }, [images]);

  // Animate progress
  useFrame((_, delta) => {
    if (!materialRef.current) return;

    if (isTransitioning) {
      progress.current = Math.min(progress.current + delta * 1.2, 1.0);
    }

    materialRef.current.uniforms.uProgress.value = progress.current;
    materialRef.current.uniforms.uTextureCurrent.value = textures[currentIndex] || textures[0];
    materialRef.current.uniforms.uTextureNext.value = textures[nextIndex] || textures[0];
  });

  const uniforms = useMemo(() => ({
    uTextureCurrent: { value: textures[0] },
    uTextureNext: { value: textures[0] },
    uProgress: { value: 0 },
    uIntensity: { value: intensity },
    uResolution: { value: new THREE.Vector2(viewport.width, viewport.height) },
  }), [textures, intensity, viewport.width, viewport.height]);

  return (
    <mesh ref={meshRef} scale={[viewport.width, viewport.height, 1]}>
      <planeGeometry args={[1, 1, 32, 32]} />
      <shaderMaterial
        ref={materialRef}
        vertexShader={vertexShader}
        fragmentShader={fragmentShader}
        uniforms={uniforms}
      />
    </mesh>
  );
}

// ─────────────────────────────────────────────
// Public Component
// ─────────────────────────────────────────────
export interface WebGLGalleryProps extends React.HTMLAttributes<HTMLDivElement> {
  /** Array of image URLs */
  images: string[];
  /** Distortion intensity (default 1.0) */
  intensity?: number;
  /** Show navigation controls */
  showControls?: boolean;
  /** Show image counter */
  showCounter?: boolean;
  /** Aspect ratio (default "16/9") */
  aspectRatio?: string;
}

export function WebGLGallery({
  images,
  intensity = 1.0,
  showControls = true,
  showCounter = true,
  aspectRatio = "16/9",
  className,
  ...props
}: WebGLGalleryProps) {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [nextIndex, setNextIndex] = useState(0);
  const [isTransitioning, setIsTransitioning] = useState(false);
  const progressRef = useRef(0);

  const goTo = useCallback((targetIndex: number) => {
    if (isTransitioning || targetIndex === currentIndex) return;

    setNextIndex(targetIndex);
    setIsTransitioning(true);
    progressRef.current = 0;

    // Wait for the transition to finish
    setTimeout(() => {
      setCurrentIndex(targetIndex);
      setIsTransitioning(false);
      progressRef.current = 0;
    }, 900); // ~1 second transition
  }, [isTransitioning, currentIndex]);

  const goNext = useCallback(() => {
    const next = (currentIndex + 1) % images.length;
    goTo(next);
  }, [currentIndex, images.length, goTo]);

  const goPrev = useCallback(() => {
    const prev = (currentIndex - 1 + images.length) % images.length;
    goTo(prev);
  }, [currentIndex, images.length, goTo]);

  return (
    <div
      className={cn("relative w-full overflow-hidden rounded-2xl bg-black group", className)}
      style={{ aspectRatio }}
      {...props}
    >
      {/* WebGL Canvas */}
      <Canvas
        camera={{ position: [0, 0, 5], fov: 45 }}
        gl={{ antialias: true, alpha: false }}
        style={{ position: "absolute", inset: 0 }}
      >
        <TransitionPlane
          images={images}
          currentIndex={currentIndex}
          nextIndex={nextIndex}
          progress={progressRef}
          isTransitioning={isTransitioning}
          intensity={intensity}
        />
      </Canvas>

      {/* Navigation Controls */}
      {showControls && (
        <>
          <button
            onClick={goPrev}
            disabled={isTransitioning}
            className="absolute left-4 top-1/2 -translate-y-1/2 z-10 w-12 h-12 rounded-full bg-white/10 backdrop-blur-md border border-white/20 flex items-center justify-center text-white opacity-0 group-hover:opacity-100 transition-all duration-300 hover:bg-white/20 hover:scale-110 disabled:opacity-30 disabled:cursor-not-allowed"
            aria-label="Previous"
          >
            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M15 18l-6-6 6-6"/></svg>
          </button>
          <button
            onClick={goNext}
            disabled={isTransitioning}
            className="absolute right-4 top-1/2 -translate-y-1/2 z-10 w-12 h-12 rounded-full bg-white/10 backdrop-blur-md border border-white/20 flex items-center justify-center text-white opacity-0 group-hover:opacity-100 transition-all duration-300 hover:bg-white/20 hover:scale-110 disabled:opacity-30 disabled:cursor-not-allowed"
            aria-label="Next"
          >
            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M9 18l6-6-6-6"/></svg>
          </button>
        </>
      )}

      {/* Image Counter */}
      {showCounter && (
        <div className="absolute bottom-4 left-1/2 -translate-x-1/2 z-10 flex items-center gap-2">
          {images.map((_, i) => (
            <button
              key={i}
              onClick={() => goTo(i)}
              disabled={isTransitioning}
              className={cn(
                "w-2 h-2 rounded-full transition-all duration-300",
                i === currentIndex
                  ? "bg-white w-6"
                  : "bg-white/40 hover:bg-white/70"
              )}
              aria-label={`Go to image ${i + 1}`}
            />
          ))}
        </div>
      )}
    </div>
  );
}
